resource "aws_security_group" "web" {
  name = "web-sg"

  dynamic "ingress" {
    for_each = ["80", "443"]
    content {
      from_port   = ingress.value
      to_port     = ingress.value
      protocol    = "tcp"
      cidr_blocks = ["0.0.0.0/0"]
    }
  }
}

# ── variables.tf ──────────────────────────────────────────
# Variables
variable "region" {
  type        = string
  description = "The region in which to launch the EC2 instance"
  default     = "us-east-1"
}

variable "environment" {
  type        = string
  description = "The environment in which to launch the EC2 instance"
  # default     = "dev"
}

variable "instance_types" {
  type        = map(string)
  description = "The types of instances to launch"
  default = {
    dev     = "t2.micro"
    staging = "t2.medium"
    prod    = "t2.large"
  }
}

locals {
  file_content = file("${path.module}/hello-tf.txt")
}

variable "common_tags" {
  type        = map(string)
  description = "Common tags to apply to all resources"
  default = {
    Owner    = "Valerii Vasianovych"
    Provider = "AWS-Terraform"
  }
}

# variable "1_helloworld" { # incorrect variable name
#   type        = string
#   default     = "Hello World"
# }

# variable "hello_world_2" { # correct variable name
#   type        = string
#   default     = "Hello World"
# }

# ── outputs.tf ──────────────────────────────────────────
# Outputs
# output "created_instance_type" {
#   value = aws_instance.example_ec2.instance_type
# }

# output "created_instance_az" {
#   value = aws_instance.example_ec2.availability_zone
# }

output "file_content" {
  value = local.file_content
}

output "multiply" {
  value = 2 * 7
}

output "greater_than" {
  value = 5 > 4
}

# output "hello_world" {
#   value = "${var.1_hello_world}"
# }

# ── count-for-if.tf ──────────────────────────────────────────
variable "aws_users" {
  description = "This is array with names of new users"
  type        = list(string)
  default     = ["ola", "wika", "nastya", "alisa"]
}

# terraform plan -target=aws_ian_user.users
resource "aws_iam_user" "users" {
  count = length(var.aws_users)               # number of users from list
  name  = element(var.aws_users, count.index) # names of users
  tags = {
    Names : "Name of user: ${element(var.aws_users, count.index)}"
    Number : "Number of user from Terraform array: ${count.index + 1}"
  }
}

# attach addministrator policy to users
data "aws_iam_policy" "admin_policy" {
  arn = "arn:aws:iam::aws:policy/AdministratorAccess"
}

resource "aws_iam_user_policy_attachment" "admin_policy" {
  count      = length(var.aws_users)
  user       = element(aws_iam_user.users[*].name, count.index)
  policy_arn = data.aws_iam_policy.admin_policy.arn
}

output "return_users" {
  value = aws_iam_user.users
}

output "iam_users_list" {
  value = [
    for i in aws_iam_user.users :
    "Username: ${i.name} has ARN: ${i.arn} and number in array ${index(aws_iam_user.users[*].name, i.name) + 1}"
  ]
}

output "iam_users_map" {
  value = {
    for i in aws_iam_user.users :
    i.unique_id => "Name of user: ${i.id}"
  }
}

output "show_specific_users" {
  value = [
    for i in aws_iam_user.users :
    i.name if length(i.name) == 4
  ]
}

##############################################################

variable "numbers" {
  description = "This is array with names of new users"
  type        = list(number)
  default     = [1, 2, 3, 4, 5]
}

output "return_numbers" {
  value = length(var.numbers)
}

# ── local_file.tf ──────────────────────────────────────────
resource "local_file" "foo_file" {
  content  = "The environment of this terraform is: ${var.environment}"
  filename = "${path.module}/local_files/foo_file.txt"
}

variable "files" {
  default = {
    "dev.txt"     = "Development Environment"
    "prod.txt"    = "Production Environment"
    "staging.txt" = "Staging Environment"
  }
}

resource "local_file" "multiple_files" {
  for_each = var.files

  content  = each.value
  filename = "${path.module}/local_files/${each.key}"
}

# ── s3-import.tf ──────────────────────────────────────────
# Import existing S3 bucket from AWS
resource "aws_s3_bucket" "import-example" {
  bucket = "rds-import-s3-bucket" # actual bucket name in AWS
}

# terraform import aws_s3_bucket.import-example minikube-crossplane-bucket-v2

# ── vpc.tf ──────────────────────────────────────────
# module "vpc" {
#   source = "terraform-aws-modules/vpc/aws"

#   name = "test-vpc"
#   cidr = "10.0.0.0/16"

#   azs             = ["${var.region}a", "${var.region}b"]
#   private_subnets = []
#   public_subnets  = ["10.0.10.0/24", "10.0.20.0/24"]

#   enable_nat_gateway = false
#   enable_vpn_gateway = false

#   tags = {
#     Terraform = "true"
#   }
# }

# ── variables.tf ──────────────────────────────────────────
variable "region" {
  default = "us-east-1"
}

variable "env" {
  default = "dev"
}

variable "vpc_cidr" {
  default = "10.0.0.0/16"
}

variable "public_subnet_cidrs" {
  default = [
    "10.0.10.0/24",
    "10.0.11.0/24"
  ]
}

variable "private_subnet_cidrs" {
  default = [
    "10.0.20.0/24",
    "10.0.21.0/24"
  ]
}

variable "common_tags" {
  default = {
    Owner : "Valerii Vasianovych"
    Project : "Terraform AWS VPC"
  }
}

# ── outputs.tf ──────────────────────────────────────────
output "vpc_id" {
  value = aws_vpc.main.id
}

output "public_subnet_cidrs" {
  value = var.public_subnet_cidrs
}

output "private_subnet_cidrs" {
  value = var.private_subnet_cidrs
}

output "account_id" {
  value = data.aws_caller_identity.current.id
}

# ── datasource.tf ──────────────────────────────────────────
data "aws_availability_zones" "available" {}
data "aws_caller_identity" "current" {}

# ── private-subnet.tf ──────────────────────────────────────────
# resource "aws_eip" "nat" {
#   count = length(var.private_subnet_cidrs) # Number of EIPs for NAT gateways based on the number of private subnets
#   tags = merge(var.common_tags, {
#     Name   = "${var.env}-nat-eip-${count.index + 1}"
#     Region = "Region: ${var.region}"
#   })
# }

# resource "aws_nat_gateway" "nat" {
#   count         = length(var.private_subnet_cidrs) # Number of NAT gateways based on the number of private subnets
#   allocation_id = aws_eip.nat[count.index].id # Each NAT gateway is associated with a separate EIP
#   subnet_id     = element(aws_subnet.public_subnets[*].id, count.index) # value of the public subnet ID, used to associate the NAT gateway with each private subnet
#   tags = merge(var.common_tags, {
#     Name   = "${var.env}-nat-gw-${count.index + 1}"
#     Region = "Region: ${var.region}"
#   })
# }

resource "aws_subnet" "private_subnets" {
  count             = length(var.private_subnet_cidrs) # Number of private subnets based on the number of CIDRs provided
  vpc_id            = aws_vpc.main.id
  cidr_block        = element(var.private_subnet_cidrs, count.index) # Number of CIDRs provided for private subnets based on the count.index
  availability_zone = data.aws_availability_zones.available.names[count.index] # Availability zone based on the count.index
  tags = merge(var.common_tags, {
    Name   = "${var.env}-private-subnet-${count.index + 1}"
    Region = "Region: ${var.region}"
  })
}

resource "aws_route_table" "private_subnets" {
  count  = length(var.private_subnet_cidrs) # Number of route tables based on the number of private subnets
  vpc_id = aws_vpc.main.id
  route {
    cidr_block = "0.0.0.0/0"
    # gateway_id = aws_nat_gateway.nat[count.index].id
  }
  tags = merge(var.common_tags, {
    Name   = "${var.env}-route-private-subnets-${count.index + 1}"
    Region = "Region: ${var.region}"
  })
}

resource "aws_route_table_association" "private_routes" {
  count          = length(aws_subnet.private_subnets[*].id) # Number of route table associations based on the number of private subnets
  route_table_id = aws_route_table.private_subnets[count.index].id # Route table ID based on the count.index
  subnet_id      = element(aws_subnet.private_subnets[*].id, count.index) # Subnet ID based on the count.index
}

# ── public-subnet.tf ──────────────────────────────────────────
resource "aws_subnet" "public_subnets" {
  count                   = length(var.public_subnet_cidrs)
  vpc_id                  = aws_vpc.main.id
  cidr_block              = element(var.public_subnet_cidrs, count.index)
  availability_zone       = data.aws_availability_zones.available.names[count.index]
  map_public_ip_on_launch = true
  tags = merge(var.common_tags, {
    Name   = "${var.env}-public-subnet-${count.index + 1}"
    Region = "Region: ${var.region}"
  })
}

resource "aws_route_table" "public_subnets" {
  vpc_id = aws_vpc.main.id
  route {
    cidr_block = "0.0.0.0/0"
    gateway_id = aws_internet_gateway.main.id
  }
  tags = merge(var.common_tags, {
    Name   = "${var.env}-route-public-subnets"
    Region = "Region: ${var.region}"
  })
}

resource "aws_route_table_association" "public_routes" {
  count          = length(aws_subnet.public_subnets[*].id) # Number of route table associations based on the number of public subnets
  route_table_id = aws_route_table.public_subnets.id # Route table ID based on the count.index
  subnet_id      = element(aws_subnet.public_subnets[*].id, count.index) # ID of public subnet based on the count.index
}

# ── vpc.tf ──────────────────────────────────────────
resource "aws_vpc" "main" {
  cidr_block = var.vpc_cidr
  tags = merge(var.common_tags, {
    Name   = "${var.env}-vpc"
    Region = "Region: ${var.region}"
  })
}

resource "aws_internet_gateway" "main" {
  vpc_id = aws_vpc.main.id
  tags = merge(var.common_tags, {
    Name   = "${var.env}-igw"
    Region = "Region: ${var.region}"
  })
}

# ── main.tf ──────────────────────────────────────────
terraform {
    backend "s3" {
    bucket           = "terrafrom-tfstate-file-s3-bucket"
    # dynamodb_table = "terrafrom-tfstate-dynamodb"
    encrypt          = true
    key              = "aws/tfstates/ec2-create/terraform.tfstate"
    region           = "us-east-1"
  }

  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 4.16"
    }
  }

  required_version = ">= 1.2.0"
}

provider "aws" {
  region = "us-east-1"
}

# ── variables.tf ──────────────────────────────────────────
variable "monitoring_value" {
    description = "Enable detailed monitoring"
    type        = bool
    default     = false
}

variable "instance_type" {
    description = "Define instance type"
    type        = string
    default     = "t2.micro"
}

variable "common_tags" {
    description = "Tags to apply to all resources"
    type        = map(string)
    default     = {
        Owner       = "Valerii Vasianovych"
        Project     = "AWS Instance Creation"
        Environment = "Development"
    }
}

variable "allow_security_groups_ports" {
    description = "The ports to open on the security group"
    type        = list(number)
    default     = [22, 80, 443]
}

# ── outputs.tf ──────────────────────────────────────────
output "aws_caller_identity" {
    value = data.aws_caller_identity.current
}

output "aws_region" {
    value = data.aws_region.current.name
}

output "aws_region_description" {
    value = data.aws_region.current.description
}

output "aws_availability_zones" {
    value = data.aws_availability_zones.available
}

# ── datasource.tf ──────────────────────────────────────────
data "aws_region" "current" {}
data "aws_region" "available" {}
data "aws_availability_zones" "available" {}
data "aws_caller_identity" "current" {}
data "aws_ami" "latest_ubuntu" {
  owners      = ["099720109477"]
  most_recent = true
  filter {
    name   = "name"
    values = ["ubuntu/images/hvm-ssd-gp3/ubuntu-noble-24.04-amd64-server-*"]
  }
}

# ── ec2-resource.tf ──────────────────────────────────────────
resource "aws_instance" "ubuntu_instance" {
    ami                    = data.aws_ami.latest_ubuntu.id
    instance_type          = var.instance_type
    key_name               = "ServersKey"
    vpc_security_group_ids = [aws_security_group.instance_security_group.id]
    user_data              = file("install-nginx.sh")
    monitoring             = var.monitoring_value

    tags = merge(var.common_tags, {
      Name = "Latest Ubuntu Instance"
      Year = 2024
    })
}

resource "aws_security_group" "instance_security_group" {
  name        = "Instance Security Group"
  description = "Allow HTTP and HTTPS inbound traffic"

  dynamic "ingress" {
    for_each = var.allow_security_groups_ports
    content {
      from_port   = ingress.value
      to_port     = ingress.value
      protocol    = "tcp"
      cidr_blocks = ["0.0.0.0/0"]
    }
    }

    egress {
        from_port   = 0
        to_port     = 0
        protocol    = "-1"
        cidr_blocks = ["0.0.0.0/0"]

    }
    tags = merge(var.common_tags, {
        Name = "Instance Security Group"
        Year = 2024
    })
}

