output "region" {
  description = "AWS region"
  value       = var.region
}

output "cidr_block" {
  description = "CIDR block for the VPC"
  value       = var.cidr_block
}

output "public_subnet_cidrs" {
  description = "The CIDR blocks for the public subnets"
  value       = var.public_subnet_cidrs
}

output "common_tags" {
  description = "Common tags for all resources"
  value       = var.common_tags
}

output "env" {
  description = "Environment name"
  value       = var.env
}

output "developer" {
    description = "List of developers"
    value       = var.developer
}

output "ingress_ports" {
    description = "Security group ports"
    value       = var.ingress_ports
}

output "instance_type" {
    description = "Instance type"
    value       = var.instance_type
}

# ── main.tf ──────────────────────────────────────────
terraform {
  backend "s3" {
    bucket = "terrafrom-tfstate-file-s3-bucket"
    # dynamodb_table = "terraform-tfstate-dynamodb"
    encrypt = true
    key     = "aws/tfstates/remote-tf-state/dev1/terraform.tfstate"
    region  = "us-east-1"
  }

  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 4.16"
    }
  }
}

module "common_vars" {
  source = "../common"
}

# ── outputs.tf ──────────────────────────────────────────
output "vpc_id" {
   value = aws_vpc.main
}

output "public_subnet_ids" {
    value = aws_subnet.public_subnet[*].id
}

output "owner" {
    value = data.aws_caller_identity.current.account_id
}

# ── datasource.tf ──────────────────────────────────────────
data "aws_region" "current" {}
data "aws_caller_identity" "current" {}
data "aws_availability_zones" "available" {}

# ── vpc.tf ──────────────────────────────────────────
provider "aws" {
  region = module.common_vars.region
}

resource "aws_vpc" "main" {
  cidr_block = module.common_vars.cidr_block
    tags = merge(module.common_vars.common_tags, {
     Name        = "VPC-${module.common_vars.env}"
     Environment = module.common_vars.env
  })
}

resource "aws_internet_gateway" "main" {
  vpc_id = aws_vpc.main.id
  tags = merge(module.common_vars.common_tags, {
     Name        = "IGW-${module.common_vars.env}"
     Environment = module.common_vars.env
  })
}

resource "aws_subnet" "public_subnet" {
  count      = length(module.common_vars.public_subnet_cidrs)
  vpc_id     = aws_vpc.main.id
  cidr_block = element(module.common_vars.public_subnet_cidrs, count.index)
  availability_zone = data.aws_availability_zones.available.names[count.index]
  map_public_ip_on_launch = true
    tags = merge(module.common_vars.common_tags, {
     Name        = "Public-Subnet-${module.common_vars.env}-${data.aws_availability_zones.available.names[count.index]}-${count.index + 1}"
     Environment = module.common_vars.env
  })
}

resource "aws_route_table" "public_subnets" {
    vpc_id = aws_vpc.main.id
    route {
        cidr_block = "0.0.0.0/0"
        gateway_id = aws_internet_gateway.main.id
    }
    tags = merge(module.common_vars.common_tags, {
     Name        = "Route-Table-${module.common_vars.env}"
     Environment = "${module.common_vars.env}"
  })
}

resource "aws_route_table_association" "public_subnets" {
  count = length(aws_subnet.public_subnet[*].id)
  route_table_id = aws_route_table.public_subnets.id
  subnet_id = element(aws_subnet.public_subnet[*].id, count.index)
}

# ── main.tf ──────────────────────────────────────────
terraform {
  backend "s3" {
    bucket = "terrafrom-tfstate-file-s3-bucket"
    # dynamodb_table = "terraform-tfstate-dynamodb"
    encrypt = true
    key     = "aws/tfstates/remote-tf-state/dev2/terraform.tfstate"
    region  = "us-east-1"
  }

  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 4.16"
    }
  }
}

module "common_vars" {
  source = "../common"
}

# ── outputs.tf ──────────────────────────────────────────
output "sg_group_id" {
  value = aws_security_group.webserver.id
}

output "webservers_ids" {
  value = aws_instance.ubuntu_webserver[*].id
}

output "aws_instance_public_ip" {
  value = [for i in range(length(aws_instance.ubuntu_webserver)) : aws_instance.ubuntu_webserver[i].public_ip]
}

output "aws_instance_private_ip" {
  value = [for i in range(length(aws_instance.ubuntu_webserver)) : aws_instance.ubuntu_webserver[i].private_ip]
}

output "elastic_ip" {
  value = aws_eip.public_eip[*].public_ip
}

output "eip_ids" {
  value = aws_eip.public_eip[*].id
}

# ── datasource.tf ──────────────────────────────────────────
data "terraform_remote_state" "vpc" {
  backend = "s3"
  config = {
    bucket  = "terrafrom-tfstate-file-s3-bucket"
    encrypt = true
    key     = "aws/tfstates/remote-tf-state/dev1/terraform.tfstate"
    region  = "us-east-1"
  }
}

data "aws_ami" "latest_ubuntu" {
  owners      = ["099720109477"]
  most_recent = true
  filter {
    name   = "name"
    values = ["ubuntu/images/hvm-ssd-gp3/ubuntu-noble-24.04-amd64-server-*"]
  }
}

# ── instance.tf ──────────────────────────────────────────
provider "aws" {
    region = module.common_vars.region
}

resource "aws_instance" "ubuntu_webserver" {
  count         = length(data.terraform_remote_state.vpc.outputs.public_subnet_ids)
  ami           = data.aws_ami.latest_ubuntu.id
  instance_type = (module.common_vars.env == "dev" ? module.common_vars.instance_type.dev : module.common_vars.instance_type.prod)
  key_name      = "ServersKey"
  vpc_security_group_ids = [aws_security_group.webserver.id]
  subnet_id     = element(data.terraform_remote_state.vpc.outputs.public_subnet_ids, count.index)
  user_data     = file("userdata/script.sh")
  tags = merge(module.common_vars.common_tags, {
    Name        = "Ubuntu-${data.aws_ami.latest_ubuntu.id}-${count.index + 1}"
    Subnet      = element(data.terraform_remote_state.vpc.outputs.public_subnet_ids, count.index)
    Environment = "${module.common_vars.env}"
  })
}

resource "aws_security_group" "webserver" {
  name   = "${module.common_vars.env}-webserver-sg"
  vpc_id = data.terraform_remote_state.vpc.outputs.vpc_id["id"]
  dynamic "ingress" {
    for_each = module.common_vars.ingress_ports[module.common_vars.env]
    content {
      from_port   = ingress.value
      to_port     = ingress.value
      protocol    = "tcp"
      cidr_blocks = ["0.0.0.0/0"]
    }
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = merge(module.common_vars.common_tags, {
    Name        = "${module.common_vars.env}-webserver-sg"
    Environment = "${module.common_vars.env}"
  })
}

resource "aws_eip" "public_eip" {
  count = length(data.terraform_remote_state.vpc.outputs.public_subnet_ids)
  vpc   = true
}

resource "aws_eip_association" "eip_assoc" {
  count          = length(data.terraform_remote_state.vpc.outputs.public_subnet_ids)
  instance_id    = element(aws_instance.ubuntu_webserver.*.id, count.index)
  allocation_id  = element(aws_eip.public_eip.*.id, count.index)
}

# ── main.tf ──────────────────────────────────────────
terraform {
  backend "s3" {
    bucket  = "terrafrom-tfstate-file-s3-bucket"
    encrypt = true
    key     = "aws/tfstates/remote-tf-state/dev3/terraform.tfstate"
    region  = "us-east-1"
  }

  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 4.16"
    }
  }
}

module "common_vars" {
  source = "../common"
}

# ── outputs.tf ──────────────────────────────────────────
output "ec2_remote_state_outputs" {
  value = data.terraform_remote_state.ec2.outputs
}

output "nlb_dns_name" {
  value = aws_lb.webservers_nlb.dns_name
}

# ── alb.tf ──────────────────────────────────────────
resource "aws_lb" "webservers_nlb" {
  name               = "webservers-nlb"
  internal           = false
  load_balancer_type = "network"
  security_groups    = [data.terraform_remote_state.ec2.outputs.sg_group_id]

  enable_deletion_protection = false

  dynamic "subnet_mapping" {
    for_each = data.terraform_remote_state.vpc.outputs.public_subnet_ids
    content {
      subnet_id = data.terraform_remote_state.vpc.outputs.public_subnet_ids[subnet_mapping.key]
    }
  }

  tags = merge(module.common_vars.common_tags, {
    Name = "webservers-nlb-${module.common_vars.env}"
    Type = "NLB"
    VPC  = data.terraform_remote_state.vpc.outputs.vpc_id["id"]
  })

  depends_on = [data.terraform_remote_state.vpc]
}

resource "aws_lb_target_group" "webservers_tg" {
  name     = "webservers-tg"
  port     = 80
  protocol = "TCP"
  vpc_id   = data.terraform_remote_state.vpc.outputs.vpc_id["id"]

  health_check {
    interval            = 30
    protocol            = "TCP"
    timeout             = 5
    unhealthy_threshold = 3
    healthy_threshold   = 3
  }

  tags = merge(module.common_vars.common_tags, {
    Name        = "webservers-tg-${module.common_vars.env}"
    Environment = module.common_vars.env
  })
}

resource "aws_lb_target_group_attachment" "webservers_tg_attachment" {
  count               = length(data.terraform_remote_state.vpc.outputs.public_subnet_ids)
  target_group_arn    = aws_lb_target_group.webservers_tg.arn
  target_id           = data.terraform_remote_state.ec2.outputs.webservers_ids[count.index]
  port                = 80
}

resource "aws_lb_listener" "webservers_listener" {
  load_balancer_arn = aws_lb.webservers_nlb.arn
  port              = "80"
  protocol          = "TCP"

  default_action {
    type             = "forward"
    target_group_arn = aws_lb_target_group.webservers_tg.arn
  }
}

# ── datasource.tf ──────────────────────────────────────────
data "terraform_remote_state" "vpc" {
  backend = "s3"
  config = {
    bucket  = "terrafrom-tfstate-file-s3-bucket"
    encrypt = true
    key     = "aws/tfstates/remote-tf-state/dev1/terraform.tfstate"
    region  = "us-east-1"
  }
}

data "terraform_remote_state" "ec2" {
  backend = "s3"
  config = {
    bucket  = "terrafrom-tfstate-file-s3-bucket"
    encrypt = true
    key     = "aws/tfstates/remote-tf-state/dev2/terraform.tfstate"
    region  = "us-east-1"
  }
}

# ── variables.tf ──────────────────────────────────────────
variable "region" {
  default = "us-east-1"
}

variable "env" {
  default = "dev"
}

variable "vpc_cidr" {
  default = "10.0.0.0/16"
}

variable "public_subnet_cidrs" {
  default = [
    "10.0.10.0/24",
    "10.0.11.0/24"
  ]
}

variable "private_subnet_cidrs" {
  default = [
    "10.0.20.0/24",
    "10.0.21.0/24"
  ]
}

variable "common_tags" {
  default = {
    Owner : "Valerii Vasianovych"
  }
}

# ── outputs.tf ──────────────────────────────────────────
output "vpc_id" {
  value = aws_vpc.main.id
}

output "public_subnet_cidrs" {
  value = var.public_subnet_cidrs
}

output "private_subnet_cidrs" {
  value = var.private_subnet_cidrs
}

output "account_id" {
  value = data.aws_caller_identity.current.id
}

# ── datasource.tf ──────────────────────────────────────────
data "aws_availability_zones" "available" {}
data "aws_caller_identity" "current" {}

# ── private-subnet.tf ──────────────────────────────────────────
resource "aws_eip" "nat" {
  count = length(var.private_subnet_cidrs) # Number of EIPs for NAT gateways based on the number of private subnets
  tags = merge(var.common_tags, {
    Name   = "${var.env}-nat-eip-${count.index + 1}"
    Region = "Region: ${var.region}"
  })
}

resource "aws_nat_gateway" "nat" {
  count         = length(var.private_subnet_cidrs) # Number of NAT gateways based on the number of private subnets
  allocation_id = aws_eip.nat[count.index].id # Each NAT gateway is associated with a separate EIP
  subnet_id     = element(aws_subnet.public_subnets[*].id, count.index) # value of the public subnet ID, used to associate the NAT gateway with each private subnet
  tags = merge(var.common_tags, {
    Name   = "${var.env}-nat-gw-${count.index + 1}"
    Region = "Region: ${var.region}"
  })
}

resource "aws_subnet" "private_subnets" {
  count             = length(var.private_subnet_cidrs) # Number of private subnets based on the number of CIDRs provided
  vpc_id            = aws_vpc.main.id
  cidr_block        = element(var.private_subnet_cidrs, count.index) # Number of CIDRs provided for private subnets based on the count.index
  availability_zone = data.aws_availability_zones.available.names[count.index] # Availability zone based on the count.index
  tags = merge(var.common_tags, {
    Name   = "${var.env}-private-subnet-${count.index + 1}"
    Region = "Region: ${var.region}"
  })
}

resource "aws_route_table" "private_subnets" {
  count  = length(var.private_subnet_cidrs) # Number of route tables based on the number of private subnets
  vpc_id = aws_vpc.main.id
  route {
    cidr_block = "0.0.0.0/0"
    # gateway_id = aws_nat_gateway.nat[count.index].id
  }
  tags = merge(var.common_tags, {
    Name   = "${var.env}-route-private-subnets-${count.index + 1}"
    Region = "Region: ${var.region}"
  })
}

resource "aws_route_table_association" "private_routes" {
  count          = length(aws_subnet.private_subnets[*].id) # Number of route table associations based on the number of private subnets
  route_table_id = aws_route_table.private_subnets[count.index].id # Route table ID based on the count.index
  subnet_id      = element(aws_subnet.private_subnets[*].id, count.index) # Subnet ID based on the count.index
}

# ── public-subnet.tf ──────────────────────────────────────────
resource "aws_subnet" "public_subnets" {
  count                   = length(var.public_subnet_cidrs)
  vpc_id                  = aws_vpc.main.id
  cidr_block              = element(var.public_subnet_cidrs, count.index)
  availability_zone       = data.aws_availability_zones.available.names[count.index]
  map_public_ip_on_launch = true
  tags = merge(var.common_tags, {
    Name   = "${var.env}-public-subnet-${count.index + 1}"
    Region = "Region: ${var.region}"
  })
}

resource "aws_route_table" "public_subnets" {
  vpc_id = aws_vpc.main.id
  route {
    cidr_block = "0.0.0.0/0"
    gateway_id = aws_internet_gateway.main.id
  }
  tags = merge(var.common_tags, {
    Name   = "${var.env}-route-public-subnets"
    Region = "Region: ${var.region}"
  })
}

resource "aws_route_table_association" "public_routes" {
  count          = length(aws_subnet.public_subnets[*].id) # Number of route table associations based on the number of public subnets
  route_table_id = aws_route_table.public_subnets.id # Route table ID based on the count.index
  subnet_id      = element(aws_subnet.public_subnets[*].id, count.index) # ID of public subnet based on the count.index
}

# ── vpc.tf ──────────────────────────────────────────
resource "aws_vpc" "main" {
  cidr_block = var.vpc_cidr
  tags = merge(var.common_tags, {
    Name   = "${var.env}-vpc"
    Region = "Region: ${var.region}"
  })
}

resource "aws_internet_gateway" "main" {
  vpc_id = aws_vpc.main.id
  tags = merge(var.common_tags, {
    Name   = "${var.env}-igw"
    Region = "Region: ${var.region}"
  })
}

