locals {
  create_public_resources  = length(var.public_subnet_ids) > 0
  create_private_resources = length(var.private_subnet_ids) > 0
  create_db_resources      = length(var.db_private_subnet_ids) > 0

  use_nlb       = local.create_private_resources && length(var.private_subnet_ids) == 1
  use_alb       = local.create_private_resources && length(var.private_subnet_ids) >= 2
}

# ── outputs.tf ──────────────────────────────────────────
output "bastion_instance_id" {
  value       = local.create_public_resources ? data.aws_instances.bastion_instances[0].ids : []
  description = "List of IDs of the bastion instances managed by the ASG."
}

output "bastion_instance_ip" {
  value       = local.create_public_resources ? data.aws_instances.bastion_instances[0].public_ips : []
  description = "List of public IPs of the bastion instances managed by the ASG."
}

output "bastion_host_azs" {
  value       = local.create_public_resources ? [data.aws_subnet.public_subnets[0].availability_zone] : []
  description = "List of Availability Zones of the bastion instances."
}

output "private_instance_id" {
  value       = local.create_private_resources ? data.aws_instances.private_instances[0].ids : []
  description = "List of IDs of the private instances managed by the ASG."
}

output "private_instance_ip" {
  value       = local.create_private_resources ? data.aws_instances.private_instances[0].private_ips : []
  description = "List of private IPs of the private instances managed by the ASG."
}

output "private_instances_azs" {
  value       = local.create_private_resources ? [for subnet in data.aws_subnet.private_subnets : subnet.availability_zone] : []
  description = "List of Availability Zones of the private instances."
}

output "application_domain_name" {
  value       = local.create_private_resources ? aws_route53_record.app_domain_record[0].fqdn : null
  description = "The fully qualified domain name (FQDN) of the application, or null if no private subnets are created."
}

# ── app-route53.tf ──────────────────────────────────────────
# http
# resource "aws_route53_record" "app_domain_record" {
#   zone_id = var.hosted_zone_id
#   name    = var.hosted_zone_name
#   type    = "A"

#   alias {
#     name                   = aws_lb.private_instance_alb[0].dns_name
#     zone_id                = aws_lb.private_instance_alb[0].zone_id
#     evaluate_target_health = true
#   }

#   depends_on = [aws_lb.private_instance_alb]
# }

# https
resource "aws_acm_certificate" "app_domain_cert" {
  count             = local.create_private_resources ? 1 : 0
  domain_name       = "app.${var.hosted_zone_name}"
  validation_method = "DNS"

  # subject_alternative_names = ["app.${var.hosted_zone_name}"]  # Modified to include wildcard if needed

  tags = {
    Name = "${var.env}-app-certificate"
  }

  lifecycle {
    create_before_destroy = true
  }
}

resource "aws_route53_record" "app_cert_validation" {
  for_each = local.create_private_resources ? {
    for dvo in aws_acm_certificate.app_domain_cert[0].domain_validation_options : dvo.domain_name => {
      name   = dvo.resource_record_name
      record = dvo.resource_record_value
      type   = dvo.resource_record_type
    }
  } : {}

  allow_overwrite = true
  name            = each.value.name
  records         = [each.value.record]
  ttl             = 60
  type            = each.value.type
  zone_id         = var.hosted_zone_id
}

resource "aws_acm_certificate_validation" "app_cert" {
  count                   = local.create_private_resources ? 1 : 0
  certificate_arn         = aws_acm_certificate.app_domain_cert[0].arn
  validation_record_fqdns = [for record in aws_route53_record.app_cert_validation : record.fqdn]
}

resource "aws_route53_record" "app_domain_record" {
  count   = local.create_private_resources ? 1 : 0
  zone_id = var.hosted_zone_id
  name    = "app.${var.hosted_zone_name}"
  type    = "A"

  alias {
    name                   = local.use_nlb ? aws_lb.private_instance_nlb[0].dns_name : (local.use_alb ? aws_lb.private_instance_alb[0].dns_name : "")
    zone_id                = local.use_nlb ? aws_lb.private_instance_nlb[0].zone_id : (local.use_alb ? aws_lb.private_instance_alb[0].zone_id : "")
    evaluate_target_health = true
  }

  depends_on = [aws_lb.private_instance_nlb, aws_lb.private_instance_alb]
}

# ── datasource.tf ──────────────────────────────────────────
data "aws_instances" "bastion_instances" {
  count = length(var.public_subnet_ids) > 0 ? 1 : 0

  instance_tags = {
    Name = "${var.env}-bastion-host-asg-*"
  }
}

data "aws_instances" "private_instances" {
  count = length(var.private_subnet_ids) > 0 ? 1 : 0

  instance_tags = {
    Name = "${var.env}-private-instance-asg-*"
  }

  depends_on = [aws_autoscaling_group.private_instance_asg]
}

data "aws_subnet" "public_subnets" {
  count = length(var.public_subnet_ids)
  id    = var.public_subnet_ids[count.index]
}

data "aws_subnet" "private_subnets" {
  count = length(var.private_subnet_ids)
  id    = var.private_subnet_ids[count.index]
}

data "aws_subnet" "db_private_subnets" {
  count = length(var.db_private_subnet_ids)
  id    = var.db_private_subnet_ids[count.index]
}

# ── private-instance.tf ──────────────────────────────────────────
# Creation of NLB for private instances
resource "aws_lb" "private_instance_nlb" {
  count              = local.use_nlb ? 1 : 0
  name               = "${var.env}-private-instance-nlb"
  internal           = true
  load_balancer_type = "network"
  subnets            = var.private_subnet_ids

  tags = {
    Name = "${var.env}-private-instance-nlb"
  }
}

resource "aws_lb_target_group" "private_instance_tg_nlb" {
  count       = local.use_nlb ? 1 : 0
  name        = "${var.env}-private-tg-nlb"
  port        = 80
  protocol    = "TCP"
  vpc_id      = var.vpc_id
  target_type = "instance"

  health_check {
    protocol            = "TCP"
    interval            = 30
    timeout             = 10
    healthy_threshold   = 3
    unhealthy_threshold = 3
  }

  tags = {
    Name = "${var.env}-private-tg-nlb"
  }
}

resource "aws_lb_listener" "private_instance_listener_nlb_tls" {
  count             = local.use_nlb ? 1 : 0
  load_balancer_arn = aws_lb.private_instance_nlb[0].arn
  port              = 443
  protocol          = "TLS"
  certificate_arn   = local.create_private_resources ? aws_acm_certificate_validation.app_cert[0].certificate_arn : ""

  default_action {
    type             = "forward"
    target_group_arn = aws_lb_target_group.private_instance_tg_nlb[0].arn
  }

  depends_on = [aws_acm_certificate_validation.app_cert]
}

# Creation of ALB for private instances
resource "aws_lb" "private_instance_alb" {
  count              = local.use_alb ? 1 : 0
  name               = "${var.env}-private-instance-alb"
  internal           = true
  load_balancer_type = "application"
  security_groups    = [aws_security_group.private_sg[0].id]
  subnets            = var.private_subnet_ids

  tags = {
    Name = "${var.env}-private-instance-alb"
  }
}

resource "aws_lb_target_group" "private_instance_tg_alb" {
  count       = local.use_alb ? 1 : 0
  name        = "${var.env}-private-tg-alb"
  port        = 80
  protocol    = "HTTP"
  vpc_id      = var.vpc_id
  target_type = "instance"

  health_check {
    path                = "/"
    protocol            = "HTTP"
    matcher             = "200"
    interval            = 30
    timeout             = 5
    healthy_threshold   = 2
    unhealthy_threshold = 2
  }

  tags = {
    Name = "${var.env}-private-tg-alb"
  }
}

resource "aws_lb_listener" "private_instance_listener_alb_https" {
  count             = local.use_alb ? 1 : 0
  load_balancer_arn = aws_lb.private_instance_alb[0].arn
  port              = 443
  protocol          = "HTTPS"
  ssl_policy        = "ELBSecurityPolicy-TLS13-1-2-2021-06"
  certificate_arn   = local.create_private_resources ? aws_acm_certificate_validation.app_cert[0].certificate_arn : ""

  default_action {
    type             = "forward"
    target_group_arn = aws_lb_target_group.private_instance_tg_alb[0].arn
  }

  depends_on = [aws_acm_certificate_validation.app_cert]
}

# resource "aws_lb_listener" "private_instance_listener" {
#   count             = local.create_private_resources ? 1 : 0
#   load_balancer_arn = aws_lb.private_instance_alb[0].arn
#   port              = "80"
#   protocol          = "HTTP"

#   default_action {
#     type             = "forward"
#     target_group_arn = aws_lb_target_group.private_instance_tg[0].arn
#   }
# }

# Creation of ASG for private instances
resource "aws_launch_template" "private_instance_lt" {
  count         = local.create_private_resources ? 1 : 0
  image_id      = var.ami
  instance_type = var.instance_type_private_instance
  key_name      = var.key_name
  user_data     = filebase64("${path.module}/scripts/install-nginx.sh")
  network_interfaces {
    associate_public_ip_address = false
    security_groups             = [aws_security_group.private_sg[0].id]
  }

  metadata_options {
    http_endpoint = "enabled"
    http_tokens   = "required"
  }
  tags = {
    Name = "${var.env}-private-instance-lt"
  }
}

resource "aws_autoscaling_group" "private_instance_asg" {
  count               = local.create_private_resources ? 1 : 0
  vpc_zone_identifier = var.private_subnet_ids
  desired_capacity    = local.use_nlb ? 2 : length(var.private_subnet_ids)
  max_size            = local.use_nlb ? 2 : length(var.private_subnet_ids)
  min_size            = 1

  launch_template {
    id      = aws_launch_template.private_instance_lt[0].id
    version = "$Latest"
  }

  target_group_arns = local.create_private_resources ? (local.use_nlb ? [aws_lb_target_group.private_instance_tg_nlb[0].arn] : [aws_lb_target_group.private_instance_tg_alb[0].arn]) : []

  dynamic "tag" {
    for_each = {
      for idx in range(local.use_nlb ? 2 : length(var.private_subnet_ids)) : idx => {
        key   = "Name"
        value = format("${var.env}-private-instance-%03d", idx + 1)
      }
    }
    content {
      key                 = tag.value.key
      value               = tag.value.value
      propagate_at_launch = true
    }
  }
}

# ── rds-instance.tf ──────────────────────────────────────────

# ── security-groups.tf ──────────────────────────────────────────
# SG for bastion host 80 443 and 22

resource "aws_security_group" "public_sg" {
  count       = length(var.public_subnet_ids) > 0 ? 1 : 0
  name        = "${var.env}-security-group-public"
  vpc_id      = var.vpc_id
  description = "Allows traffic for instances in public subnets"
  dynamic "ingress" {
    for_each = [for port in var.public_sg : port if port != 1194]
    content {
      from_port   = ingress.value
      to_port     = ingress.value
      protocol    = "tcp"
      cidr_blocks = ["0.0.0.0/0"]
    }
  }

  dynamic "ingress" {
    for_each = [for port in var.public_sg : port if port == 1194]
    content {
      from_port   = ingress.value
      to_port     = ingress.value
      protocol    = "udp"
      cidr_blocks = ["0.0.0.0/0"]
    }
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
  tags = {
    Name = "${var.env}-security-group-public"
  }
}

resource "aws_security_group" "private_sg" {
  count       = length(var.private_subnet_ids) > 0 ? 1 : 0
  name        = "${var.env}-security-group-private"
  vpc_id      = var.vpc_id
  description = "Allows traffic for instances in public subnets"
  dynamic "ingress" {
    for_each = var.private_sg
    content {
      from_port   = ingress.value
      to_port     = ingress.value
      protocol    = "tcp"
      cidr_blocks = ["10.0.0.0/16"]
    }
  }
  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
  tags = {
    Name = "${var.env}-security-group-private"
  }
}

resource "aws_security_group" "db_sg" {
  count       = length(var.db_private_subnet_ids) > 0 ? 1 : 0
  name        = "${var.env}-security-group-db"
  vpc_id      = var.vpc_id
  description = "Allows traffic for instances in public subnets"
  dynamic "ingress" {
    for_each = var.db_private_sg
    content {
      from_port   = ingress.value
      to_port     = ingress.value
      protocol    = "tcp"
      cidr_blocks = ["10.0.0.0/16"]
    }
  }
  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
  tags = {
    Name = "${var.env}-security-group-db"
  }
}

# ── vpn-endpoint.tf ──────────────────────────────────────────
# Client VPN Resources
resource "aws_ec2_client_vpn_endpoint" "vpn_endpoint" {
  count                  = local.create_private_resources ? 1 : 0
  description            = "${var.env}-client-vpn-endpoint"
  client_cidr_block      = var.client_vpn_cidr_block
  split_tunnel           = true
  server_certificate_arn = var.vpn_server_cert_arn
  security_group_ids     = [aws_security_group.private_sg[0].id]
  vpc_id                 = var.vpc_id
  transport_protocol     = "udp"

  authentication_options {
    type                       = "certificate-authentication"
    root_certificate_chain_arn = var.vpn_client_cert_arn
  }

  connection_log_options {
    enabled = false
  }

  tags = {
    Name        = "${var.env}-client-vpn"
    Environment = var.env
  }
}

resource "aws_ec2_client_vpn_network_association" "vpn_associations" {
  count                  = local.create_private_resources ? length(var.private_subnet_ids) : 0
  client_vpn_endpoint_id = aws_ec2_client_vpn_endpoint.vpn_endpoint[0].id
  subnet_id              = var.private_subnet_ids[count.index]
}

resource "aws_ec2_client_vpn_authorization_rule" "vpn_auth_rule" {
  count                  = local.create_private_resources ? 1 : 0
  client_vpn_endpoint_id = aws_ec2_client_vpn_endpoint.vpn_endpoint[0].id
  target_network_cidr    = "0.0.0.0/0"
  authorize_all_groups   = true

  depends_on = [aws_ec2_client_vpn_network_association.vpn_associations]
}

# ── variables.tf ──────────────────────────────────────────
# Infrastructure Configuration
variable "region" {
  description = "The AWS region"
  type        = string
  default     = ""
}

variable "env" {
  description = "The environment"
  type        = string
  default     = ""
}

variable "account_id" {
  description = "The AWS account ID"
  type        = string
  default     = ""
}

# Network Configuration
variable "vpc_id" {
  description = "The VPC ID"
  type        = string
  default     = ""
}

variable "vpc_cidr" {
  description = "The CIRDR block for the VPC"
  type        = string
  default     = ""
}

variable "public_subnet_cidrs" {
  description = "The CIDR blocks for the public subnets"
  type        = list(string)
  default     = []
}

variable "private_subnet_cidrs" {
  description = "The CIDR blocks for the private subnets"
  type        = list(string)
  default     = []
}

variable "db_private_subnet_cidrs" {
  description = "The CIDR blocks for the database subnets"
  type        = list(string)
  default     = []
}

# ── outputs.tf ──────────────────────────────────────────
output "region" {
  value = var.region
}

output "env" {
  value = var.env
}

output "vpc_id" {
  value = aws_vpc.main.id
}

output "vpc_cidr_block" {
  value = aws_vpc.main.cidr_block
}

output "public_subnet_cidr_blocks" {
  value = length(aws_subnet.public_subnets) > 0 ? aws_subnet.public_subnets[*].cidr_block : []
}

output "public_subnet_ids" {
  value = length(aws_subnet.public_subnets) > 0 ? aws_subnet.public_subnets[*].id : []
}

output "private_subnet_cidr_blocks" {
  value = length(aws_subnet.private_subnets) > 0 ? aws_subnet.private_subnets[*].cidr_block : []
}

output "private_subnet_ids" {
  value = length(aws_subnet.private_subnets) > 0 ? aws_subnet.private_subnets[*].id : []
}

output "db_private_subnet_cidr_blocks" {
  value = length(aws_subnet.db_private_subnets) > 0 ? aws_subnet.db_private_subnets[*].cidr_block : []

}

output "db_private_subnet_ids" {
  value = length(aws_subnet.db_private_subnets) > 0 ? aws_subnet.db_private_subnets[*].id : []
}

# ── db_subnets.tf ──────────────────────────────────────────
resource "aws_subnet" "db_private_subnets" {
  count             = length(var.db_private_subnet_cidrs)
  vpc_id            = aws_vpc.main.id
  cidr_block        = element(var.db_private_subnet_cidrs, count.index)
  availability_zone = data.aws_availability_zones.available.names[count.index]
  tags = {
    Name = "${var.env}-db-private-subnet-${count.index + 1}"
    CIDR = element(var.db_private_subnet_cidrs, count.index)
  }
}

# not be able to access the internet from and to
resource "aws_route_table" "db_private_subnets" {
  count  = length(var.db_private_subnet_cidrs)
  vpc_id = aws_vpc.main.id
  tags = {
    Name = "${var.env}-db-route-private-subnets-${count.index + 1}"
  }
}

resource "aws_route_table_association" "db_private_routes" {
  count          = length(aws_subnet.db_private_subnets[*].id)
  route_table_id = aws_route_table.db_private_subnets[count.index].id
  subnet_id      = element(aws_subnet.db_private_subnets[*].id, count.index)
}

# ── private-subnets.tf ──────────────────────────────────────────
resource "aws_eip" "nat" {
  count = length(var.private_subnet_cidrs)
  tags = {
    Name = "${var.env}-eip-${count.index + 1}"
  }
}

resource "aws_nat_gateway" "nat" {
  count         = length(var.private_subnet_cidrs)
  allocation_id = aws_eip.nat[count.index].id
  subnet_id     = aws_subnet.public_subnets[count.index].id
  tags = {
    Name = "${var.env}-nat-gw-${count.index + 1}"
  }
}

resource "aws_subnet" "private_subnets" {
  count             = length(var.private_subnet_cidrs)
  vpc_id            = aws_vpc.main.id
  cidr_block        = var.private_subnet_cidrs[count.index]
  availability_zone = data.aws_availability_zones.available.names[count.index]
  tags = {
    Name = "${var.env}-private-subnet-${count.index + 1}"
    CIDR = var.private_subnet_cidrs[count.index]
  }
}

resource "aws_route_table" "private_subnets" {
  count  = length(var.private_subnet_cidrs)
  vpc_id = aws_vpc.main.id
  route {
    cidr_block     = "0.0.0.0/0"
    nat_gateway_id = aws_nat_gateway.nat[count.index].id
  }
  tags = {
    Name = "${var.env}-route-private-subnets-${count.index + 1}"
  }
}

resource "aws_route_table_association" "private_routes" {
  count          = length(var.private_subnet_cidrs)
  route_table_id = aws_route_table.private_subnets[count.index].id
  subnet_id      = aws_subnet.private_subnets[count.index].id
}

# ── public-subnets.tf ──────────────────────────────────────────
resource "aws_subnet" "public_subnets" {
  count                   = length(var.public_subnet_cidrs)
  vpc_id                  = aws_vpc.main.id
  cidr_block              = element(var.public_subnet_cidrs, count.index)
  availability_zone       = data.aws_availability_zones.available.names[count.index]
  map_public_ip_on_launch = true
  tags = {
    Name = "${var.env}-public-subnet-${count.index + 1}"
    CIDR = element(var.public_subnet_cidrs, count.index)
  }
}

resource "aws_route_table" "public_subnets" {
  vpc_id = aws_vpc.main.id
  route {
    cidr_block = "0.0.0.0/0"
    gateway_id = aws_internet_gateway.main.id
  }
  tags = {
    Name = "${var.env}-route-public-subnets"
  }
}

resource "aws_route_table_association" "public_routes" {
  count          = length(aws_subnet.public_subnets[*].id)
  route_table_id = aws_route_table.public_subnets.id
  subnet_id      = element(aws_subnet.public_subnets[*].id, count.index)
}

# ── vpc.tf ──────────────────────────────────────────
data "aws_availability_zones" "available" {}

resource "aws_vpc" "main" {
  cidr_block = var.vpc_cidr
  tags = {
    Name = "vpc-${var.env}"
  }
}

resource "aws_internet_gateway" "main" {
  vpc_id = aws_vpc.main.id
  tags = {
    Name = "igw-${var.env}"
  }
}

terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 3.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"

  default_tags {
    tags = {
      Owner     = "Valerii Vasianovych"
      CreatedBy = "Terraform"
      Project   = "AWS Green/Blue Deployment with Terraform"
    }
  }
}

data "aws_availability_zones" "available" {}

data "aws_ami" "latest_ubuntu" {
  owners      = ["099720109477"]
  most_recent = true
  filter {
    name   = "name"
    values = ["ubuntu/images/hvm-ssd-gp3/ubuntu-noble-24.04-amd64-server-*"]
  }
}

resource "aws_default_vpc" "default" {}

resource "aws_default_subnet" "default-az1" {
  availability_zone = data.aws_availability_zones.available.names[0]
}

resource "aws_default_subnet" "default-az2" {
  availability_zone = data.aws_availability_zones.available.names[1]
}

resource "aws_security_group" "web" {
  name        = "Web Security Group"
  description = "Allow HTTP and HTTPS inbound traffic"
  vpc_id      = aws_default_vpc.default.id
  dynamic "ingress" {
    for_each = ["80", "443"]
    content {
      from_port   = ingress.value
      to_port     = ingress.value
      protocol    = "tcp"
      cidr_blocks = ["0.0.0.0/0"]
    }
  }
  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
  tags = {
    Name = "Web Security Group"
  }
}

resource "aws_launch_template" "web" {
  name                   = "WebServer-Highly-Available-LT"
  image_id               = data.aws_ami.latest_ubuntu.id
  instance_type          = "t2.micro"
  key_name               = "ServersKey"
  vpc_security_group_ids = [aws_security_group.web.id]
  user_data              = filebase64("${path.module}/script.sh")
}

resource "aws_autoscaling_group" "web" {
  name                = "WebServer-Highly-Available-ASG-Ver-${aws_launch_template.web.latest_version}"
  max_size            = 2
  min_size            = 2
  health_check_type   = "ELB"
  vpc_zone_identifier = [aws_default_subnet.default-az1.id, aws_default_subnet.default-az2.id]
  target_group_arns   = [aws_lb_target_group.web.arn]

  launch_template {
    id      = aws_launch_template.web.id
    version = aws_launch_template.web.latest_version
  }

  dynamic "tag" {
    for_each = {
      Name   = "WebServer-In-ASG-v${aws_launch_template.web.latest_version}"
      TAGKEY = "TAGVALUE"
    }
    content {
      key                 = tag.key
      value               = tag.value
      propagate_at_launch = true # This value is used for the lifecycle of the resource
    }
  }
  lifecycle {
    create_before_destroy = true
  }
}

resource "aws_lb" "web" {
  name               = "WebServer-Highly-Available-LB"
  load_balancer_type = "application"
  security_groups    = [aws_security_group.web.id]
  subnets            = ["${aws_default_subnet.default-az1.id}", "${aws_default_subnet.default-az2.id}"]
}

resource "aws_lb_target_group" "web" {
  name                 = "WebServer-Highly-Available-TG"
  port                 = 80
  protocol             = "HTTP"
  vpc_id               = aws_default_vpc.default.id
  deregistration_delay = 10
}

resource "aws_lb_listener" "http" {
  load_balancer_arn = aws_lb.web.arn
  port              = "80"
  protocol          = "HTTP"

  default_action {
    type             = "forward"
    target_group_arn = aws_lb_target_group.web.arn
  }
}

output "web_lb_url_name" {
  value = aws_lb.web.dns_name
}

# ── variables.tf ──────────────────────────────────────────
variable "region" {
  description = "The AWS region to launch the resources."
  type        = string
  default     = "us-east-1"
}

variable "bucket_name" {
  description = "The name of the S3 bucket."
  type        = string
  default     = "valerii-vasianovych.online"
}

variable "acl" {
  description = "The ACL for the S3 bucket."
  type        = string
  default     = "public-read"
}

variable "path_pages" {
  description = "The path to the static files to be uploaded to the S3 bucket."
  type        = string
  default     = "pages"
}

variable "zone_id" {
  description = "The Route 53 zone ID."
  type        = string
  default     = "Z3AQBSTGFYJSTF"
}

# ── datasource.tf ──────────────────────────────────────────
data "aws_region" "current" {}
data "aws_caller_identity" "current" {}
data "aws_route53_zone" "selected" {
  name         = var.bucket_name
  private_zone = false
}

# ── output.tf ──────────────────────────────────────────
output "region" {
  value = data.aws_region.current.name
}

output "account_id" {
  value = data.aws_caller_identity.current.account_id
}

output "bucket_name" {
  value = aws_s3_bucket.static_website.bucket
}

output "bucket_arn" {
  value = aws_s3_bucket.static_website.arn
}

output "bucket_website_domain" {
  value = "http://${var.bucket_name}"
}

output "bucket_website_domain_www" {
  value = "http://www.${var.bucket_name}"
}

# ── provider.tf ──────────────────────────────────────────
terraform {
  backend "s3" {
    bucket = "terrafrom-tfstate-file-s3-bucket"
    # dynamodb_table = "terraform-tfstate-dynamodb"
    encrypt = true
    key     = "aws/tfstates/s3-static-page/terraform.tfstate"
    region  = "us-east-1"
  }
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.16"
    }
  }
}

# ── route53.tf ──────────────────────────────────────────
resource "aws_route53_record" "root" {
  zone_id = data.aws_route53_zone.selected.zone_id
  name    = var.bucket_name
  type    = "A"
  alias {
    name                   = "s3-website-${var.region}.amazonaws.com."
    zone_id                = var.zone_id
    evaluate_target_health = false
  }
  depends_on = [aws_s3_bucket.static_website]
}

resource "aws_route53_record" "www" {
  zone_id = data.aws_route53_zone.selected.zone_id
  name    = "www.${var.bucket_name}"
  type    = "A"
  alias {
    name                   = "s3-website-${var.region}.amazonaws.com."
    zone_id                = var.zone_id
    evaluate_target_health = false
  }
  depends_on = [aws_s3_bucket.redirect_bucket]
}

# ── static-s3.tf ──────────────────────────────────────────
provider "aws" {
  region = var.region
}

resource "aws_s3_bucket" "static_website" {
  bucket = var.bucket_name

  tags = {
    Name     = "Static Website Bucket"
    Endpoint = "http://${var.bucket_name}"
  }
}

resource "aws_s3_bucket" "redirect_bucket" {
  bucket = "www.${var.bucket_name}"

  tags = {
    Name     = "www Bucket for redirect to the main bucket"
    Endpoint = "http://www.${var.bucket_name}"
  }
}

resource "aws_s3_bucket_website_configuration" "redirect_bucket_website" {
  bucket = aws_s3_bucket.redirect_bucket.id

  redirect_all_requests_to {
    host_name = var.bucket_name
  }
}

resource "aws_s3_bucket_ownership_controls" "static_website" {
  bucket = aws_s3_bucket.static_website.id
  rule {
    object_ownership = "BucketOwnerPreferred"
  }
}

resource "aws_s3_bucket_ownership_controls" "redirect_bucket" {
  bucket = aws_s3_bucket.redirect_bucket.id
  rule {
    object_ownership = "BucketOwnerPreferred"
  }
}

resource "aws_s3_bucket_public_access_block" "access_reles" {
  bucket = aws_s3_bucket.static_website.id

  block_public_acls       = false
  block_public_policy     = false
  ignore_public_acls      = false
  restrict_public_buckets = false
}

resource "aws_s3_bucket_acl" "acl_rules" {
  depends_on = [
    aws_s3_bucket_ownership_controls.static_website,
    aws_s3_bucket_public_access_block.access_reles,
  ]
  bucket = aws_s3_bucket.static_website.id
  acl    = "public-read"
}

resource "aws_s3_bucket_policy" "static_website_policy" {
  bucket = aws_s3_bucket.static_website.id

  policy = jsonencode({
    Version = "2012-10-17",
    Statement = [
      {
        Sid       = "PublicReadGetObject",
        Effect    = "Allow",
        Principal = "*",
        Action    = "s3:GetObject",
        Resource  = "arn:aws:s3:::${var.bucket_name}/*",
      }
    ]
  })
}

resource "aws_s3_bucket_website_configuration" "website_config" {
  bucket = aws_s3_bucket.static_website.id

  index_document {
    suffix = "index.html"
  }

  error_document {
    key = "error.html"
  }
}

resource "aws_s3_object" "bucket_objects" {
  for_each = fileset("${path.module}/pages", "*")

  bucket = aws_s3_bucket.static_website.id
  key    = each.value
  source = "${path.module}/pages/${each.value}"
  content_type = lookup({
    "html" = "text/html",
  }, split(".", each.value)[1], "application/octet-stream")
}

# ── main.tf ──────────────────────────────────────────
terraform {
  backend "s3" {
    bucket = "terrafrom-tfstate-file-s3-bucket"
    # dynamodb_table = "terraform-tfstate-dynamodb"
    encrypt = true
    key     = "aws/tfstates/terraform-ansible/terraform.tfstate"
    region  = "us-east-1"
  }
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.16"
    }
  }
}

# ── variables.tf ──────────────────────────────────────────
variable "region" {
  description = "AWS region"
  type        = string
  default     = "us-east-1"
}

variable "common_tags" {
  description = "Common tags for all resources"
  type        = map(string)
  default = {
    Owner       = "Valerii Vasianovych"
    Environment = "Development"
  }
}

locals {
  vpc_id           = "vpc-0f47deecc163757a6"
  subnet_id        = "subnet-001cbe6a01612ea6c"
  ssh_user         = "ubuntu"
  key_name         = "ServersKey"
  private_key_path = "~/ssh_key_pairs/aws/ServersKey.pem"
}

# ── outputs.tf ──────────────────────────────────────────
output "region" {
  value = var.region
}

output "aws_caller_identity" {
    value = data.aws_caller_identity.current.id
}

output "vpc_id" {
  value = local.vpc_id
}

output "instance_id" {
  value = aws_instance.webserver.id
}

output "instance_public_ip" {
  value = aws_instance.webserver.public_ip
}

# ── datasource.tf ──────────────────────────────────────────
data "aws_caller_identity" "current" {}

data "aws_ami" "latest_ubuntu" {
  owners      = ["099720109477"]
  most_recent = true
  filter {
    name   = "name"
    values = ["ubuntu/images/hvm-ssd-gp3/ubuntu-noble-24.04-amd64-server-*"]
  }
}

# ── instance.tf ──────────────────────────────────────────
provider "aws" {
  region = var.region
}

resource "aws_security_group" "webserver-sg" {
  name   = "webserver-sg"
  vpc_id = local.vpc_id

  dynamic "ingress" {
    for_each = [22, 80, 443]
    content {
      from_port   = ingress.value
      to_port     = ingress.value
      protocol    = "tcp"
      cidr_blocks = ["0.0.0.0/0"]
    }
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

resource "aws_instance" "webserver" {
  ami                         = data.aws_ami.latest_ubuntu.id
  instance_type               = "t2.micro"
  subnet_id                   = local.subnet_id
  associate_public_ip_address = true
  key_name                    = local.key_name
  security_groups             = [aws_security_group.webserver-sg.id]

  provisioner "remote-exec" {
    inline = ["echo 'Wait until SSH is ready'"]

    connection {
      type        = "ssh"
      user        = local.ssh_user
      private_key = file(local.private_key_path)
      host        = aws_instance.webserver.public_ip
    }
  }

  provisioner "local-exec" {
    command = "ansible-playbook -i ${aws_instance.webserver.public_ip}, --private-key ${local.private_key_path} nginx-playbook.yaml"
  }

  depends_on = [aws_security_group.webserver-sg]

  tags = merge(var.common_tags, {
    Name    = "WebServer Instance in ${var.region}"
    Project = "Terraform with Ansible"
  })
}

# ── main.tf ──────────────────────────────────────────
terraform {
  backend "s3" {
    bucket       = "terrafrom-tfstate-file-s3-bucket"
    encrypt      = true
    key          = "aws/tfstates/tasks/alb-ec2/terraform.tfstate"
    region       = "us-east-1"
    use_lockfile = true
  }
}

provider "aws" {
  region = var.region
  default_tags {
    tags = {
        Environment = var.env
        Owner = "Valerii Vasianovych"
        Project = "ALB Project"
    }
  }
}

resource "aws_eip" "alb_eip" {
  count = 1
  tags = {
    Name = "alb-eip-${count.index + 1}-${var.env}"
  }

}

