# ── datasource.tf ──────────────────────────────────────────
data "aws_availability_zones" "available" {}

# ── main.tf ──────────────────────────────────────────
provider "aws" {
  region = "us-east-1"
}

provider "awscc" {
  region = "us-east-1"
}

variable "region" {
  description = "AWS region"
  type        = string
  default     = "us-east-1"
}

variable "tags" {
  default = {
    Owner   = "Valerii Vasianovych with ID"
    Project = "Cybersecurity Project in us-east-1 region. Project: AWS Cloud and Terraform IaC"
  }
}

locals {
  refformat_tags = [for key, value in var.tags : {
    key   = key
    value = value
  }]
}

resource "aws_instance" "ubuntu_ec2" {
  ami           = data.aws_ami.latest_ubuntu.id
  instance_type = "t2.micro"
  key_name      = "aws_ssh_key"
  # add security group
  vpc_security_group_ids = [awscc_ec2_security_group.sg.id]
  tags          = merge(var.tags, { Name = "Instance A" })
}

resource "awscc_ec2_instance" "ubuntu_ec2" {
  image_id      = data.aws_ami.latest_ubuntu.id
  instance_type = "t2.micro"
  key_name      = "aws_ssh_key"
  security_group_ids = [awscc_ec2_security_group.sg.id]
  tags          = concat(local.refformat_tags, [{
    key   = "Name"
    value = "Instance B"
  }])
}

resource "awscc_ec2_security_group" "sg" {
  group_description = "Security group allowing HTTP, HTTPS, SSH and ICMP access"
  vpc_id            = data.aws_vpc.default.id

  security_group_ingress = [
    {
      ip_protocol = "tcp"
      from_port   = 80
      to_port     = 80
      cidr_ip     = "0.0.0.0/0"
      description = "Allow HTTP access"
    },
    {
      ip_protocol = "tcp"
      from_port   = 443
      to_port     = 443
      cidr_ip     = "0.0.0.0/0"
      description = "Allow HTTPS access"
    },
    {
      ip_protocol = "tcp"
      from_port   = 22
      to_port     = 22
      cidr_ip     = "0.0.0.0/0"
      description = "Allow SSH access"
    },
    {
      ip_protocol = "icmp"
      from_port   = -1
      to_port     = -1
      cidr_ip     = "0.0.0.0/0"
      description = "Allow ICMP (ping)"
    }
  ]

  security_group_egress = [
    {
      ip_protocol = "-1"
      from_port   = -1
      to_port     = -1
      cidr_ip     = "0.0.0.0/0"
      description = "Allow all outbound traffic"
    }
  ]

  tags = concat(local.refformat_tags, [{
    key   = "Name"
    value = "allow-web-ssh"
  }])
}

# ── datasource.tf ──────────────────────────────────────────
data "aws_caller_identity" "current" {}
data "aws_availability_zones" "available" {}
data "aws_region" "current" {}
data "aws_vpc" "default" {
  default = true
}
data "aws_ami" "latest_ubuntu" {
  owners      = ["099720109477"]
  most_recent = true
  filter {
    name   = "name"
    values = ["ubuntu/images/hvm-ssd-gp3/ubuntu-noble-24.04-amd64-server-*"]
  }
}

# ── main.tf ──────────────────────────────────────────
terraform {
  backend "s3" {
    bucket       = "terrafrom-tfstate-file-s3-bucket"
    encrypt      = true
    key          = "aws/tfstates/tasks/ecs/terraform.tfstate"
    region       = "us-east-1"
    use_lockfile = true
  }
}

provider "aws" {
  region = var.region

  default_tags {
    tags = {
      Name        = "ECS Cluster"
      Environment = var.env
      Owner       = "Valerii Vasianovych"
    }
  }
}

# Create Fargate ECS Cluster
resource "aws_ecs_cluster" "ecs_cluster" {
  name = "ecs-cluster-${var.env}"
}

# Create Task Definition
resource "aws_ecs_task_definition" "nginx" {
  family                   = "nginx-${var.env}"
  requires_compatibilities = ["FARGATE"]
  network_mode            = "awsvpc"
  cpu                     = 256
  memory                  = 512
  execution_role_arn      = aws_iam_role.ecs_task_execution_role.arn

  container_definitions = jsonencode([
    {
      name      = "nginx"
      image     = "nginx:latest"
      essential = true
      portMappings = [
        {
          containerPort = 80
          protocol      = "tcp"
        }
      ]
    }
  ])
}

# Create IAM role for ECS Task Execution
resource "aws_iam_role" "ecs_task_execution_role" {
  name = "ecs-task-execution-role-${var.env}"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "ecs-tasks.amazonaws.com"
        }
      }
    ]
  })
}

# Attach AWS managed policy for ECS Task Execution Role
resource "aws_iam_role_policy_attachment" "ecs_task_execution_role_policy" {
  role       = aws_iam_role.ecs_task_execution_role.name
  policy_arn = "arn:aws:iam::aws:policy/service-role/AmazonECSTaskExecutionRolePolicy"
}

# Create ECS Service
resource "aws_ecs_service" "nginx" {
  name            = "nginx-service-${var.env}"
  cluster         = aws_ecs_cluster.ecs_cluster.id
  task_definition = aws_ecs_task_definition.nginx.arn
  desired_count   = 1
  launch_type     = "FARGATE"

  network_configuration {
    subnets          = data.aws_subnets.subnets.ids
    security_groups  = [aws_security_group.nginx_service.id]
    assign_public_ip = true
  }
}

# Create Security Group for the ECS Service
resource "aws_security_group" "nginx_service" {
  name        = "nginx-service-sg-${var.env}"
  description = "Security group for Nginx ECS service"
  vpc_id      = data.aws_vpc.default.id

  ingress {
    from_port   = 80
    to_port     = 80
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

