provider "aws" {
  region = var.region_name[1]
  alias  = "region-2"
}

# ── variables.tf ──────────────────────────────────────────
variable "region_name" {
  default = ["eu-central-1", "eu-west-1"]
}

# ── outputs.tf ──────────────────────────────────────────
output "public_ip_addresse_1" {
  value = aws_instance.instance-1.public_ip
}

output "public_ip_addresse_2" {
  value = aws_instance.instance-2.public_ip
}

# ── datasource.tf ──────────────────────────────────────────
data "aws_ami" "latest_ubuntu_region_1" {
  provider    = aws.region-1
  owners      = ["099720109477"]
  most_recent = true
  filter {
    name   = "name"
    values = ["ubuntu/images/hvm-ssd-gp3/ubuntu-noble-24.04-amd64-server-*"]
  }
}

data "aws_ami" "latest_ubuntu_region_2" {
  provider    = aws.region-2
  owners      = ["099720109477"]
  most_recent = true
  filter {
    name   = "name"
    values = ["ubuntu/images/hvm-ssd-gp3/ubuntu-noble-24.04-amd64-server-*"]
  }
}

# ── instances.tf ──────────────────────────────────────────
resource "aws_instance" "instance-1" {
  provider        = aws.region-1
  ami             = data.aws_ami.latest_ubuntu_region_1.id
  instance_type   = "t2.micro"
  security_groups = [aws_security_group.security_group_region_1.name]
  #   key_name        = "SeversKey"
  user_data = templatefile("scripts/nginx-server-1.sh.tpl", {
    region = "${var.region_name[0]}"
  })
  tags = {
    Name = "Instance-${var.region_name[0]}"
  }
}

resource "aws_instance" "instance-2" {
  provider        = aws.region-2
  ami             = data.aws_ami.latest_ubuntu_region_2.id
  instance_type   = "t2.micro"
  security_groups = [aws_security_group.security_group_region_2.name]
  #   key_name        = "SeversKey"
  user_data = templatefile("scripts/nginx-server-2.sh.tpl", {
    region = "${var.region_name[1]}"
  })
  tags = {
    Name = "Instance-${var.region_name[1]}"
  }
}

resource "aws_security_group" "security_group" {
  provider = aws.region-1
  dynamic "ingress" {
    for_each = [22, 80, 443]
    content {
      from_port   = ingress.value
      to_port     = ingress.value
      protocol    = "tcp"
      cidr_blocks = ["0.0.0.0/0"]
    }
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

resource "aws_security_group" "security_group_region_1" {
  provider = aws.region-1
  dynamic "ingress" {
    for_each = [22, 80, 443]
    content {
      from_port   = ingress.value
      to_port     = ingress.value
      protocol    = "tcp"
      cidr_blocks = ["0.0.0.0/0"]
    }
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

resource "aws_security_group" "security_group_region_2" {
  provider = aws.region-2
  dynamic "ingress" {
    for_each = [22, 80, 443]
    content {
      from_port   = ingress.value
      to_port     = ingress.value
      protocol    = "tcp"
      cidr_blocks = ["0.0.0.0/0"]
    }
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

resource "aws_route53_health_check" "health_check_instance_1" {
  provider = aws.region-1
  type     = "HTTP"
  fqdn              = aws_instance.instance-1.public_dns
  ip_address        = aws_instance.instance-1.public_ip
  port              = 80
  resource_path     = "/"
  failure_threshold = 3
  request_interval  = 30

  tags = {
    Name = "HealthCheck-${var.region_name[0]}-Instance-1"
  }
}

resource "aws_route53_health_check" "health_check_instance_2" {
  provider = aws.region-2
  type     = "HTTP"
  fqdn              = aws_instance.instance-2.public_dns
  ip_address        = aws_instance.instance-2.public_ip
  port              = 80
  resource_path     = "/"
  failure_threshold = 3
  request_interval  = 30

  tags = {
    Name = "HealthCheck-${var.region_name[1]}-Instance-2"
  }
}

# ── variables.tf ──────────────────────────────────────────
# VPC-1
variable "vpc_region_1" {
  description = "The region of the VPC"
  type        = string
  default     = "us-east-1"
}

variable "vpc_cidr_1" {
  description = "The CIDR block for the VPC"
  type        = string
  default     = "10.0.0.0/16"
}

variable "subnet_cidr_1" {
  description = "The CIDR block for the subnet"
  type        = string
  default     = "10.0.10.0/24"
}

# VPC-2
variable "vpc_region_2" {
  description = "The region of the VPC"
  type        = string
  default     = "us-east-2"
}

variable "vpc_cidr_2" {
  description = "The CIDR block for the VPC"
  type        = string
  default     = "172.0.0.0/16"
}

variable "subnet_cidr_2" {
  description = "The CIDR block for the subnet"
  type        = string
  default     = "172.0.10.0/24"
}

variable "common_tags" {
  description = "Common tags for all resources"
  type        = map(string)
  default     = {
    Owner = "DevOps Team"
    Project = "AWS VPC Peering Connection"
  }
}

locals {
  vpc_1_name = "vpc-1"
  vpc_2_name = "vpc-2"
}

# ── outputs.tf ──────────────────────────────────────────
output "account_id" {
  value = data.aws_caller_identity.current.account_id
}

output "vpc_peering_id" {
  value = aws_vpc_peering_connection.vpc_peering.id
}

# VPC-1
output "vpc_1_cidr" {
  value = aws_vpc.vpc-1.cidr_block
}

output "vpc_1_id" {
  value = aws_vpc.vpc-1.id
}

output "subnet_1_cidr" {
  value = aws_subnet.subnet-1.cidr_block
}

# VPC-2
output "vpc_2_cidr" {
  value = aws_vpc.vpc-2.cidr_block
}

output "vpc_2_id" {
  value = aws_vpc.vpc-2.id
}

output "subnet_2_cidr" {
  value = aws_subnet.subnet-2.cidr_block
}

# ── datasource.tf ──────────────────────────────────────────
data "aws_caller_identity" "current" {}

# ── peering-connection.tf ──────────────────────────────────────────
resource "aws_vpc_peering_connection" "vpc_peering" {
  provider = aws.vpc-1
  vpc_id = aws_vpc.vpc-1.id
  peer_vpc_id = aws_vpc.vpc-2.id
  peer_region = var.vpc_region_2
  tags = merge(var.common_tags, {
    Name = "vpc-peering"
  })
  depends_on = [ aws_vpc.vpc-1, aws_vpc.vpc-2 ]
}

resource "aws_vpc_peering_connection_accepter" "vpc_peering_accepter" {
  provider = aws.vpc-2
  vpc_peering_connection_id = aws_vpc_peering_connection.vpc_peering.id
  auto_accept = true

  depends_on = [ aws_vpc_peering_connection.vpc_peering ]
}

# ── vpc-1.tf ──────────────────────────────────────────
provider "aws" {
  region = var.vpc_region_1
  alias  = "vpc-1"
}

resource "aws_vpc" "vpc-1" {
  cidr_block = var.vpc_cidr_1
  enable_dns_support = true
  enable_dns_hostnames = true
  tags = merge(var.common_tags, {
    Name = "vpc-1"
  })
}

resource "aws_internet_gateway" "igw-1" {
  vpc_id = aws_vpc.vpc-1.id
  tags = merge(var.common_tags, {
    Name = "igw-${local.vpc_1_name}"
  })
}

resource "aws_subnet" "subnet-1" {
  provider   = aws.vpc-1
  vpc_id     = aws_vpc.vpc-1.id
  cidr_block = var.subnet_cidr_1
  map_public_ip_on_launch = true
  tags = merge(var.common_tags, {
    Name = "subnet-${local.vpc_1_name}"
  })
}

resource "aws_route_table" "vpc_1_igw" {
  provider = aws.vpc-1
  vpc_id = aws_vpc.vpc-1.id
  route {
    cidr_block = "0.0.0.0/0"
    gateway_id = aws_internet_gateway.igw-1.id
  }
    tags = merge(var.common_tags, {
        Name = "route-table-${local.vpc_1_name}"
    })
}

resource "aws_route" "vpc_1_to_vpc_2" {
  provider = aws.vpc-1
  route_table_id = aws_route_table.vpc_1_igw.id
  destination_cidr_block = var.vpc_cidr_2
  vpc_peering_connection_id = aws_vpc_peering_connection.vpc_peering.id
}

resource "aws_route_table_association" "subnet_1_association" {
  provider = aws.vpc-1
  subnet_id = aws_subnet.subnet-1.id
  route_table_id = aws_route_table.vpc_1_igw.id
}

# ── vpc-2.tf ──────────────────────────────────────────
provider "aws" {
  region = var.vpc_region_2
  alias  = "vpc-2"
}

resource "aws_vpc" "vpc-2" {
  provider = aws.vpc-2
  cidr_block = var.vpc_cidr_2
  enable_dns_support = true
  enable_dns_hostnames = true
  tags = merge(var.common_tags, {
    Name = "vpc-2"
  })
}

resource "aws_internet_gateway" "igw-2" {
  provider = aws.vpc-2
  vpc_id = aws_vpc.vpc-2.id
  tags = merge(var.common_tags, {
    Name = "igw-${local.vpc_2_name}"
  })
}

resource "aws_subnet" "subnet-2" {
  provider   = aws.vpc-2
  vpc_id     = aws_vpc.vpc-2.id
  cidr_block = var.subnet_cidr_2
  map_public_ip_on_launch = true
  tags = merge(var.common_tags, {
    Name = "subnet-${local.vpc_2_name}"
  })
}

resource "aws_route_table" "vpc_2_igw" {
  provider = aws.vpc-2
  vpc_id = aws_vpc.vpc-2.id
  route {
    cidr_block = "0.0.0.0/0"
    gateway_id = aws_internet_gateway.igw-2.id
    }
    tags = merge(var.common_tags, {
        Name = "route-table-${local.vpc_2_name}"
    })
}

resource "aws_route" "vpc_2_to_vpc_1" {
  provider = aws.vpc-2
  route_table_id = aws_route_table.vpc_2_igw.id
  destination_cidr_block = var.vpc_cidr_1
  vpc_peering_connection_id = aws_vpc_peering_connection.vpc_peering.id
}

resource "aws_route_table_association" "subnet_2_association" {
  provider = aws.vpc-2
  subnet_id = aws_subnet.subnet-2.id
  route_table_id = aws_route_table.vpc_2_igw.id
}

# ── main.tf ──────────────────────────────────────────
terraform {
  backend "s3" {
    bucket       = "terraform-states-vv"
    encrypt      = true
    key          = "tasks/aws-ec2/terraform.tfstate"
    region       = "us-east-1"
    use_lockfile = true
  }
}

provider "aws" {
  region = var.region
  default_tags {
    tags = {
      Environment = "dev"
      Project     = "vpc-transit-gw"
    }
  }
}

module "vpc" {
  for_each = var.vpc_cidr
  source   = "terraform-aws-modules/vpc/aws"
  cidr     = each.value
  name     = each.key

  azs             = ["${var.region}a", "${var.region}b", "${var.region}c"]
  private_subnets = []
  public_subnets  = [local.public_subnet_cidrs[each.key]]

  enable_nat_gateway = false
  enable_vpn_gateway = false

  tags = {
    Terraform = "true"
    VPC_Name  = "${each.key}"
  }
}

resource "aws_security_group" "sg" {
  for_each = module.vpc

  vpc_id      = each.value.vpc_id
  name        = "${each.key}-sg"
  description = "Allow ICMP, SSH, HTTP, HTTPS"

  dynamic "ingress" {
    for_each = [22, 80, 443]
    content {
      from_port   = ingress.value
      to_port     = ingress.value
      protocol    = "tcp"
      cidr_blocks = ["0.0.0.0/0"]
    }
  }

  ingress {
    from_port   = -1
    to_port     = -1
    protocol    = "icmp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

resource "aws_instance" "ubuntu_ec2" {
  for_each = local.ec2_map

  ami                         = data.aws_ami.latest_ubuntu.id
  instance_type               = var.instance_type
  key_name                    = var.key_name
  subnet_id                   = each.value.subnet_id
  vpc_security_group_ids      = [each.value.sg_id]
  associate_public_ip_address = true

  tags = {
    Name = "ec2-${each.key}"
  }
}

resource "aws_ec2_transit_gateway" "tg" {
  region                         = var.region
  description                    = "Transit Gateway for VPCs"
  auto_accept_shared_attachments = "enable"
  tags = {
    Name = "TransitGateway"
  }
}

resource "aws_ec2_transit_gateway_vpc_attachment" "vpc_attachment" {
  for_each = module.vpc

  transit_gateway_id = aws_ec2_transit_gateway.tg.id
  vpc_id             = each.value.vpc_id
  subnet_ids         = each.value.public_subnets

  tags = {
    Name = "${each.key}-attachment"
  }
}

# | **VPC** | **Destination (CIDR)** | **Target / Attachment** |
# | ------- | ---------------------- | ----------------------- |
# | VPC1    | 10.20.0.0/16           | TGW Attachment к VPC2   |
# | VPC1    | 10.30.0.0/16           | TGW Attachment к VPC3   |
# | VPC2    | 10.10.0.0/16           | TGW Attachment к VPC1   |
# | VPC2    | 10.30.0.0/16           | TGW Attachment к VPC3   |
# | VPC3    | 10.10.0.0/16           | TGW Attachment к VPC1   |
# | VPC3    | 10.20.0.0/16           | TGW Attachment к VPC2   |

# ── variables.tf ──────────────────────────────────────────
variable "region" {
  description = "The AWS region where the resources will be created."
  type        = string
  default     = "us-east-1"
}

variable "env" {
  description = "The environment for the resources, e.g., dev, prod."
  type        = string
  default     = "dev"
}

variable "vpc_cidr" {
  default = {
    vpc1 = "10.10.0.0/16"
    vpc2 = "10.20.0.0/16"
    vpc3 = "10.30.0.0/16"
  }
  type = map(string)
}

locals {
  public_subnet_cidrs = {
    for k, v in var.vpc_cidr : k => cidrsubnet(v, 8, 10) # /16 → /24 (new bits = 8, subnet index = 10)
  }
}

locals {
  ec2_map = {
    for vpc_name, vpc_mod in module.vpc :
    vpc_name => {
      subnet_id = vpc_mod.public_subnets[0]
      sg_id     = aws_security_group.sg[vpc_name].id
    }
  }
}

locals {
  vpc_cidrs = var.vpc_cidr
}

variable "instance_type" {
  description = "The instance type for the EC2 instances."
  type        = string
  default     = "t2.micro"
}

variable "key_name" {
    type = string
    description = "The name of the key pair to use for the instance"
    default = "aws_ssh_key"
}

