  }
}

# Create a Load Balancer
resource "azurerm_lb" "tfexample" {
  name                = "my-terraform-lb"
  location            = azurerm_resource_group.tfexample.location
  resource_group_name = azurerm_resource_group.tfexample.name

  frontend_ip_configuration {
    name                 = "my-terraform-lb-frontend-ip"
    public_ip_address_id = azurerm_public_ip.tfexample.id
  }

  tags = {
    environment = "my-terraform-env"
  }
}

# Create a Load Balancer Backend Address Pool
resource "azurerm_lb_backend_address_pool" "tfexample" {
  name            = "my-terraform-lb-backend-pool"
  loadbalancer_id = azurerm_lb.tfexample.id
}

# Creste a Load Balancer health probes
resource "azurerm_lb_probe" "tfexample" {
  name            = "my-terraform-lb-probe"
  loadbalancer_id = azurerm_lb.tfexample.id
  port            = var.server_port
}

# Create a Load Balancer Rule
resource "azurerm_lb_rule" "tfexample" {
  name                           = "my-terraform-lb-rule"
  loadbalancer_id                = azurerm_lb.tfexample.id
  protocol                       = "Tcp"
  frontend_port                  = 80
  backend_port                   = var.server_port
  frontend_ip_configuration_name = "my-terraform-lb-frontend-ip"
  backend_address_pool_ids       = [azurerm_lb_backend_address_pool.tfexample.id]
  probe_id                       = azurerm_lb_probe.tfexample.id
}

# Create a Virtual Machine Scale Set
resource "azurerm_linux_virtual_machine_scale_set" "tfexample" {
  name                            = "my-terraform-vm-scale-set"
  location                        = azurerm_resource_group.tfexample.location
  resource_group_name             = azurerm_resource_group.tfexample.name
  sku                             = "Standard_DS1_v2"
  instances                       = 2
  admin_username                  = "azureuser"
  admin_password                  = "Password1234!"
  disable_password_authentication = false

  source_image_reference {
    publisher = "Canonical"
    offer     = "UbuntuServer"
    sku       = "18.04-LTS"
    version   = "latest"
  }

  os_disk {
    storage_account_type = "Standard_LRS"
    caching              = "ReadWrite"
  }

  network_interface {
    name    = "my-terraform-vm-ss-nic"
    primary = true

    ip_configuration {
      name                                   = "my-terraform-vm-ss-nic-ip"
      primary                                = true
      subnet_id                              = azurerm_subnet.tfexample.id
      load_balancer_backend_address_pool_ids = [azurerm_lb_backend_address_pool.tfexample.id]
    }
  }

  extension {
    name                 = "hostname"
    publisher            = "Microsoft.Azure.Extensions"
    type                 = "CustomScript"
    type_handler_version = "2.1"

    settings = <<SETTINGS
      {
        "commandToExecute": "echo 'Hello, World' > index.html ; nohup busybox httpd -f -p ${var.server_port} &"
      }
    SETTINGS
  }

  tags = {
    environment = "my-terraform-env"
  }
}

# ── outputs.tf ──────────────────────────────────────────
# Data source to access the properties of an existing Azure Public IP Address
data "azurerm_public_ip" "tfexample" {
  name                = azurerm_public_ip.tfexample.name
  resource_group_name = azurerm_linux_virtual_machine_scale_set.tfexample.resource_group_name
}

# # Output variable: Public IP address
output "public_ip" {
  value = data.azurerm_public_ip.tfexample.ip_address
}

# ── vars.tf ──────────────────────────────────────────
# Input variable: server port
variable "server_port" {
  description = "The port the server will use for HTTP requests"
  default     = "8080"
}

# ── main.tf ──────────────────────────────────────────
# Set the Azure Provider source and version being used
terraform {
  required_version = ">= 0.14"

  required_providers {
    azurerm = {
      source  = "hashicorp/azurerm"
      version = "~> 3.1.0"
    }
  }
}

# Configure the Microsoft Azure provider
provider "azurerm" {
  features {}
}

# Create a Resource Group if it doesn’t exist
resource "azurerm_resource_group" "tfexample" {
  name     = "my-terraform-rg"
  location = "West Europe"
}

# Create a Storage account
resource "azurerm_storage_account" "terraform_state" {
  name                     = var.storage_account_name
  resource_group_name      = azurerm_resource_group.tfexample.name
  location                 = azurerm_resource_group.tfexample.location
  account_tier             = "Standard"
  account_replication_type = "LRS"

  tags = {
    environment = "my-terraform-env"
  }
}

# Create a Storage container
resource "azurerm_storage_container" "terraform_state" {
  name                  = var.container_name
  storage_account_name  = azurerm_storage_account.terraform_state.name
  container_access_type = "private"
}

# ── outputs.tf ──────────────────────────────────────────
# Output variable: Blob Storage container name
output "blob_storage_container" {
  value = "https://${azurerm_storage_account.terraform_state.name}.blob.core.windows.net/${azurerm_storage_container.terraform_state.name}/"
}

# ── vars.tf ──────────────────────────────────────────
# Input variable: Name of Storage Account
variable "storage_account_name" {
  description = "The name of the storage account. Must be globally unique, length between 3 and 24 characters and contain numbers and lowercase letters only."
  default     = "mytfstorageaccount"
}

# Input variable: Name of Storage container
variable "container_name" {
  description = "The name of the Blob Storage container."
  default     = "my-terraform-state-container"
}

# ── main.tf ──────────────────────────────────────────
# Set the Azure Provider source and version being used
terraform {
  required_version = ">= 0.14"

  required_providers {
    azurerm = {
      source  = "hashicorp/azurerm"
      version = "~> 3.1.0"
    }
  }
}

# Configure the Microsoft Azure provider
provider "azurerm" {
  features {}
}

# ── backend.tf ──────────────────────────────────────────
# Define Terraform backend using a blob storage container on Microsoft Azure for storing the Terraform state
terraform {
  backend "azurerm" {
    resource_group_name  = "my-terraform-rg"
    storage_account_name = "mytfstorageaccount"
    container_name       = "my-terraform-state-container"
    key                  = "terraform.tfstate"
  }
}

# ── main.tf ──────────────────────────────────────────
# https://registry.terraform.io/providers/hashicorp/aws/latest/docs/resources/instance
# Resource: aws_instance

resource "aws_instance" "server" {
  # The AMI to use for the instance.
  ami = var.ami

  # The type of instance to start.
  instance_type = "t2.micro"

  lifecycle {
    create_before_destroy = true
    ignore_changes        = [tags]
  }
}

# https://registry.terraform.io/providers/hashicorp/aws/latest/docs/resources/eip
# Resource: aws_eip

resource "aws_eip" "ip" {
  vpc      = true
  instance = aws_instance.server.id
}

# ── variables.tf ──────────────────────────────────────────
variable "ami" {
  default = "ami-0ac73f33a1888c64a"
}

# ── output.tf ──────────────────────────────────────────
output "ip" {
  value = aws_eip.ip.public_ip
}

# ── provider.tf ──────────────────────────────────────────
provider "aws" {
  region  = "us-west-2"
  profile = "terraform"
}

terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 3.0"
    }
  }
  backend "s3" {
    profile = "terraform"
    bucket = "antonputra-tfstate"
    key    = "services/server.tfstate"
    region = "us-west-2"
    dynamodb_table = "tfstate"
  }
}

# create variable type object called catalog_data with attributes: about_text, architectures, description. Set default to null
variable "website_settings" {
  type = object({
    about_text    = string
    architectures = list(string)
    description   = string
  })
  default = null
}

# create ecr public repository, use dynamic block for catalog_data, iterate over website_settings object
resource "aws_ecrpublic_repository" "example" {
  repository_name = "example"

  dynamic "catalog_data" {
    for_each = var.website_settings[*]

    content {
      about_text    = catalog_data.value.about_text
      architectures = catalog_data.value.architectures
      description   = catalog_data.value.description
    }
  }
}

# create efs file system using variable env_type, set the availability_zone_name attribute to the first AZ if the env_type value is dev, otherwise null
resource "aws_efs_file_system" "example" {
  availability_zone_name = var.env_type == "dev" ? element(data.aws_availability_zones.available.names, 0) : null
  encrypted              = true
  performance_mode       = "generalPurpose"
  throughput_mode        = "bursting"
}

variable "env_type" {
  type    = string
  default = "prod"
}

data "aws_availability_zones" "available" {
}

# create elastic ip according to count of the var instance_count, create output called public_ip_list with value of all elastic ip
resource "aws_eip" "example" {
  count = var.instance_count
}

output "public_ip_list" {
  value = aws_eip.example.*.public_ip
}

variable "instance_count" {
  type = number
}

# ── aws_secretsmanager_count_if.tf ──────────────────────────────────────────
# Write Terraform configuration that creates Secrets Manager and set the secret version if var generate_secret is true

resource "aws_secretsmanager_secret" "example" {
  name = "my_secret"
}

resource "aws_secretsmanager_secret_version" "example" {
  count = var.generate_secret ? 1 : 0

  secret_id     = aws_secretsmanager_secret.example.id
  secret_string = random_password.example.result
}

resource "random_password" "example" {
  length  = 16
  special = true
}

variable "generate_secret" {
  type    = bool
  default = false
}

# ── aws_secretsmanager_version_if.tf ──────────────────────────────────────────
# Create Terraform resoource for secrets manager secret, set the secret value from variable secret_string if available, else auto-generate the secret

resource "aws_secretsmanager_secret" "example" {
  name = "my_secret"
}

resource "aws_secretsmanager_secret_version" "example" {
  secret_id     = aws_secretsmanager_secret.example.id
  secret_string = var.generate_secret ? random_password.example.result : var.secret_string
}

resource "random_password" "example" {
  length  = 16
  special = true
}

variable "secret_string" {
  type      = string
  sensitive = true
}

variable "generate_secret" {
  type    = bool
  default = false
}

# ── aws_vpc_merge_function.tf ──────────────────────────────────────────
# merge tags from two variables into locales called combined_tags, use function merge to merge tags from two variables called env_tags and business_tags
locals {
  combined_tags = merge(var.env_tags, var.business_tags)
}

variable "env_tags" {
  type = map(string)
  default = {
    Environment = "Sandbox"
  }
}

variable "business_tags" {
  type = map(string)
  default = {
    BusinessUnit = "Finance"
    Application  = "Example"
  }
}

# create vpc using the combined tags
resource "aws_vpc" "example" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_support   = true
  enable_dns_hostnames = true
  tags                 = local.combined_tags
}

