  architectures = ["arm64"]
  environment = {
    variables = {
      MY_KEY_1 = "MY_VALUE_1"
      MY_KEY_2 = "MY_VALUE_2"
    }
  }
}

# ── awscc_lambda_function_with_lambda_layer_p3.tf ──────────────────────────────────────────
# Write Terraform configuration that creates AWS Lambda Function with Lambda Layer, use awscc provider

# Create IAM Role for Lambda Function
resource "awscc_iam_role" "main" {
  description = "AWS IAM role for lambda function"
  assume_role_policy_document = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Sid    = ""
        Principal = {
          Service = "lambda.amazonaws.com"
        }
      },
    ]
  })
}

// Create local .zip file containing source code
data "archive_file" "main" {
  type        = "zip"
  source_file = "main.py"
  output_path = "lambda_function_payload.zip"
}

# Create Lambda Layer
resource "aws_lambda_layer_version" "lambda_layer" {
  filename   = "lambda_layer_payload.zip"
  layer_name = "lambda_layer_name"

  compatible_runtimes = ["python3.10"]
}

# Create Lambda Function
resource "awscc_lambda_function" "main" {
  function_name = "lambda_function_name"
  description   = "AWS Lambda function"
  code = {
    zip_file = data.archive_file.main.output_path
  }
  handler       = "main.lambda_handler"
  runtime       = "python3.10"
  layers        = [aws_lambda_layer_version.lambda_layer.arn]
  timeout       = "300"
  memory_size   = "128"
  role          = awscc_iam_role.main.arn
  architectures = ["arm64"]
  environment = {
    variables = {
      MY_KEY_1 = "MY_VALUE_1"
      MY_KEY_2 = "MY_VALUE_2"
    }
  }
}

# ── awscc_s3_bucket_name_conditional.tf ──────────────────────────────────────────
# create s3 bucket with Terraform AWSCC, if the var name_length is bigger than 0, then use random pet for bucket name, otherwise set bucket name as var bucket_name
resource "awscc_s3_bucket" "example" {
  bucket_name = var.name_length > 0 ? random_pet.example.id : var.bucket_name
}

variable "bucket_name" {
  type    = string
  default = ""
}

variable "name_length" {
  type    = number
  default = 2
}

resource "random_pet" "example" {
  keepers = {
    length = var.name_length
  }
  length = var.name_length
}

# ── awscc_s3_bucket_name_dynamic.tf ──────────────────────────────────────────
# aws_iam_policy_document for bucket policy, use dynamic block to iterate over list of iam role names. For each statement, set the action to Getobject, set resource to bucket prefix + role name, set AWS principal role ARN with combination of account id and role name

resource "awscc_s3_bucket" "example" {
}

resource "awscc_s3_bucket_policy" "example" {
  bucket          = awscc_s3_bucket.example.id
  policy_document = data.aws_iam_policy_document.example.json
}

data "aws_iam_policy_document" "example" {
  dynamic "statement" {
    for_each = var.iam_role_names
    content {
      sid       = statement.key
      actions   = ["s3:GetObject"]
      resources = ["${awscc_s3_bucket.example.arn}/${statement.value}/*"]
      principals {
        type        = "AWS"
        identifiers = ["arn:aws:iam::${var.account_id}:role/${statement.value}"]
      }
    }
  }
}

variable "iam_role_names" {
  type = list(any)
  default = [
    "my-role-1",
    "my-role-2"
  ]
}

variable "account_id" {
  type = string
}

# ── awscc_s3_bucket_p1.tf ──────────────────────────────────────────
