    variable "igw_name"{
      default = "terra-igw"
      }

# ROUTE TABLE INFO
    variable "rt_name"{
      default = "terra-rt"
      }
# ROUTE TABLE INFO
    variable "sg_name"{
      default = "terra-sg"
      }

# COMPUTE INSTANCE INFO
  variable hostname {
    default = "TerraHost"
}
  variable "instance_name" {
        default = "TerraCompute"
      }

  variable "instance_type" {
        default = "ecs.c5.large" # FREE TIERE for 3 months or ecs.t5-lc1m1.small for 1 year
