        default = "./cloud-init/centos_userdata.txt" # "./cloud-init/vm.cloud-config"
      }

variable "key_name" {
      default= "demo_ali_KeyPair"
      }

variable ssh_public_key {
  default = "~/.ssh/id_rsa_ali.pub"

}
# VNIC INFO
        variable "private_ip" {
        default = "192.168.10.51"
      }

