# ── compute.tf ──────────────────────────────────────────
terraform {
        required_version = ">= 0.12.0"
      }
######################
# DATA SOURCE
######################

data "aws_ami" "terra_img" {
   most_recent = true
  owners = ["679593333241"]

    filter {
    name = "name"
    values = ["centos-7*"]
  }

  filter {
    name = "state"
    values = ["available"]
  }
  filter {
    name   = "virtualization-type"
    values = ["hvm"]
  }

  filter {
    name   = "architecture"
    values = ["x86_64"]
  }

  filter {
    name   = "root-device-type"
    values = ["ebs"]
  }
    filter {
    name   = "block-device-mapping.volume-size"
    values = ["8"]
  }
}

locals {
  ebs_iops = var.ebs_volume_type == "io1" ? var.ebs_iops : 0
}

