#  key_name   = "var.key_KeyPair"
#  public_key = "${file("/home/brokedba/id_rsa_aws.pub")}"
#}
 #     data  "aws_subnet" "terra_sub" {
    #Required
    #count     = length(data.oci_core_subnet.terrasub.id)
    #subnet_id =lookup(oci_core_subnet.terrasub[count.index],id)
