  description = "The Name of the newly created vpc"
  value       = google_compute_network.terra_vpc.name
}
#output "vpc_id" {
#      description = "id of created vpc. "
#      value       = google_compute_network.terra_vpc.id
#    }

output "Subnet_Name" {
      description = "Name of created vpc's Subnet. "
      value       =  google_compute_subnetwork.terra_sub.name
    }
output "Subnet_id" {
      description = "id of created vpc. "
      value       = google_compute_subnetwork.terra_sub.id
    }
output "Subnet_CIDR" {
      description = "cidr block of vpc's Subnet. "
      value       = google_compute_subnetwork.terra_sub.ip_cidr_range
    }

output "fire_wall_rules" {
      description = "Shows ingress rules of the Security group "
     value       = google_compute_firewall.web-server.allow
}

##  INSTANCE OUTPUT

      output "instance_name" {
        description = " id of created instances. "
        value       = google_compute_instance.terra_instance.name
      }

      output "hostname" {
        description = " id of created instances. "
        value       = google_compute_instance.terra_instance.hostname
      }

      output "private_ip" {
        description = "Private IPs of created instances. "
        value       = google_compute_instance.terra_instance.network_interface.0.network_ip
      }

      output "public_ip" {
        description = "Public IPs of created instances. "
        value       = google_compute_instance.terra_instance.network_interface.0.access_config.0.nat_ip
      }

 output "SSH_Connection" {
     value      = format("ssh connection to instance  ${var.instance_name} ==> sudo ssh -i ~/id_rsa_gcp  ${var.admin}@%s",google_compute_instance.terra_instance.network_interface.0.access_config.0.nat_ip)
}

# ── compute.tf ──────────────────────────────────────────
provider "google" {
    credentials = file(var.gcp_credentials)
    project = var.project
    region  = var.region
    zone    = var.zone
  }
#####################
# PROJECT DATA SOURCE
#####################

data "google_client_config" "current" {

}
#variable "project_id" {
#  default = data.google_client_config.current.project
#}
#############
# Instances
#############

 resource "google_compute_instance" "terra_instance" {
  name     = var.instances_name
  hostname = var.hostname
  project  = data.google_client_config.current.project
  zone     = var.zone
  machine_type = var.vm_type

  metadata = {
   ssh-keys = "${var.admin}:${file("~/id_rsa_gcp.pub")}"   # Change Me
    startup-script        = ("${file(var.user_data)}")
  #  startup-script-custom = "stdlib::info Hello World"
  }
  network_interface {
    network            = google_compute_network.terra_vpc.self_link
    subnetwork         = google_compute_subnetwork.terra_sub.self_link
    subnetwork_project = data.google_client_config.current.project
    network_ip         = var.private_ip
  access_config {
      // Include this section to give the VM an external ip address
   }
 }

  depends_on = [data.google_client_config.current]
######################
# IMAGE
######################

  boot_disk {
    initialize_params {
      image = var.os_image[var.OS].name      #"debian-cloud/debian-9"
    }
  }
 # scratch_disk {
  #  interface = "SCSI"
  #}

scheduling {
  on_host_maintenance = "MIGRATE"
  automatic_restart   =  true
}

# service account
  service_account {
    scopes = ["https://www.googleapis.com/auth/compute.readonly"]
  }
 tags = ["web-server"]
}

######################
# ADDRESS
######################
# Reserving a static internal IP address
resource "google_compute_address" "internal_reserved_subnet_ip" {
  name         = "internal-address"
  subnetwork   = google_compute_subnetwork.terra_sub.id
  address_type = "INTERNAL"
  address      = var.private_ip
  region       = var.region
}

#resource "google_compute_address" "static" {
#  name = "ipv4-address"
#}

output "ip" {
 value = google_compute_instance.terra_instance.network_interface.0.access_config.0.nat_ip
}

# ── vpc.tf ──────────────────────────────────────────
############################
# SERVICE ACCOUNT (OPTIONAL)
############################
# Note: The user running terraform needs to have the IAM Admin role assigned to them before you can do this.
# resource "google_service_account" "instance_admin" {
#  account_id   = "instance-admin"
#  display_name = "instance s-account"
#  }
# resource "google_project_iam_binding" "instance_sa_iam" {
#  project = data.google_client_config.current.project # < PROJECT ID>
#  role    = "roles/compute.instanceAdmin.v1"
#  members = [
#    "serviceAccount:${google_service_account.instance_admin.email}"
#  ]

#################
# VPC
#################

resource "google_compute_network" "terra_vpc" {
    project   = data.google_client_config.current.project
    name = "terra-vpc"
    auto_create_subnetworks = false
    mtu                     = 1460
    }

#################
# SUBNET
#################
resource "google_compute_subnetwork" "terra_sub" {
  name          = "terra-sub"
  ip_cidr_range = var.subnet_cidr
  region        = var.region
  network       = google_compute_network.terra_vpc.name
  description   = "This is a custom subnet "
  private_ip_google_access = "true"
  log_config {
    aggregation_interval = "INTERVAL_10_MIN"
    flow_sampling        = 0.5
    metadata             = "INCLUDE_ALL_METADATA"
  }

    secondary_ip_range {
                range_name    = "subnet-01-secondary-01"
                ip_cidr_range = "192.168.64.0/24"
            }

}
######################
# Firewall
######################
# web network tag
resource "google_compute_firewall" "web-server" {
  project     = data.google_client_config.current.project  # you can Replace this with your project ID in quotes var.project_id
  name        = "allow-http-rule"
  network     = google_compute_network.terra_vpc.name
  description = "Creates firewall rule targeting tagged instances"

  allow {
    protocol = "tcp"
    ports    = ["80","22","443","3389"]
         }
   source_ranges = ["0.0.0.0/0"]
   target_tags = ["web-server"]
    timeouts {}
}

output "project" {
  value = "${data.google_client_config.current.project}"
}

provider "libvirt" {
  uri = "qemu:///system"
}
 terraform {
  required_providers {
    libvirt = {
      source  = "dmacvicar/libvirt"
      version = "0.6.2"
    }
  }
}
#provider "libvirt" {
#  alias = "server2"
#  uri   = "qemu+ssh://root@192.168.100.10/system"
#}

resource "libvirt_volume" "centos7-qcow2" {
  name = "centos7.qcow2"
  pool = "default"
  source = "https://cloud.centos.org/centos/7/images/CentOS-7-x86_64-GenericCloud.qcow2"
  #source = "./CentOS-7-x86_64-GenericCloud.qcow2"
  format = "qcow2"
}
# Use CloudInit to add our ssh-key to the instance
resource "libvirt_cloudinit_disk" "commoninit" {
 name           = "commoninit.iso"
 pool           = "default" #CHANGEME
 user_data      = data.template_file.user_data.rendered
}

data "template_file" "user_data" {
 template = file("${path.module}/cloud_init.cfg")
}
# Define KVM domain to create
resource "libvirt_domain" "centovm" {
  name   = "centovm"
  memory = "1024"
  vcpu   = 1

cloudinit = libvirt_cloudinit_disk.commoninit.id

  network_interface {
    network_name = "default"
    hostname = "terracentos"
  }

  disk {
    volume_id = "${libvirt_volume.centos7-qcow2.id}"
  }

  console {
    type = "pty"
    target_type = "serial"
    target_port = "0"
  }

  graphics {
    type = "spice"
    listen_type = "address"
    autoport = true
  }
}

# ── main.tf ──────────────────────────────────────────
// Copyright (c) 2018, 2021, Oracle and/or its affiliates.

########################
# Compartment
########################

resource "oci_identity_compartment" "this" {
  count          = var.compartment_create ? 1 : 0
  compartment_id = var.compartment_id != null ? var.compartment_id : var.tenancy_ocid
  name           = var.compartment_name
  description    = var.compartment_description
  enable_delete  = var.enable_delete
}

data "oci_identity_compartments" "this" {
  count          = var.compartment_create ? 0 : 1
  compartment_id = var.compartment_id

  filter {
    name   = "name"
    values = [var.compartment_name]
  }
}

locals {
  compartment_ids        = concat(flatten(data.oci_identity_compartments.this.*.compartments), tolist( [tomap({"id" = ""})]))
  parent_compartment_ids = concat(flatten(data.oci_identity_compartments.this.*.compartments), tolist([tomap({"compartment_id" = ""})]))
}

# ── variables.tf ──────────────────────────────────────────
// Copyright (c) 2018, 2021, Oracle and/or its affiliates.

variable "tenancy_ocid" {
  type = string
  description = "(Deprecated) The OCID of the tenancy."
  default = null
}

variable "compartment_id" {
  type = string
  description = "The OCID of the parent compartment containing the compartment. Allow for sub-compartments creation"
  default     = null
}

variable "compartment_name" {
  type = string
  description = "The name you assign to the compartment during creation. The name must be unique across all compartments in the tenancy. "
  default     = null
}

// The description is only used if compartment_create = true.
variable "compartment_description" {
  type = string
  description = "The description you assign to the compartment. Does not have to be unique, and it's changeable. "
  default     = null
}

variable "compartment_create" {
  type = bool
  description = "(Deprecated) Create the compartment or not. If true, the compartment will be managed by this module, and the user must have permissions to create the compartment; If false, compartment data will be returned about the compartment if it exists, if not found, then an empty string will be returned for the compartment ID."
  default     = true
}

variable "enable_delete" {
  type = bool
  description = "Enable compartment delete on destroy. If true, compartment will be deleted when `terraform destroy` is executed; If false, compartment will not be deleted on `terraform destroy` execution"
  default     = false
}

