terraform {
  required_version = ">= 1.5" # ">= 1.1"
  required_providers {
    oci = {
      source  = "oracle/oci"
      version = ">= 6" #"~> 4"
      # https://registry.terraform.io/providers/oracle/oci/
      configuration_aliases = [oci.home_region]
    }
    local = {
      source  = "hashicorp/local"
