# Gets supported Kubernetes versions for node pools
data "oci_containerengine_node_pool_option" "node_pool" {
  node_pool_option_id = "all"
}

# ── variables.tf ──────────────────────────────────────────
#########################################################
# Public IPs.
# Author Brokedba https://twitter.com/BrokeDba
#########################################################
provider "oci" {
  alias            = "primary"
  tenancy_ocid     = var.tenancy_ocid
  user_ocid        = var.user_ocid
  fingerprint      = var.fingerprint
  private_key_path = var.private_key_path
  region           = var.region
}

provider "oci" {
  alias            = "dr"
  tenancy_ocid     = var.tenancy_ocid
  user_ocid        = var.user_ocid
  fingerprint      = var.fingerprint
  private_key_path = var.private_key_path
  region           = var.dr_region
}
############################
#  Hidden Variable Group   #
############################
variable "tenancy_ocid" {}
variable "user_ocid" {}
variable "fingerprint" {}
variable "private_key_path" {}
variable "region" {}
variable "dr_region" {}

######################
# locals :
######################
# all cases in one map
locals {
  ips = {
    primary_site = {  # key (display_name) => value (description)
      mgmt-public_ip-vm-a = "Public IP for Firewall Primary VM management Interface"
      mgmt-public_ip-vm-b = "Public IP for Firewall Secondary VM management Interface"
      untrust-floating-public_ip = "Floating Public IP for Firewall Untrust Interface"
      untrust-floating-public_ip_frontend_1 = "Floating Public IP for Firewall Untrust Interface inbound (frontend cluster ip)"
    },
    dr_site = {
      dr-mgmt-public_ip-vm-c = "DR Public IP for Firewall Primary VM management Interface"
      dr-mgmt-public_ip-vm-d = "DR Public IP for Firewall Secondary VM management Interface"
      dr-untrust-floating-public_ip = "DR Floating Public IP for Firewall Untrust Interface"
      dr-untrust-floating-public_ip_frontend_1 = "DR Floating Public IP for Firewall Untrust Interface inbound (frontend cluster ip)"
      }
}
}

# ── output.tf ──────────────────────────────────────────
# display the Public Ips
output "Toronto_public_ips" {
      description = "Shows all public IPs and their OCIDs in Primary site [Toronto]"
      value        = { for ip,p in  oci_core_public_ip.primary_firewall_public_ip : ip => format("name: %s IP:%s OCID:%s",p.display_name,p.ip_address, p.id) }
}

output "Montreal_public_ips" {
      description = "Shows all public IPs and their OCIDs in DR site [Montreal]"
      value        = { for ip,p in  oci_core_public_ip.dr_firewall_public_ip : ip => format("name: %s IP:%s OCID:%s",p.display_name,p.ip_address, p.id) }
}

# ── publicip.tf ──────────────────────────────────────────
# ---- Terraform Version and configuration_aliases [primary Toronto, DR Montreal]
terraform {
required_version = ">= 1.0.3"
required_providers {
 oci = {
      source  = "oracle/oci"
      version = "4.105.0"
      configuration_aliases =  [ oci.primary, oci.dr ]
   }
  }
}

 resource "oci_core_public_ip" "primary_firewall_public_ip" {
    provider = oci.primary
    #Required
    for_each = local.ips.primary_site
    compartment_id = var.tenancy_ocid
    lifetime = "RESERVED"
    #Optional
    display_name = each.key
    # ---- Vnics aren't available yet, No assignment needed
    #assignedEntityId = oci_core_private_ip.test_private_ip.id
    #public_ip_pool_id = oci_core_public_ip_pool.test_public_ip_pool.id
}

 resource "oci_core_public_ip" "dr_firewall_public_ip" {
    provider = oci.dr
    #Required
    for_each = local.ips.dr_site
    compartment_id = var.tenancy_ocid
    lifetime = "RESERVED"
    #Optional
    display_name = each.key

}

# ── versions.tf ──────────────────────────────────────────
terraform {
  required_version = ">= 0.12"
}

# ── 00-params.tf ──────────────────────────────────────────
# parms file for aws ec2 cloud

#### VPC Network
variable "vpc_cidr" {
  default = "192.168.0.0/16"
}

#### NETWORK PARAMS
variable "network_http" {
  default = {
    subnet_name = "subnet_http"
    cidr        = "192.168.1.0/24"
  }
}

# ── 010-ssh-key.tf ──────────────────────────────────────────
# Define ssh to config in instance

# Create default ssh publique key
resource "aws_key_pair" "user_key" {
  key_name   = "user-key"
  public_key = "ssh-rsa  email@example.com"
}

# ── 015-ami.tf ──────────────────────────────────────────
data "aws_ami" "ubuntu" {
  most_recent = true

  filter {
    name   = "name"
    values = ["ubuntu/images/hvm-ssd/ubuntu-trusty-14.04-amd64-server-*"]
  }

  filter {
    name   = "virtualization-type"
    values = ["hvm"]
  }

  owners = ["099720109477"] # Canonical
}

# ── 020-network.tf ──────────────────────────────────────────
# Network configuration

# VPC creation
resource "aws_vpc" "terraform" {
  cidr_block           = var.vpc_cidr
  enable_dns_hostnames = true
  tags = {
    Name = "vpc-http"
  }
}

# Subnet configuration
resource "aws_subnet" "http" {
  vpc_id     = aws_vpc.terraform.id
  cidr_block = var.network_http["cidr"]
  tags = {
    Name = "subnet-http"
  }
  depends_on = [aws_internet_gateway.gw]
}

# External gateway configuration
resource "aws_internet_gateway" "gw" {
  vpc_id = aws_vpc.terraform.id
  tags = {
    Name = "internet-gateway"
  }
}

# ── 030-security-group.tf ──────────────────────────────────────────
# Security group configuration

# Default administration port
resource "aws_security_group" "administration" {
  name        = "administration"
  description = "Allow default administration service"
  vpc_id      = aws_vpc.terraform.id
  tags = {
    Name = "administration"
  }

  # Open ssh port
  ingress {
    from_port   = 22
    to_port     = 22
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  # Allow icmp
  ingress {
    from_port   = 8
    to_port     = 0
    protocol    = "icmp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  # Open access to public network
  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

# Open web port
resource "aws_security_group" "web" {
  name        = "web"
  description = "Allow web incgress trafic"
  vpc_id      = aws_vpc.terraform.id
  tags = {
    Name = "web"
  }

  # http port
  ingress {
    from_port   = 80
    to_port     = 80
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  # https port
  ingress {
    from_port   = 443
    to_port     = 443
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  # Open access to public network
  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

# ── 060-instance-http.tf ──────────────────────────────────────────
#### INSTANCE HTTP ####

# Create instance
resource "aws_instance" "http" {
  ami           = data.aws_ami.ubuntu.id
  instance_type = "t2.micro"
  key_name      = aws_key_pair.user_key.key_name
  vpc_security_group_ids = [
    aws_security_group.administration.id,
    aws_security_group.web.id,
  ]
  subnet_id = aws_subnet.http.id
  user_data = file("scripts/first-boot.sh")
  tags = {
    Name = "http-instance"
  }
}

# Attach floating ip on instance http
resource "aws_eip" "public_http" {
  vpc        = true
  instance   = aws_instance.http.id
  depends_on = [aws_internet_gateway.gw]
  tags = {
    Name = "public-http"
  }
}

# ── 070-routing-table.tf ──────────────────────────────────────────
# Create ande associate route

# Routing table configuration
resource "aws_route_table" "http" {
  vpc_id = aws_vpc.terraform.id
  route {
    cidr_block = "0.0.0.0/0"
    gateway_id = aws_internet_gateway.gw.id
  }
}

# Associate http route
resource "aws_route_table_association" "http" {
  subnet_id      = aws_subnet.http.id
  route_table_id = aws_route_table.http.id
}

# ── versions.tf ──────────────────────────────────────────
terraform {
  required_version = ">= 0.12"
}

# ── 00-params.tf ──────────────────────────────────────────
# parms file for aws ec2 cloud

#### VPC Network
variable "vpc_cidr" {
  default = "192.168.0.0/16"
}

#### NETWORK PARAMS
