# Associate http route
resource "aws_route_table_association" "http" {
  subnet_id      = aws_subnet.http.id
  route_table_id = aws_route_table.public.id
}

# Associate db route
resource "aws_route_table_association" "db" {
  subnet_id      = aws_subnet.db.id
  route_table_id = aws_route_table.public.id
}

# ── 100-outputs.tf ──────────────────────────────────────────
# Display output information

# Display http loadbalancer dns name
output "lb_hostname_http" {
  value = aws_elb.http.dns_name
}

# Display db loadbalancer dns name
output "lb_hostname_db" {
  value = aws_elb.db.dns_name
}

# ── main.tf ──────────────────────────────────────────
module "aws_reverse_proxy" {
  # Available inputs: https://github.com/futurice/terraform-utils/tree/master/aws_reverse_proxy#inputs
  # Check for updates: https://github.com/futurice/terraform-utils/compare/v11.0...master
  source = "git::ssh://git@github.com/futurice/terraform-utils.git//aws_reverse_proxy?ref=v11.0"

  origin_url             = "http://example.com/"           # note that this is just a dummy value to satisfy CloudFront, it won't ever be used with the override_* variables in place
  site_domain            = "${var.redirect_domain}"
  name_prefix            = "${var.name_prefix}"
  comment_prefix         = "${var.comment_prefix}"
  cloudfront_price_class = "${var.cloudfront_price_class}"
  viewer_https_only      = "${var.viewer_https_only}"
  lambda_logging_enabled = "${var.lambda_logging_enabled}"
  tags                   = "${var.tags}"

  add_response_headers = {
    "Strict-Transport-Security" = "${var.redirect_with_hsts ? "max-age=31557600; preload" : ""}"
    "Location"                  = "${var.redirect_url}"
  }

  override_response_status             = "${var.redirect_permanently ? "301" : "302"}"
  override_response_status_description = "${var.redirect_permanently ? "Moved Permanently" : "Found"}"

  override_response_body = <<EOF
  <!doctype html>
  <html lang="en">
  <head>
    <meta charset="utf-8">
    <title>Redirecting</title>
  </head>
  <body>
    <pre>Redirecting to: <a href="${var.redirect_url}">${var.redirect_url}</a></pre>
  </body>
  EOF
}

# ── variables.tf ──────────────────────────────────────────
variable "redirect_domain" {
  description = "Domain which will redirect to the given `redirect_url`; e.g. `\"docs.example.com\"`"
}

variable "redirect_url" {
  description = "The URL this domain redirect should send clients to; e.g. `\"https://readthedocs.org/projects/example\"`"
}

variable "name_prefix" {
  description = "Name prefix to use for objects that need to be created (only lowercase alphanumeric characters and hyphens allowed, for S3 bucket name compatibility)"
  default     = "aws-domain-redirect---"
}

variable "comment_prefix" {
  description = "This will be included in comments for resources that are created"
  default     = "Domain redirect: "
}

variable "cloudfront_price_class" {
  description = "Price class to use (`100`, `200` or `\"All\"`, see https://aws.amazon.com/cloudfront/pricing/)"
  default     = 100
}

variable "viewer_https_only" {
  description = "Set this to `false` if you need to support insecure HTTP access for clients, in addition to HTTPS"
  default     = true
}

variable "redirect_permanently" {
  description = "Which HTTP status code to use for the redirect; if `true`, uses `301 Moved Permanently`, instead of `302 Found`"
  default     = false
}

variable "redirect_with_hsts" {
  description = "Whether to send the `Strict-Transport-Security` header with the redirect (recommended for security)"
  default     = true
}

variable "lambda_logging_enabled" {
  description = "When `true`, writes information about incoming requests to the Lambda function's CloudWatch group"
  default     = false
}

variable "tags" {
  description = "AWS Tags to add to all resources created (where possible); see https://aws.amazon.com/answers/account-management/aws-tagging-strategies/"
  type        = "map"
  default     = {}
}

# ── main.tf ──────────────────────────────────────────
# Create the main EC2 instance
# https://www.terraform.io/docs/providers/aws/r/instance.html
resource "aws_instance" "this" {
  instance_type          = "${var.instance_type}"
  ami                    = "${var.instance_ami}"
  availability_zone      = "${local.availability_zone}"
  key_name               = "${aws_key_pair.this.id}"                            # the name of the SSH keypair to use for provisioning
  vpc_security_group_ids = ["${aws_security_group.this.id}"]
  subnet_id              = "${data.aws_subnet.this.id}"
  user_data              = "${sha1(local.reprovision_trigger)}"                 # this value isn't used by the EC2 instance, but its change will trigger re-creation of the resource
  tags                   = "${merge(var.tags, map("Name", "${var.hostname}"))}"
  volume_tags            = "${merge(var.tags, map("Name", "${var.hostname}"))}" # give the root EBS volume a name (+ other possible tags) that makes it easier to identify as belonging to this host

  root_block_device {
    volume_size = "${var.root_volume_size}"
  }

  connection {
    user        = "${var.ssh_username}"
    private_key = "${file("${var.ssh_private_key_path}")}"
    agent       = false                                    # don't use SSH agent because we have the private key right here
  }

  provisioner "remote-exec" {
    inline = [
      "sudo hostnamectl set-hostname ${var.hostname}",
      "echo 127.0.0.1 ${var.hostname} | sudo tee -a /etc/hosts", # https://askubuntu.com/a/59517
    ]
  }

  provisioner "remote-exec" {
    script = "${path.module}/provision-docker.sh"
  }

  provisioner "file" {
    source      = "${path.module}/provision-swap.sh"
    destination = "/home/${var.ssh_username}/provision-swap.sh"
  }

  provisioner "remote-exec" {
    inline = [
      "sh /home/${var.ssh_username}/provision-swap.sh ${var.swap_file_size} ${var.swap_swappiness}",
      "rm /home/${var.ssh_username}/provision-swap.sh",
    ]
  }
}

# Attach the separate data volume to the instance, if so configured

resource "aws_volume_attachment" "this" {
  count       = "${var.data_volume_id == "" ? 0 : 1}" # only create this resource if an external EBS data volume was provided
  device_name = "/dev/xvdh"                           # note: this depends on the AMI, and can't be arbitrarily changed
  instance_id = "${aws_instance.this.id}"
  volume_id   = "${var.data_volume_id}"
}

resource "null_resource" "provisioners" {
  count      = "${var.data_volume_id == "" ? 0 : 1}" # only create this resource if an external EBS data volume was provided
  depends_on = ["aws_volume_attachment.this"]        # because we depend on the EBS volume being available

  connection {
    host        = "${aws_instance.this.public_ip}"
    user        = "${var.ssh_username}"
    private_key = "${file("${var.ssh_private_key_path}")}"
    agent       = false                                    # don't use SSH agent because we have the private key right here
  }

  # When creating the attachment
  provisioner "remote-exec" {
    script = "${path.module}/provision-ebs.sh"
  }

  # When tearing down the attachment
  provisioner "remote-exec" {
    when   = "destroy"
    inline = ["sudo umount -v ${aws_volume_attachment.this.device_name}"]
  }
}

# ── variables.tf ──────────────────────────────────────────
# Whenever the contents of this block changes, the host should be re-provisioned
locals {
  reprovision_trigger = <<EOF
    # Trigger reprovision on variable changes:
    ${var.hostname}
    ${var.ssh_username}
    ${var.ssh_private_key_path}
    ${var.ssh_public_key_path}
    ${var.swap_file_size}
    ${var.swap_swappiness}
    ${var.reprovision_trigger}
    # Trigger reprovision on file changes:
    ${file("${path.module}/provision-docker.sh")}
    ${file("${path.module}/provision-ebs.sh")}
    ${file("${path.module}/provision-swap.sh")}
  EOF
}

locals {
  availability_zone = "${data.aws_availability_zones.this.names[0]}" # use the first available AZ in the region (AWS ensures this is constant per user)
}

variable "hostname" {
  description = "Hostname by which this service is identified in metrics, logs etc"
  default     = "aws-ec2-ebs-docker-host"
}

variable "instance_type" {
  description = "See https://aws.amazon.com/ec2/instance-types/ for options; for example, typical values for small workloads are `\"t2.nano\"`, `\"t2.micro\"`, `\"t2.small\"`, `\"t2.medium\"`, and `\"t2.large\"`"
  default     = "t2.micro"
}

variable "instance_ami" {
  description = "See https://cloud-images.ubuntu.com/locator/ec2/ for options"
  default     = "ami-0bdf93799014acdc4"                                        # Ubuntu 18.04.1 LTS (eu-central-1, amd64, hvm:ebs-ssd, 2018-09-12)
}

variable "ssh_private_key_path" {
  description = "SSH private key file path, relative to Terraform project root"
  default     = "ssh.private.key"
}

variable "ssh_public_key_path" {
  description = "SSH public key file path, relative to Terraform project root"
  default     = "ssh.public.key"
}

variable "ssh_username" {
  description = "Default username built into the AMI (see 'instance_ami')"
  default     = "ubuntu"
}

variable "vpc_id" {
  description = "ID of the VPC our host should join; if empty, joins your Default VPC"
  default     = ""
}

variable "reprovision_trigger" {
  description = "An arbitrary string value; when this value changes, the host needs to be reprovisioned"
  default     = ""
}

variable "root_volume_size" {
  description = "Size (in GiB) of the EBS volume that will be created and mounted as the root fs for the host"
  default     = 8                                                                                              # this matches the other defaults, including the selected AMI
}

variable "data_volume_id" {
  description = "The ID of the EBS volume to mount as `/data`"
  default     = ""                                             # empty string means no EBS volume will be attached
}

variable "swap_file_size" {
  description = "Size of the swap file allocated on the root volume"
  default     = "512M"                                               # a smallish default to match default 8 GiB EBS root volume
}

variable "swap_swappiness" {
  description = "Swappiness value provided when creating the swap file"
  default     = "10"                                                    # 100 will make the host use the swap as much as possible, 0 will make it use only in case of emergency
}

variable "allow_incoming_http" {
  description = "Whether to allow incoming HTTP traffic on the host security group"
  default     = false
}

variable "allow_incoming_https" {
  description = "Whether to allow incoming HTTPS traffic on the host security group"
  default     = false
}

variable "allow_incoming_dns" {
  description = "Whether to allow incoming DNS traffic on the host security group"
  default     = false
}

variable "tags" {
  description = "AWS Tags to add to all resources created (where possible); see https://aws.amazon.com/answers/account-management/aws-tagging-strategies/"
  type        = "map"
  default     = {}
}

# ── outputs.tf ──────────────────────────────────────────
output "hostname" {
  description = "Hostname by which this service is identified in metrics, logs etc"
  value       = "${var.hostname}"
}

output "public_ip" {
  description = "Public IP address assigned to the host by EC2"
  value       = "${aws_instance.this.public_ip}"
}

output "instance_id" {
  description = "AWS ID for the EC2 instance used"
  value       = "${aws_instance.this.id}"
}

output "availability_zone" {
  description = "AWS Availability Zone in which the EC2 instance was created"
  value       = "${local.availability_zone}"
}

output "ssh_username" {
  description = "Username that can be used to access the EC2 instance over SSH"
  value       = "${var.ssh_username}"
}

output "ssh_private_key_path" {
  description = "Path to SSH private key that can be used to access the EC2 instance"
  value       = "${var.ssh_private_key_path}"
}

output "ssh_private_key" {
  description = "SSH private key that can be used to access the EC2 instance"
  value       = "${file("${var.ssh_private_key_path}")}"
}

output "security_group_id" {
  description = "Security Group ID, for attaching additional security rules externally"
  value       = "${aws_security_group.this.id}"
}

# ── data.tf ──────────────────────────────────────────
# Access data about available availability zones in the current region
data "aws_availability_zones" "this" {}

# Retrieve info about the VPC this host should join

data "aws_vpc" "this" {
  default = "${var.vpc_id == "" ? true : false}"
  id      = "${var.vpc_id}"
}

data "aws_subnet" "this" {
  vpc_id            = "${data.aws_vpc.this.id}"
  availability_zone = "${local.availability_zone}"
}

# ── security.tf ──────────────────────────────────────────
# Create an SSH key pair for accessing the EC2 instance
resource "aws_key_pair" "this" {
  public_key = "${file("${var.ssh_public_key_path}")}"
}

# Create our default security group to access the instance, over specific protocols
resource "aws_security_group" "this" {
  vpc_id = "${data.aws_vpc.this.id}"
  tags   = "${merge(var.tags, map("Name", "${var.hostname}"))}"
}

# Incoming SSH & outgoing ANY needs to be allowed for provisioning to work

resource "aws_security_group_rule" "outgoing_any" {
  security_group_id = "${aws_security_group.this.id}"
  type              = "egress"
  from_port         = 0
  to_port           = 0
  protocol          = "-1"
  cidr_blocks       = ["0.0.0.0/0"]
}

resource "aws_security_group_rule" "incoming_ssh" {
  security_group_id = "${aws_security_group.this.id}"
  type              = "ingress"
  from_port         = 22
  to_port           = 22
  protocol          = "tcp"
  cidr_blocks       = ["0.0.0.0/0"]
}

# The rest of the security rules are opt-in

resource "aws_security_group_rule" "incoming_http" {
  count             = "${var.allow_incoming_http ? 1 : 0}"
  security_group_id = "${aws_security_group.this.id}"
  type              = "ingress"
  from_port         = 80
  to_port           = 80
  protocol          = "tcp"
  cidr_blocks       = ["0.0.0.0/0"]
}

resource "aws_security_group_rule" "incoming_https" {
  count             = "${var.allow_incoming_https ? 1 : 0}"
  security_group_id = "${aws_security_group.this.id}"
  type              = "ingress"
  from_port         = 443
  to_port           = 443
  protocol          = "tcp"
  cidr_blocks       = ["0.0.0.0/0"]
}

resource "aws_security_group_rule" "incoming_dns_tcp" {
  count             = "${var.allow_incoming_dns ? 1 : 0}"
  security_group_id = "${aws_security_group.this.id}"
  type              = "ingress"
  from_port         = 53
  to_port           = 53
  protocol          = "tcp"
  cidr_blocks       = ["0.0.0.0/0"]
}

resource "aws_security_group_rule" "incoming_dns_udp" {
  count             = "${var.allow_incoming_dns ? 1 : 0}"
  security_group_id = "${aws_security_group.this.id}"
  type              = "ingress"
  from_port         = 53
  to_port           = 53
  protocol          = "udp"
  cidr_blocks       = ["0.0.0.0/0"]
}

# ── main.tf ──────────────────────────────────────────
# Based on: https://www.terraform.io/docs/providers/aws/guides/serverless-with-aws-lambda-and-api-gateway.html
# See also: https://github.com/hashicorp/terraform/issues/10157
# See also: https://github.com/carrot/terraform-api-gateway-cors-module/

# This aws_lambda_function is used when invoked with a local zipfile
resource "aws_lambda_function" "local_zipfile" {
  count = "${var.function_s3_bucket == "" ? 1 : 0}"

  # These are SPECIFIC to the deployment method:
  filename         = "${var.function_zipfile}"
  source_code_hash = "${var.function_s3_bucket == "" ? "${base64sha256(file("${var.function_zipfile}"))}" : ""}"

  # These are the SAME for both:
  description   = "${var.comment_prefix}${var.api_domain}"
  function_name = "${local.prefix_with_domain}"
  handler       = "${var.function_handler}"
  runtime       = "${var.function_runtime}"
  timeout       = "${var.function_timeout}"
  memory_size   = "${var.memory_size}"
  role          = "${aws_iam_role.this.arn}"
  tags          = "${var.tags}"

  environment {
    variables = "${var.function_env_vars}"
  }
}

# This aws_lambda_function is used when invoked with a zipfile in S3
resource "aws_lambda_function" "s3_zipfile" {
  count = "${var.function_s3_bucket == "" ? 0 : 1}"

  # These are SPECIFIC to the deployment method:
  s3_bucket = "${var.function_s3_bucket}"
  s3_key    = "${var.function_zipfile}"

  # These are the SAME for both:
  description   = "${var.comment_prefix}${var.api_domain}"
  function_name = "${local.prefix_with_domain}"
  handler       = "${var.function_handler}"
  runtime       = "${var.function_runtime}"
  timeout       = "${var.function_timeout}"
  memory_size   = "${var.memory_size}"
  role          = "${aws_iam_role.this.arn}"
  tags          = "${var.tags}"

  environment {
    variables = "${var.function_env_vars}"
  }
}

# Terraform isn't particularly helpful when you want to depend on the existence of a resource which may have count 0 or 1, like our functions.
# This is a hacky way of referring to the properties of the function, regardless of which one got created.
# https://github.com/hashicorp/terraform/issues/16580#issuecomment-342573652
locals {
  function_id         = "${element(concat(aws_lambda_function.local_zipfile.*.id, list("")), 0)}${element(concat(aws_lambda_function.s3_zipfile.*.id, list("")), 0)}"
  function_arn        = "${element(concat(aws_lambda_function.local_zipfile.*.arn, list("")), 0)}${element(concat(aws_lambda_function.s3_zipfile.*.arn, list("")), 0)}"
  function_invoke_arn = "${element(concat(aws_lambda_function.local_zipfile.*.invoke_arn, list("")), 0)}${element(concat(aws_lambda_function.s3_zipfile.*.invoke_arn, list("")), 0)}"
}

# ── variables.tf ──────────────────────────────────────────
variable "api_domain" {
  description = "Domain on which the Lambda will be made available (e.g. `\"api.example.com\"`)"
}

variable "name_prefix" {
  description = "Name prefix to use for objects that need to be created (only lowercase alphanumeric characters and hyphens allowed, for S3 bucket name compatibility)"
  default     = "aws-lambda-api---"
}

variable "comment_prefix" {
  description = "This will be included in comments for resources that are created"
  default     = "Lambda API: "
}

variable "function_zipfile" {
  description = "Path to a ZIP file that will be installed as the Lambda function (e.g. `\"my-api.zip\"`)"
}

variable "function_s3_bucket" {
  description = "When provided, the zipfile is retrieved from an S3 bucket by this name instead (filename is still provided via `function_zipfile`)"
  default     = ""
}

variable "function_handler" {
  description = "Instructs Lambda on which function to invoke within the ZIP file"
  default     = "index.handler"
}

variable "function_timeout" {
  description = "The amount of time your Lambda Function has to run in seconds"
  default     = 3
}

variable "memory_size" {
  description = "Amount of memory in MB your Lambda Function can use at runtime"
  default     = 128
}

variable "function_runtime" {
  description = "Which node.js version should Lambda use for this function"
  default     = "nodejs8.10"
}

variable "function_env_vars" {
  description = "Which env vars (if any) to invoke the Lambda with"
  type        = "map"

  default = {
    # This effectively useless, but an empty map can't be used in the "aws_lambda_function" resource
    # -> this is 100% safe to override with your own env, should you need one
    aws_lambda_api = ""
  }
}

variable "stage_name" {
  description = "Name of the single stage created for the API on API Gateway" # we're not using the deployment features of API Gateway, so a single static stage is fine
  default     = "default"
}

variable "lambda_logging_enabled" {
  description = "When true, writes any console output to the Lambda function's CloudWatch group"
  default     = false
}

variable "api_gateway_logging_level" {
  description = "Either `\"OFF\"`, `\"INFO\"` or `\"ERROR\"`; note that this requires having a CloudWatch log role ARN globally in API Gateway Settings"
  default     = "OFF"
}

variable "api_gateway_cloudwatch_metrics" {
  description = "When true, sends metrics to CloudWatch"
  default     = false
}

variable "tags" {
  description = "AWS Tags to add to all resources created (where possible); see https://aws.amazon.com/answers/account-management/aws-tagging-strategies/"
  type        = "map"
  default     = {}
}

variable "throttling_rate_limit" {
  description = "How many sustained requests per second should the API process at most; see https://docs.aws.amazon.com/apigateway/latest/developerguide/api-gateway-request-throttling.html"
  default     = 10000
}

variable "throttling_burst_limit" {
  description = "How many burst requests should the API process at most; see https://docs.aws.amazon.com/apigateway/latest/developerguide/api-gateway-request-throttling.html"
  default     = 5000
}

locals {
  prefix_with_domain = "${var.name_prefix}${replace("${var.api_domain}", "/[^a-z0-9-]+/", "-")}" # only lowercase alphanumeric characters and hyphens are allowed in e.g. S3 bucket names
}

# ── outputs.tf ──────────────────────────────────────────
output "function_name" {
  description = "This is the unique name of the Lambda function that was created"
  value       = "${local.function_id}"
}

output "api_gw_invoke_url" {
  description = "This URL can be used to invoke the Lambda through the API Gateway"
  value       = "${aws_api_gateway_deployment.this.invoke_url}"
}

# ── api_gateway_config.tf ──────────────────────────────────────────
resource "aws_api_gateway_rest_api" "this" {
  name        = "${local.prefix_with_domain}"
  description = "${var.comment_prefix}${var.api_domain}"
}

resource "aws_api_gateway_deployment" "this" {
  rest_api_id = "${aws_api_gateway_rest_api.this.id}"

  depends_on = [
    "aws_api_gateway_integration.proxy_root",
    "aws_api_gateway_integration.proxy_other",
  ]
}

resource "aws_api_gateway_stage" "this" {
  stage_name    = "${var.stage_name}"
  description   = "${var.comment_prefix}${var.api_domain}"
  rest_api_id   = "${aws_api_gateway_rest_api.this.id}"
  deployment_id = "${aws_api_gateway_deployment.this.id}"
  tags          = "${var.tags}"
}

resource "aws_api_gateway_method_settings" "this" {
  rest_api_id = "${aws_api_gateway_rest_api.this.id}"
  stage_name  = "${aws_api_gateway_stage.this.stage_name}"
  method_path = "*/*"

  settings {
    metrics_enabled        = "${var.api_gateway_cloudwatch_metrics}"
    logging_level          = "${var.api_gateway_logging_level}"
    data_trace_enabled     = "${var.api_gateway_logging_level == "OFF" ? false : true}"
    throttling_rate_limit  = "${var.throttling_rate_limit}"
    throttling_burst_limit = "${var.throttling_burst_limit}"
  }
}

resource "aws_api_gateway_domain_name" "this" {
  domain_name              = "${var.api_domain}"
  regional_certificate_arn = "${aws_acm_certificate_validation.this.certificate_arn}"

  endpoint_configuration {
    types = ["REGIONAL"]
  }
}

resource "aws_api_gateway_base_path_mapping" "this" {
  api_id      = "${aws_api_gateway_rest_api.this.id}"
  stage_name  = "${aws_api_gateway_stage.this.stage_name}"
  domain_name = "${aws_api_gateway_domain_name.this.domain_name}"
}

# ── api_gateway_resources.tf ──────────────────────────────────────────
# Add root resource to the API (it it needs to be included separately from the "proxy" resource defined below), which forwards to our Lambda:

resource "aws_api_gateway_method" "proxy_root" {
  rest_api_id   = "${aws_api_gateway_rest_api.this.id}"
  resource_id   = "${aws_api_gateway_rest_api.this.root_resource_id}"
  http_method   = "ANY"
  authorization = "NONE"
}

resource "aws_api_gateway_integration" "proxy_root" {
  rest_api_id             = "${aws_api_gateway_rest_api.this.id}"
  resource_id             = "${aws_api_gateway_method.proxy_root.resource_id}"
  http_method             = "${aws_api_gateway_method.proxy_root.http_method}"
  integration_http_method = "POST"
  type                    = "AWS_PROXY"
  uri                     = "${local.function_invoke_arn}"
}

# Add a "proxy" resource, that matches all paths (except the root, defined above) and forwards them to our Lambda:

resource "aws_api_gateway_resource" "proxy_other" {
  rest_api_id = "${aws_api_gateway_rest_api.this.id}"
  parent_id   = "${aws_api_gateway_rest_api.this.root_resource_id}"
  path_part   = "{proxy+}"
}

resource "aws_api_gateway_method" "proxy_other" {
  rest_api_id   = "${aws_api_gateway_rest_api.this.id}"
  resource_id   = "${aws_api_gateway_resource.proxy_other.id}"
  http_method   = "ANY"
  authorization = "NONE"
}

resource "aws_api_gateway_integration" "proxy_other" {
  rest_api_id             = "${aws_api_gateway_rest_api.this.id}"
  resource_id             = "${aws_api_gateway_method.proxy_other.resource_id}"
  http_method             = "${aws_api_gateway_method.proxy_other.http_method}"
  integration_http_method = "POST"
  type                    = "AWS_PROXY"
  uri                     = "${local.function_invoke_arn}"
}

resource "aws_api_gateway_method_response" "proxy_other" {
  rest_api_id = "${aws_api_gateway_rest_api.this.id}"
  resource_id = "${aws_api_gateway_resource.proxy_other.id}"
  http_method = "${aws_api_gateway_method.proxy_other.http_method}"
  status_code = "200"

  response_models = {
    "application/json" = "Empty"
  }
}

resource "aws_api_gateway_integration_response" "proxy_other" {
  depends_on  = ["aws_api_gateway_integration.proxy_other"]
  rest_api_id = "${aws_api_gateway_rest_api.this.id}"
  resource_id = "${aws_api_gateway_resource.proxy_other.id}"
  http_method = "${aws_api_gateway_method.proxy_other.http_method}"
  status_code = "${aws_api_gateway_method_response.proxy_other.status_code}"

  response_templates = {
    "application/json" = ""
  }
}

# ── certificate.tf ──────────────────────────────────────────
# Generate a certificate for the domain automatically using ACM
# https://www.terraform.io/docs/providers/aws/r/acm_certificate.html
resource "aws_acm_certificate" "this" {
  domain_name       = "${var.api_domain}"
  validation_method = "DNS"                                                                       # the required records are created below
  tags              = "${merge(var.tags, map("Name", "${var.comment_prefix}${var.api_domain}"))}"
}

# Add the DNS records needed by the ACM validation process
resource "aws_route53_record" "cert_validation" {
  name    = "${aws_acm_certificate.this.domain_validation_options.0.resource_record_name}"
  type    = "${aws_acm_certificate.this.domain_validation_options.0.resource_record_type}"
  zone_id = "${data.aws_route53_zone.this.zone_id}"
  records = ["${aws_acm_certificate.this.domain_validation_options.0.resource_record_value}"]
  ttl     = 60
}

# Request a validation for the cert with ACM
resource "aws_acm_certificate_validation" "this" {
  certificate_arn         = "${aws_acm_certificate.this.arn}"
  validation_record_fqdns = ["${aws_route53_record.cert_validation.fqdn}"]
}

# ── data.tf ──────────────────────────────────────────
data "aws_route53_zone" "this" {
  name = "${replace("${var.api_domain}", "/.*\\b(\\w+\\.\\w+)\\.?$/", "$1")}" # e.g. "foo.example.com" => "example.com"
}

# ── permissions.tf ──────────────────────────────────────────
# Allow Lambda to invoke our functions:
resource "aws_iam_role" "this" {
  name = "${local.prefix_with_domain}"
  tags = "${var.tags}"

  assume_role_policy = <<EOF
{
  "Version": "2012-10-17",
  "Statement": [
    {
      "Effect": "Allow",
      "Principal": {
        "Service": [
          "lambda.amazonaws.com",
          "edgelambda.amazonaws.com"
        ]
      },
      "Action": "sts:AssumeRole"
    }
  ]
}
EOF
}

# Allow API Gateway to invoke our functions:
resource "aws_lambda_permission" "this" {
  statement_id  = "AllowAPIGatewayInvoke"
  action        = "lambda:InvokeFunction"
  function_name = "${local.function_arn}"
  principal     = "apigateway.amazonaws.com"
  source_arn    = "${aws_api_gateway_stage.this.execution_arn}/*/*" # the /*/* portion grants access from any method on any resource within the API Gateway "REST API"
}

# Allow writing logs to CloudWatch from our functions:
resource "aws_iam_policy" "this" {
  count = "${var.lambda_logging_enabled ? 1 : 0}"
  name  = "${local.prefix_with_domain}"

  policy = <<EOF
{
  "Version": "2012-10-17",
  "Statement": [
    {
      "Action": [
        "logs:CreateLogGroup",
        "logs:CreateLogStream",
        "logs:PutLogEvents"
      ],
      "Resource": "arn:aws:logs:*:*:*",
      "Effect": "Allow"
    }
  ]
}
EOF
}

resource "aws_iam_role_policy_attachment" "this" {
  count      = "${var.lambda_logging_enabled ? 1 : 0}"
  role       = "${aws_iam_role.this.name}"
  policy_arn = "${aws_iam_policy.this.arn}"
}

# ── route53.tf ──────────────────────────────────────────
# Add an IPv4 DNS record pointing to the API Gateway
resource "aws_route53_record" "ipv4" {
  zone_id = "${data.aws_route53_zone.this.zone_id}"
  name    = "${var.api_domain}"
  type    = "A"

  alias {
    name                   = "${aws_api_gateway_domain_name.this.regional_domain_name}"
    zone_id                = "${aws_api_gateway_domain_name.this.regional_zone_id}"
    evaluate_target_health = false
  }
}

# Add an IPv6 DNS record pointing to the API Gateway
resource "aws_route53_record" "ipv6" {
  zone_id = "${data.aws_route53_zone.this.zone_id}"
  name    = "${var.api_domain}"
  type    = "AAAA"

  alias {
    name                   = "${aws_api_gateway_domain_name.this.regional_domain_name}"
    zone_id                = "${aws_api_gateway_domain_name.this.regional_zone_id}"
    evaluate_target_health = false
  }
}

# ── main.tf ──────────────────────────────────────────
# This aws_lambda_function is used when invoked with a local zipfile
resource "aws_lambda_function" "local_zipfile" {
  count = "${var.function_s3_bucket == "" ? 1 : 0}"

  # These are SPECIFIC to the deployment method:
  filename         = "${var.function_zipfile}"
  source_code_hash = "${var.function_s3_bucket == "" ? "${base64sha256(file("${var.function_zipfile}"))}" : ""}"

  # These are the SAME for both:
  description   = "${var.comment_prefix}${var.cronjob_name}"
  function_name = "${local.prefix_with_name}"
  handler       = "${var.function_handler}"
  runtime       = "${var.function_runtime}"
  timeout       = "${var.function_timeout}"
  memory_size   = "${var.memory_size}"
  role          = "${aws_iam_role.this.arn}"
  tags          = "${var.tags}"

  environment {
    variables = "${var.function_env_vars}"
  }
}

# This aws_lambda_function is used when invoked with a zipfile in S3
resource "aws_lambda_function" "s3_zipfile" {
  count = "${var.function_s3_bucket == "" ? 0 : 1}"

  # These are SPECIFIC to the deployment method:
  s3_bucket = "${var.function_s3_bucket}"
  s3_key    = "${var.function_zipfile}"

  # These are the SAME for both:
  description   = "${var.comment_prefix}${var.cronjob_name}"
  function_name = "${local.prefix_with_name}"
  handler       = "${var.function_handler}"
  runtime       = "${var.function_runtime}"
  timeout       = "${var.function_timeout}"
  memory_size   = "${var.memory_size}"
  role          = "${aws_iam_role.this.arn}"
  tags          = "${var.tags}"

  environment {
    variables = "${var.function_env_vars}"
  }
}

# Terraform isn't particularly helpful when you want to depend on the existence of a resource which may have count 0 or 1, like our functions.
# This is a hacky way of referring to the properties of the function, regardless of which one got created.
# https://github.com/hashicorp/terraform/issues/16580#issuecomment-342573652
locals {
  function_id         = "${element(concat(aws_lambda_function.local_zipfile.*.id, list("")), 0)}${element(concat(aws_lambda_function.s3_zipfile.*.id, list("")), 0)}"
  function_arn        = "${element(concat(aws_lambda_function.local_zipfile.*.arn, list("")), 0)}${element(concat(aws_lambda_function.s3_zipfile.*.arn, list("")), 0)}"
  function_invoke_arn = "${element(concat(aws_lambda_function.local_zipfile.*.invoke_arn, list("")), 0)}${element(concat(aws_lambda_function.s3_zipfile.*.invoke_arn, list("")), 0)}"
}

# ── variables.tf ──────────────────────────────────────────
variable "cronjob_name" {
  description = "Name which will be used to create your Lambda function (e.g. `\"my-important-cronjob\"`)"
}

variable "name_prefix" {
  description = "Name prefix to use for objects that need to be created (only lowercase alphanumeric characters and hyphens allowed, for S3 bucket name compatibility)"
  default     = "aws-lambda-cronjob---"
}

variable "comment_prefix" {
  description = "This will be included in comments for resources that are created"
  default     = "Lambda Cronjob: "
}

variable "schedule_expression" {
  description = "How often to run the Lambda (see https://docs.aws.amazon.com/AmazonCloudWatch/latest/events/ScheduledEvents.html); e.g. `\"rate(15 minutes)\"` or `\"cron(0 12 * * ? *)\"`"
  default     = "rate(60 minutes)"
}

variable "function_zipfile" {
  description = "Path to a ZIP file that will be installed as the Lambda function (e.g. `\"my-cronjob.zip\"`)"
}

variable "function_s3_bucket" {
  description = "When provided, the zipfile is retrieved from an S3 bucket by this name instead (filename is still provided via `function_zipfile`)"
  default     = ""
}

variable "function_handler" {
  description = "Instructs Lambda on which function to invoke within the ZIP file"
  default     = "index.handler"
}

variable "function_timeout" {
  description = "The amount of time your Lambda Function has to run in seconds"
  default     = 3
}

variable "memory_size" {
  description = "Amount of memory in MB your Lambda Function can use at runtime"
  default     = 128
}

variable "function_runtime" {
  description = "Which node.js version should Lambda use for this function"
  default     = "nodejs8.10"
}

variable "function_env_vars" {
  description = "Which env vars (if any) to invoke the Lambda with"
  type        = "map"

  default = {
    # This effectively useless, but an empty map can't be used in the "aws_lambda_function" resource
    # -> this is 100% safe to override with your own env, should you need one
    aws_lambda_cronjob = ""
  }
}

variable "lambda_logging_enabled" {
  description = "When true, writes any console output to the Lambda function's CloudWatch group"
  default     = false
}

variable "tags" {
  description = "AWS Tags to add to all resources created (where possible); see https://aws.amazon.com/answers/account-management/aws-tagging-strategies/"
  type        = "map"
  default     = {}
}

locals {
  prefix_with_name = "${var.name_prefix}${replace("${var.cronjob_name}", "/[^a-z0-9-]+/", "-")}" # only lowercase alphanumeric characters and hyphens are allowed in e.g. S3 bucket names
}

# ── outputs.tf ──────────────────────────────────────────
output "function_name" {
  description = "This is the unique name of the Lambda function that was created"
  value       = "${local.function_id}"
}

# ── permissions.tf ──────────────────────────────────────────
# Allow Lambda to invoke our functions:

resource "aws_iam_role" "this" {
  name = "${local.prefix_with_name}"
  tags = "${var.tags}"

  assume_role_policy = <<EOF
{
  "Version": "2012-10-17",
  "Statement": [
    {
      "Effect": "Allow",
      "Principal": {
        "Service": [
          "lambda.amazonaws.com"
        ]
      },
      "Action": "sts:AssumeRole"
    }
  ]
}
EOF
}

# Allow writing logs to CloudWatch from our functions:

resource "aws_iam_policy" "this" {
  count = "${var.lambda_logging_enabled ? 1 : 0}"
  name  = "${local.prefix_with_name}"

  policy = <<EOF
{
  "Version": "2012-10-17",
  "Statement": [
    {
      "Action": [
        "logs:CreateLogGroup",
        "logs:CreateLogStream",
        "logs:PutLogEvents"
      ],
      "Resource": "arn:aws:logs:*:*:*",
      "Effect": "Allow"
    }
  ]
}
EOF
}

resource "aws_iam_role_policy_attachment" "this" {
  count      = "${var.lambda_logging_enabled ? 1 : 0}"
  role       = "${aws_iam_role.this.name}"
  policy_arn = "${aws_iam_policy.this.arn}"
}

# Add the scheduled execution rules & permissions:

resource "aws_cloudwatch_event_rule" "this" {
  name                = "${local.prefix_with_name}---scheduled-invocation"
  schedule_expression = "${var.schedule_expression}"
  tags                = "${var.tags}"
}

resource "aws_cloudwatch_event_target" "this" {
  rule      = "${aws_cloudwatch_event_rule.this.name}"
  target_id = "${aws_cloudwatch_event_rule.this.name}"
  arn       = "${local.function_arn}"
}

resource "aws_lambda_permission" "this" {
  statement_id  = "${local.prefix_with_name}---scheduled-invocation"
  action        = "lambda:InvokeFunction"
  function_name = "${local.function_id}"
  principal     = "events.amazonaws.com"
  source_arn    = "${aws_cloudwatch_event_rule.this.arn}"
}

# ── main.tf ──────────────────────────────────────────
# Create a new Mailgun domain
resource "mailgun_domain" "this" {
  name          = "${var.mail_domain}"
  spam_action   = "${var.spam_action}"
  wildcard      = "${var.wildcard}"
  smtp_password = "${var.smtp_password}"
}

# DNS records for domain setup & verification are below
# See https://app.mailgun.com/app/domains/<your-domain>/verify for these instructions

resource "aws_route53_record" "sending" {
  count = "${length(mailgun_domain.this.sending_records)}"

  zone_id = "${data.aws_route53_zone.this.zone_id}"
  name    = "${lookup(mailgun_domain.this.sending_records[count.index], "name")}"
  type    = "${lookup(mailgun_domain.this.sending_records[count.index], "record_type")}"
  ttl     = 300

  records = [
    "${lookup(mailgun_domain.this.sending_records[count.index], "value")}",
  ]
}

resource "aws_route53_record" "receiving" {
  zone_id = "${data.aws_route53_zone.this.zone_id}"
  name    = "${var.mail_domain}"
  type    = "${lookup(mailgun_domain.this.receiving_records[0], "record_type")}"
  ttl     = 300

  records = [
    "${lookup(mailgun_domain.this.receiving_records[0], "priority")} ${lookup(mailgun_domain.this.receiving_records[0], "value")}",
    "${lookup(mailgun_domain.this.receiving_records[1], "priority")} ${lookup(mailgun_domain.this.receiving_records[1], "value")}",
  ]
}

# ── variables.tf ──────────────────────────────────────────
variable "mail_domain" {
  description = "Domain which you want to use for sending/receiving email (e.g. `\"example.com\"`)"
}

variable "smtp_password" {
  description = "Password that Mailgun will require for sending out SMPT mail via this domain"
}

variable "spam_action" {
  description = "See https://www.terraform.io/docs/providers/mailgun/r/domain.html#spam_action"
  default     = "disabled"
}

variable "wildcard" {
  description = "See https://www.terraform.io/docs/providers/mailgun/r/domain.html#wildcard"
  default     = false
}

variable "tags" {
  description = "AWS Tags to add to all resources created (where possible); see https://aws.amazon.com/answers/account-management/aws-tagging-strategies/"
  type        = "map"
  default     = {}
}

# ── outputs.tf ──────────────────────────────────────────
output "mail_domain" {
  value       = "${var.mail_domain}"
  description = "Domain which you want to use for sending/receiving email (e.g. `\"example.com\"`)"
}

output "api_base_url" {
  value       = "https://api.mailgun.net/v3/${var.mail_domain}/"
  description = "Base URL of the Mailgun API for your domain"
}

# ── data.tf ──────────────────────────────────────────
data "aws_route53_zone" "this" {
  name = "${replace("${var.mail_domain}", "/.*\\b(\\w+\\.\\w+)\\.?$/", "$1")}" # e.g. "foo.example.com" => "example.com"
}

# ── variables.tf ──────────────────────────────────────────
variable "site_domain" {
  description = "Domain on which the reverse proxy will be made available (e.g. `\"www.example.com\"`)"
}

variable "name_prefix" {
  description = "Name prefix to use for objects that need to be created (only lowercase alphanumeric characters and hyphens allowed, for S3 bucket name compatibility)"
  default     = "aws-reverse-proxy---"
}

variable "comment_prefix" {
  description = "This will be included in comments for resources that are created"
  default     = "Reverse proxy: "
}

variable "origin_url" {
  description = "Base URL for proxy upstream site (e.g. `\"https://example.com/\"`)"
}

variable "cloudfront_price_class" {
  description = "CloudFront price class to use (`100`, `200` or `\"All\"`, see https://aws.amazon.com/cloudfront/pricing/)"
  default     = 100
}

variable "viewer_https_only" {
  description = "Set this to `false` if you need to support insecure HTTP access for clients, in addition to HTTPS"
  default     = true
}

variable "cache_ttl_override" {
  description = "When >= 0, override the cache behaviour for ALL objects in the origin, so that they stay in the CloudFront cache for this amount of seconds"
  default     = -1
}

variable "default_root_object" {
  description = "The object to return when the root URL is requested"
  default     = ""
}

variable "add_response_headers" {
  description = "Map of HTTP headers (if any) to add to outgoing responses before sending them to clients"
  type        = "map"

  default = {
    "Strict-Transport-Security" = "max-age=31557600; preload" # i.e. 1 year (in seconds)
  }
}

variable "origin_custom_header_name" {
  description = "Name of a custom header to send to the origin; this can be used to convey an authentication header to the origin, for example"

  # Unfortunately, since Terraform doesn't allow conditional inline blocks (yet), we need to ALWAYS have SOME header here.
  # This default one will be sent if a custom one isn't defined, but it's assumed to be harmless.
  default = "X-Custom-Origin-Header"
}

variable "origin_custom_header_value" {
  description = "Value of a custom header to send to the origin; see `origin_custom_header_name`"
  default     = ""
}

variable "origin_custom_port" {
  description = "When > 0, use this port for communication with the origin server, instead of relevant standard port"
  default     = 0
}

variable "override_response_status" {
  description = "When this and the other `override_response_*` variables are non-empty, skip sending the request to the origin altogether, and instead respond as instructed here"
  default     = ""
}

variable "override_response_status_description" {
  description = "Same as `override_response_status`"
  default     = ""
}

variable "override_response_body" {
  description = "Same as `override_response_status`"
  default     = ""
}

variable "basic_auth_username" {
  description = "When non-empty, require this username with HTTP Basic Auth"
  default     = ""
}

variable "basic_auth_password" {
  description = "When non-empty, require this password with HTTP Basic Auth"
  default     = ""
}

variable "basic_auth_realm" {
  description = "When using HTTP Basic Auth, this will be displayed by the browser in the auth prompt"
  default     = "Authentication Required"
}

variable "basic_auth_body" {
  description = "When using HTTP Basic Auth, and authentication has failed, this will be displayed by the browser as the page content"
  default     = "Unauthorized"
}

variable "lambda_logging_enabled" {
  description = "When true, writes information about incoming requests to the Lambda function's CloudWatch group"
  default     = false
}

variable "tags" {
  description = "AWS Tags to add to all resources created (where possible); see https://aws.amazon.com/answers/account-management/aws-tagging-strategies/"
  type        = "map"
  default     = {}
}

locals {
  prefix_with_domain = "${var.name_prefix}${replace("${var.site_domain}", "/[^a-z0-9-]+/", "-")}" # only lowercase alphanumeric characters and hyphens are allowed in S3 bucket names
  error_ttl          = "${var.cache_ttl_override >= 0 ? var.cache_ttl_override : 0}"
}

# Because CloudFront origins expect the URL to be provided as components, we need to do a bit of URL "parsing"
locals {
  url_protocol = "${replace("${var.origin_url}", "/^(?:(\\w+):\\/\\/).*/", "$1")}"
  url_hostname = "${replace("${var.origin_url}", "/^(?:\\w+:\\/\\/)?([^/]+).*/", "$1")}"
  url_path     = "${replace("${var.origin_url}", "/^(?:\\w+:\\/\\/)?[^/]+(?:\\/(.*)|$)/", "$1")}"
}

# ── outputs.tf ──────────────────────────────────────────
output "cloudfront_id" {
  description = "The ID of the CloudFront distribution that's used for hosting the content"
  value       = "${aws_cloudfront_distribution.this.id}"
}

output "site_domain" {
  description = "Domain on which the site will be made available"
  value       = "${var.site_domain}"
}

# ── certificate.tf ──────────────────────────────────────────
# Generate a certificate for the domain automatically using ACM
# https://www.terraform.io/docs/providers/aws/r/acm_certificate.html
resource "aws_acm_certificate" "this" {
  provider          = "aws.us_east_1"                                                              # because ACM is only available in the "us-east-1" region
  domain_name       = "${var.site_domain}"
  validation_method = "DNS"                                                                        # the required records are created below
  tags              = "${merge(var.tags, map("Name", "${var.comment_prefix}${var.site_domain}"))}"
}

# Add the DNS records needed by the ACM validation process
resource "aws_route53_record" "cert_validation" {
  name    = "${aws_acm_certificate.this.domain_validation_options.0.resource_record_name}"
  type    = "${aws_acm_certificate.this.domain_validation_options.0.resource_record_type}"
  zone_id = "${data.aws_route53_zone.this.zone_id}"
  records = ["${aws_acm_certificate.this.domain_validation_options.0.resource_record_value}"]
  ttl     = 60
}

# Request a validation for the cert with ACM
resource "aws_acm_certificate_validation" "this" {
  provider                = "aws.us_east_1"                                # because ACM is only available in the "us-east-1" region
  certificate_arn         = "${aws_acm_certificate.this.arn}"
  validation_record_fqdns = ["${aws_route53_record.cert_validation.fqdn}"]
}

# ── cloudfront.tf ──────────────────────────────────────────
# Create the CloudFront distribution through which the site contents will be served
# https://www.terraform.io/docs/providers/aws/r/cloudfront_distribution.html
resource "aws_cloudfront_distribution" "this" {
  enabled             = true
  is_ipv6_enabled     = true
  default_root_object = "${var.default_root_object}"
  aliases             = ["${var.site_domain}"]
  price_class         = "PriceClass_${var.cloudfront_price_class}"
  comment             = "${var.comment_prefix}${var.site_domain}"
  tags                = "${var.tags}"

  # Define the "upstream" for the CloudFront distribution
  origin {
    domain_name = "${local.url_hostname}"
    origin_id   = "default"
    origin_path = "${local.url_path == "" ? "" : "/${local.url_path}"}"

    custom_origin_config {
      http_port              = "${var.origin_custom_port > 0 ? "${var.origin_custom_port}" : 80}"
      https_port             = "${var.origin_custom_port > 0 ? "${var.origin_custom_port}" : 443}"
      origin_protocol_policy = "${local.url_protocol}-only"
      origin_ssl_protocols   = ["TLSv1", "TLSv1.1", "TLSv1.2"]
    }

    custom_header {
      name  = "${var.origin_custom_header_name}"
      value = "${var.origin_custom_header_value}"
    }
  }

  # Define how to serve the content to clients
  default_cache_behavior {
    allowed_methods        = ["DELETE", "GET", "HEAD", "OPTIONS", "PATCH", "POST", "PUT"]
    cached_methods         = ["GET", "HEAD"]
    target_origin_id       = "default"
    viewer_protocol_policy = "${var.viewer_https_only ? "redirect-to-https" : "allow-all"}"
    compress               = true

    min_ttl     = "${var.cache_ttl_override >= 0 ? var.cache_ttl_override : 0}"     # for reference: AWS default is 0
    default_ttl = "${var.cache_ttl_override >= 0 ? var.cache_ttl_override : 0}"     # for reference: AWS default is 86400 (i.e. one day)
    max_ttl     = "${var.cache_ttl_override >= 0 ? var.cache_ttl_override : 86400}" # i.e. 1 day; for reference: AWS default is 31536000 (i.e. one year)

    forwarded_values {
      query_string = true

      cookies {
        forward = "all"
      }
    }

    # Note: This will make the Lambda undeletable, as long as this distribution/association exists
    # https://docs.aws.amazon.com/AmazonCloudFront/latest/DeveloperGuide/lambda-edge-delete-replicas.html
    lambda_function_association {
      event_type = "viewer-request"                                                                          # one of [ viewer-request, origin-request, viewer-response, origin-response ]
      lambda_arn = "${aws_lambda_function.viewer_request.arn}:${aws_lambda_function.viewer_request.version}"
    }

    # Note: This will make the Lambda undeletable, as long as this distribution/association exists
    # https://docs.aws.amazon.com/AmazonCloudFront/latest/DeveloperGuide/lambda-edge-delete-replicas.html
    lambda_function_association {
      event_type = "viewer-response"                                                                           # one of [ viewer-request, origin-request, viewer-response, origin-response ]
      lambda_arn = "${aws_lambda_function.viewer_response.arn}:${aws_lambda_function.viewer_response.version}"
    }
  }

  # This (and other custom_error_response's below) are important, because otherwise CloudFront defaults to caching errors for 5 minutes.
  # This means that if you accidentally deploy broken code, your users will be stuck seeing the error regardless of how quickly you roll back.
  # Unless a "cache_ttl_override" is provided, we never cache errors.
  # https://docs.aws.amazon.com/AmazonCloudFront/latest/DeveloperGuide/custom-error-pages-expiration.html
  custom_error_response {
    error_code            = 400                  # == "Bad Request"
    error_caching_min_ttl = "${local.error_ttl}"
  }

  custom_error_response {
    error_code            = 403                  # == "Forbidden"
    error_caching_min_ttl = "${local.error_ttl}"
  }

  custom_error_response {
    error_code            = 404                  # == "Not Found"
    error_caching_min_ttl = "${local.error_ttl}"
  }

  custom_error_response {
    error_code            = 405                  # == "Method Not Allowed"
    error_caching_min_ttl = "${local.error_ttl}"
  }

  custom_error_response {
    error_code            = 414                  # == "Request-URI Too Long"
    error_caching_min_ttl = "${local.error_ttl}"
  }

  custom_error_response {
    error_code            = 416                  # == "Requested Range Not Satisfiable"
    error_caching_min_ttl = "${local.error_ttl}"
  }

  custom_error_response {
    error_code            = 500                  # == "Internal Server Error"
    error_caching_min_ttl = "${local.error_ttl}"
  }

  custom_error_response {
    error_code            = 501                  # == "Not Implemented"
    error_caching_min_ttl = "${local.error_ttl}"
  }

  custom_error_response {
    error_code            = 502                  # == "Bad Gateway"
    error_caching_min_ttl = "${local.error_ttl}"
  }

  custom_error_response {
    error_code            = 503                  # == "Service Unavailable"
    error_caching_min_ttl = "${local.error_ttl}"
  }

  custom_error_response {
    error_code            = 504                  # == "Gateway Timeout"
    error_caching_min_ttl = "${local.error_ttl}"
  }

  # This is mandatory in Terraform :shrug:
  restrictions {
    geo_restriction {
      restriction_type = "none"
    }
  }

  # Attach our auto-generated ACM certificate to the distribution
  # https://www.terraform.io/docs/providers/aws/r/cloudfront_distribution.html#viewer-certificate-arguments
  viewer_certificate {
    acm_certificate_arn      = "${aws_acm_certificate_validation.this.certificate_arn}"
    ssl_support_method       = "sni-only"
    minimum_protocol_version = "TLSv1.1_2016"
  }
}

# ── data.tf ──────────────────────────────────────────
data "aws_route53_zone" "this" {
  name = "${replace("${var.site_domain}", "/.*\\b(\\w+\\.\\w+)\\.?$/", "$1")}" # e.g. "foo.example.com" => "example.com"
}

# ── lambda.tf ──────────────────────────────────────────
locals {
  config = {
    basic_auth_username                  = "${var.basic_auth_username}"
    basic_auth_password                  = "${var.basic_auth_password}"
    basic_auth_realm                     = "${var.basic_auth_realm}"
    basic_auth_body                      = "${var.basic_auth_body}"
    override_response_status             = "${var.override_response_status}"
    override_response_status_description = "${var.override_response_status_description}"
    override_response_body               = "${var.override_response_body}"
  }
}

# Lambda@Edge functions don't support environment variables, so let's inline the relevant parts of the config to the JS file.
# (see: "error creating CloudFront Distribution: InvalidLambdaFunctionAssociation: The function cannot have environment variables")
data "template_file" "lambda" {
  template = "${file("${path.module}/lambda.tpl.js")}"

  vars = {
    config               = "${jsonencode(local.config)}"             # single quotes need to be escaped, lest we end up with a parse error on the JS side
    add_response_headers = "${jsonencode(var.add_response_headers)}" # ^ ditto
  }
}

# Lambda functions can only be uploaded as ZIP files, so we need to package our JS file into one
data "archive_file" "lambda_zip" {
  type        = "zip"
  output_path = "${path.module}/lambda.zip"

  source {
    filename = "lambda.js"
    content  = "${data.template_file.lambda.rendered}"
  }
}

resource "aws_lambda_function" "viewer_request" {
  provider = "aws.us_east_1" # because: error creating CloudFront Distribution: InvalidLambdaFunctionAssociation: The function must be in region 'us-east-1'

  # lambda_zip.output_path will be absolute, i.e. different on different machines.
  # This can cause Terraform to notice differences that aren't actually there, so let's convert it to a relative one.
  # https://github.com/hashicorp/terraform/issues/7613#issuecomment-332238441
  filename = "${substr(data.archive_file.lambda_zip.output_path, length(path.cwd) + 1, -1)}"

  source_code_hash = "${data.archive_file.lambda_zip.output_base64sha256}"
  function_name    = "${local.prefix_with_domain}---viewer_request"
  role             = "${aws_iam_role.this.arn}"
  description      = "${var.comment_prefix}${var.site_domain} (request handler)"
  handler          = "lambda.viewer_request"
  runtime          = "nodejs8.10"
  publish          = true                                                        # because: error creating CloudFront Distribution: InvalidLambdaFunctionAssociation: The function ARN must reference a specific function version. (The ARN must end with the version number.)
  tags             = "${var.tags}"
}

resource "aws_lambda_function" "viewer_response" {
  provider = "aws.us_east_1" # because: error creating CloudFront Distribution: InvalidLambdaFunctionAssociation: The function must be in region 'us-east-1'

  # lambda_zip.output_path will be absolute, i.e. different on different machines.
  # This can cause Terraform to notice differences that aren't actually there, so let's convert it to a relative one.
  # https://github.com/hashicorp/terraform/issues/7613#issuecomment-332238441
  filename = "${substr(data.archive_file.lambda_zip.output_path, length(path.cwd) + 1, -1)}"

  source_code_hash = "${data.archive_file.lambda_zip.output_base64sha256}"
  function_name    = "${local.prefix_with_domain}---viewer_response"
  role             = "${aws_iam_role.this.arn}"
  description      = "${var.comment_prefix}${var.site_domain} (response handler)"
  handler          = "lambda.viewer_response"
  runtime          = "nodejs8.10"
  publish          = true                                                         # because: error creating CloudFront Distribution: InvalidLambdaFunctionAssociation: The function ARN must reference a specific function version. (The ARN must end with the version number.)
  tags             = "${var.tags}"
}

# Allow Lambda@Edge to invoke our functions
resource "aws_iam_role" "this" {
  name = "${local.prefix_with_domain}"
  tags = "${var.tags}"

  assume_role_policy = <<EOF
{
  "Version": "2012-10-17",
  "Statement": [
    {
      "Effect": "Allow",
      "Principal": {
        "Service": [
          "lambda.amazonaws.com",
          "edgelambda.amazonaws.com"
        ]
      },
      "Action": "sts:AssumeRole"
    }
  ]
}
EOF
}

# Allow writing logs to CloudWatch from our functions
resource "aws_iam_policy" "this" {
  count = "${var.lambda_logging_enabled ? 1 : 0}"
  name  = "${local.prefix_with_domain}"

  policy = <<EOF
{
  "Version": "2012-10-17",
  "Statement": [
    {
      "Action": [
        "logs:CreateLogGroup",
        "logs:CreateLogStream",
        "logs:PutLogEvents"
      ],
      "Resource": "arn:aws:logs:*:*:*",
      "Effect": "Allow"
    }
  ]
}
EOF
}

resource "aws_iam_role_policy_attachment" "this" {
  count      = "${var.lambda_logging_enabled ? 1 : 0}"
  role       = "${aws_iam_role.this.name}"
  policy_arn = "${aws_iam_policy.this.arn}"
}

# ── route53.tf ──────────────────────────────────────────
# Add an IPv4 DNS record pointing to the CloudFront distribution
resource "aws_route53_record" "ipv4" {
  zone_id = "${data.aws_route53_zone.this.zone_id}"
  name    = "${var.site_domain}"
  type    = "A"

  alias {
    name                   = "${aws_cloudfront_distribution.this.domain_name}"
    zone_id                = "${aws_cloudfront_distribution.this.hosted_zone_id}"
    evaluate_target_health = false
  }
}

# Add an IPv6 DNS record pointing to the CloudFront distribution
resource "aws_route53_record" "ipv6" {
  zone_id = "${data.aws_route53_zone.this.zone_id}"
  name    = "${var.site_domain}"
  type    = "AAAA"

  alias {
    name                   = "${aws_cloudfront_distribution.this.domain_name}"
    zone_id                = "${aws_cloudfront_distribution.this.hosted_zone_id}"
    evaluate_target_health = false
  }
}

# ── main.tf ──────────────────────────────────────────
module "aws_reverse_proxy" {
  # Available inputs: https://github.com/futurice/terraform-utils/tree/master/aws_reverse_proxy#inputs
  # Check for updates: https://github.com/futurice/terraform-utils/compare/v11.0...master
  source = "git::ssh://git@github.com/futurice/terraform-utils.git//aws_reverse_proxy?ref=v11.0"

  # S3 website endpoints are only available over plain HTTP
  origin_url = "http://${local.bucket_domain_name}/"

  # Our S3 bucket will only allow requests containing this custom header
  origin_custom_header_name = "User-Agent"

  # Somewhat perplexingly, this is the "correct" way to ensure users can't bypass CloudFront on their way to S3 resources
  # https://abridge2devnull.com/posts/2018/01/restricting-access-to-a-cloudfront-s3-website-origin/
  origin_custom_header_value = "${random_string.s3_read_password.result}"

  site_domain            = "${var.site_domain}"
  name_prefix            = "${var.name_prefix}"
  comment_prefix         = "${var.comment_prefix}"
  cloudfront_price_class = "${var.cloudfront_price_class}"
  viewer_https_only      = "${var.viewer_https_only}"
  cache_ttl_override     = "${var.cache_ttl_override}"
  default_root_object    = "${var.default_root_object}"
  add_response_headers   = "${var.add_response_headers}"
  basic_auth_username    = "${var.basic_auth_username}"
  basic_auth_password    = "${var.basic_auth_password}"
  basic_auth_realm       = "${var.basic_auth_realm}"
  basic_auth_body        = "${var.basic_auth_body}"
  lambda_logging_enabled = "${var.lambda_logging_enabled}"
  tags                   = "${var.tags}"
}

# ── variables.tf ──────────────────────────────────────────
variable "site_domain" {
  description = "Domain on which the static site will be made available (e.g. `\"www.example.com\"`)"
}

variable "name_prefix" {
  description = "Name prefix to use for objects that need to be created (only lowercase alphanumeric characters and hyphens allowed, for S3 bucket name compatibility)"
  default     = "aws-static-site---"
}

variable "comment_prefix" {
  description = "This will be included in comments for resources that are created"
  default     = "Static site: "
}

variable "bucket_override_name" {
  description = "When provided, assume a bucket with this name already exists for the site content, instead of creating the bucket automatically (e.g. `\"my-bucket\"`)"
  default     = ""
}

variable "cloudfront_price_class" {
  description = "CloudFront price class to use (`100`, `200` or `\"All\"`, see https://aws.amazon.com/cloudfront/pricing/)"
  default     = 100
}

variable "viewer_https_only" {
  description = "Set this to `false` if you need to support insecure HTTP access for clients, in addition to HTTPS"
  default     = true
}

variable "cache_ttl_override" {
  description = "When >= 0, override the cache behaviour for ALL objects in S3, so that they stay in the CloudFront cache for this amount of seconds"
  default     = -1
}

variable "default_root_object" {
  description = "The object to return when the root URL is requested"
  default     = "index.html"
}

variable "add_response_headers" {
  description = "Map of HTTP headers (if any) to add to outgoing responses before sending them to clients"
  type        = "map"

  default = {
    "Strict-Transport-Security" = "max-age=31557600; preload" # i.e. 1 year (in seconds)
  }
}

variable "basic_auth_username" {
  description = "When non-empty, require this username with HTTP Basic Auth"
  default     = ""
}

variable "basic_auth_password" {
  description = "When non-empty, require this password with HTTP Basic Auth"
  default     = ""
}

variable "basic_auth_realm" {
  description = "When using HTTP Basic Auth, this will be displayed by the browser in the auth prompt"
  default     = "Authentication Required"
}

variable "basic_auth_body" {
  description = "When using HTTP Basic Auth, and authentication has failed, this will be displayed by the browser as the page content"
  default     = "Unauthorized"
}

variable "lambda_logging_enabled" {
  description = "When true, writes information about incoming requests to the Lambda function's CloudWatch group"
  default     = false
}

variable "tags" {
  description = "AWS Tags to add to all resources created (where possible); see https://aws.amazon.com/answers/account-management/aws-tagging-strategies/"
  type        = "map"
  default     = {}
}

locals {
  prefix_with_domain = "${var.name_prefix}${replace("${var.site_domain}", "/[^a-z0-9-]+/", "-")}"                          # only lowercase alphanumeric characters and hyphens are allowed in S3 bucket names
  bucket_name        = "${var.bucket_override_name == "" ? "${local.prefix_with_domain}" : "${var.bucket_override_name}"}" # select between externally-provided or auto-generated bucket names
  bucket_domain_name = "${local.bucket_name}.s3-website.${data.aws_region.current.name}.amazonaws.com"                     # use current region to complete the domain name (we can't use the "aws_s3_bucket" data source because the bucket may not initially exist)
  error_ttl          = "${var.cache_ttl_override >= 0 ? var.cache_ttl_override : 0}"
}

# ── outputs.tf ──────────────────────────────────────────
output "bucket_name" {
  description = "The name of the S3 bucket that's used for hosting the content (either auto-generated or externally provided)"

  # Terraform isn't particularly helpful when you want to depend on the existence of a resource which may have count 0 or 1, like our bucket.
  # This is a hacky way of only resolving the bucket_name output once the bucket exists (if created by us).
  # https://github.com/hashicorp/terraform/issues/16580#issuecomment-342573652
  value = "${local.bucket_name}${replace("${element(concat(aws_s3_bucket.this.*.bucket, list("")), 0)}", "/.*/", "")}"
}

output "cloudfront_id" {
  description = "The ID of the CloudFront distribution that's used for hosting the content"
  value       = "${module.aws_reverse_proxy.cloudfront_id}"
}

output "site_domain" {
  description = "Domain on which the static site will be made available"
  value       = "${var.site_domain}"
}

output "bucket_domain_name" {
  description = "Full S3 domain name for the bucket used for hosting the content (e.g. `\"aws-static-site---hello-example-com.s3-website.eu-central-1.amazonaws.com\"`)"
  value       = "${local.bucket_domain_name}"
}

# ── data.tf ──────────────────────────────────────────
data "aws_route53_zone" "this" {
  name = "${replace("${var.site_domain}", "/.*\\b(\\w+\\.\\w+)\\.?$/", "$1")}" # e.g. "foo.example.com" => "example.com"
}

resource "random_string" "s3_read_password" {
  length  = 32
  special = false
}

# ── s3.tf ──────────────────────────────────────────
# Query the current AWS region so we know its S3 endpoint
data "aws_region" "current" {}

# Create the S3 bucket in which the static content for the site should be hosted
resource "aws_s3_bucket" "this" {
  count  = "${var.bucket_override_name == "" ? 1 : 0}"
  bucket = "${local.bucket_name}"
  tags   = "${var.tags}"

  # Add a CORS configuration, so that we don't have issues with webfont loading
  # http://www.holovaty.com/writing/cors-ie-cloudfront/
  cors_rule {
    allowed_headers = ["*"]
    allowed_methods = ["GET"]
    allowed_origins = ["*"]
    max_age_seconds = 3000
  }

  # Enable website hosting
  # Note, though, that when accessing the bucket over its SSL endpoint, the index_document will not be used
  website {
    index_document = "index.html"
    error_document = "error.html"
  }
}

# Use a bucket policy (instead of the simpler acl = "public-read") so we don't need to always remember to upload objects with:
# $ aws s3 cp --acl public-read ...
# https://docs.aws.amazon.com/AmazonS3/latest/dev/acl-overview.html#canned-acl
resource "aws_s3_bucket_policy" "this" {
  depends_on = ["aws_s3_bucket.this"]                      # because we refer to the bucket indirectly, we need to explicitly define the dependency
  count      = "${var.bucket_override_name == "" ? 1 : 0}"
  bucket     = "${local.bucket_name}"

  # https://docs.aws.amazon.com/AmazonS3/latest/dev/example-bucket-policies.html#example-bucket-policies-use-case-2
  policy = <<POLICY
{
  "Version": "2012-10-17",
  "Statement": [
    {
      "Effect": "Allow",
      "Principal": "*",
      "Action": "s3:GetObject",
      "Resource": "arn:aws:s3:::${local.bucket_name}/*",
      "Condition": {
        "StringEquals": {
          "aws:UserAgent": "${random_string.s3_read_password.result}"
        }
      }
    }
  ]
}
POLICY
}

# ── main.tf ──────────────────────────────────────────
## ACM Certificate
data "aws_route53_zone" "this" {
  name = replace(var.site_domain, "/.*\\b(\\w+\\.\\w+)\\.?$/", "$1") # gets domain from subdomain e.g. "foo.example.com" => "example.com"
}

module "acm" {
  source      = "terraform-aws-modules/acm/aws"
  version     = "~> v2.0"
  domain_name = var.site_domain
  zone_id     = data.aws_route53_zone.this.zone_id
  tags        = var.tags

  providers = {
    aws = "aws.us_east_1" # cloudfront needs acm certificate to be from "us-east-1" region
  }
}

## S3
resource "aws_s3_bucket" "this" {
  bucket = var.bucket_name
  tags   = var.tags
}

resource "aws_s3_bucket_public_access_block" "website_bucket" {
  bucket = aws_s3_bucket.this.id

  block_public_acls   = true
  block_public_policy = true
}

data "aws_iam_policy_document" "s3_policy_document" {
  statement {
    actions   = ["s3:GetObject"]
    resources = ["${aws_s3_bucket.this.arn}/*"]

    principals {
      type        = "AWS"
      identifiers = [aws_cloudfront_origin_access_identity.this.iam_arn]
    }
  }

  statement {
    actions   = ["s3:ListBucket"]
    resources = [aws_s3_bucket.this.arn]

    principals {
      type        = "AWS"
      identifiers = [aws_cloudfront_origin_access_identity.this.iam_arn]
    }
  }
}

resource "aws_s3_bucket_policy" "s3_policy" {
  bucket = aws_s3_bucket.this.id
  policy = data.aws_iam_policy_document.s3_policy_document.json
}

## Cloudfront

resource "aws_cloudfront_origin_access_identity" "this" {
  comment = "Origin Access Identity used to access S3 for ${var.site_domain}"
}

resource "aws_cloudfront_distribution" "this" {
  origin {
    domain_name = aws_s3_bucket.this.bucket_regional_domain_name
    origin_id   = local.s3_origin_id

    s3_origin_config {
      origin_access_identity = aws_cloudfront_origin_access_identity.this.cloudfront_access_identity_path
    }
  }

  enabled             = true
  is_ipv6_enabled     = true
  comment             = var.site_domain
  default_root_object = var.default_root_object

  aliases = [var.site_domain]

  default_cache_behavior {
    allowed_methods  = ["DELETE", "GET", "HEAD", "OPTIONS", "PATCH", "POST", "PUT"]
    cached_methods   = ["GET", "HEAD"]
    target_origin_id = local.s3_origin_id

    forwarded_values {
      query_string = false

      cookies {
        forward = "none"
      }
    }

    viewer_protocol_policy = "redirect-to-https"
    min_ttl                = var.min_ttl
    default_ttl            = var.default_ttl
    max_ttl                = var.max_ttl
  }
  price_class = var.cf_price_class

  tags = var.tags

  restrictions {
    geo_restriction {
      restriction_type = "none"
    }
  }

  viewer_certificate {
    acm_certificate_arn      = module.acm.this_acm_certificate_arn
    ssl_support_method       = "sni-only"
    minimum_protocol_version = "TLSv1.1_2016"
  }

  # By default, cloudfront caches error for five minutes. There can be situation when a developer has accidentally broken the website and you would not want to wait for five minutes for the error response to be cached.
  # https://docs.aws.amazon.com/AmazonS3/latest/dev/CustomErrorDocSupport.html
  custom_error_response {
    error_code            = 400
    error_caching_min_ttl = var.error_ttl
  }

  custom_error_response {
    error_code            = 403
    error_caching_min_ttl = var.error_ttl
  }

  custom_error_response {
    error_code            = 404
    error_caching_min_ttl = var.error_ttl
  }

  custom_error_response {
    error_code            = 405
    error_caching_min_ttl = var.error_ttl
  }

}

## Route53
# Add an IPv4 DNS record pointing to the CloudFront distribution
resource "aws_route53_record" "ipv4" {
  zone_id = data.aws_route53_zone.this.zone_id
  name    = var.site_domain
  type    = "A"

  alias {
    name                   = aws_cloudfront_distribution.this.domain_name
    zone_id                = aws_cloudfront_distribution.this.hosted_zone_id
    evaluate_target_health = false
  }
}

# Add an IPv6 DNS record pointing to the CloudFront distribution
resource "aws_route53_record" "ipv6" {
  zone_id = data.aws_route53_zone.this.zone_id
  name    = var.site_domain
  type    = "AAAA"

  alias {
    name                   = aws_cloudfront_distribution.this.domain_name
    zone_id                = aws_cloudfront_distribution.this.hosted_zone_id
    evaluate_target_health = false
  }
}

# ── variables.tf ──────────────────────────────────────────
variable "region" {
  description = "THe primary AWS region where all the resources will be created. See https://docs.aws.amazon.com/general/latest/gr/rande.html"
}

variable "tags" {
  description = "AWS Tags to add to all resources created (where possible); see https://aws.amazon.com/answers/account-management/aws-tagging-strategies/"
  type        = "map"
  default     = {}
}

variable "site_domain" {
  description = "The primary domain name of the website"
}

variable "bucket_name" {
  description = "The name of the S3 bucket wich would host the static files"
}

variable "cf_price_class" {
  description = "TThe price class for this distribution. One of PriceClass_All, PriceClass_200, PriceClass_100"
  default     = "PriceClass_100"
}

variable "default_root_object" {
  description = "The object to return when the root URL is requested"
  default     = "index.html"
}

variable "default_ttl" {
  description = "The default amount of time (in secs) that an object is cached in cloudfront in the absence of Cache-Control max-age or Expires header."
  default     = "86400"
}

variable "max_ttl" {
  description = "The maximum amount of time (in secs) that an object is cached in cloudfront before cloudfront forwards another request ot origin to determine if the object has been updated."
  default     = "31536000" # 365 days
}

variable "min_ttl" {
  description = "The minimum amount of time (in secs) that an object is cached in cloudfront before cloudfront forwards another request ot origin to determine if the object has been updated."
  default     = "0"
}

variable "error_ttl" {
  description = "The minimum amount of time (in secs) that cloudfront caches an HTTP error code."
  default     = "30"
}

locals {
  s3_origin_id = "myS3Origin"
}

# ── init.tf ──────────────────────────────────────────
provider "aws" {
  region  = var.region
  version = "~> 2.0"
}

terraform {
  required_version = "~> 0.12"
}

provider "aws" {
  alias   = "us_east_1" #cloudfront needs acm certificate to be from "us-east-1" region
  region  = "us-east-1"
  version = "~> 2.0"
}

# ── variables.tf ──────────────────────────────────────────
variable "resource_group_name" {
  type        = string
  description = "Name of the resource group where resources are to be deployed"
}

variable "alert_email_address" {
  type        = string
  description = "Email address where alert emails are sent"
}

variable "name_prefix" {
  type        = string
  description = "Name prefix to use for resources that need to be created (only lowercase characters and hyphens allowed)"
  default     = "azure-app-example--"
}

variable "app_service_name" {
  type        = string
  description = "Name for the app service"
  default     = "appservice"
}

# https://www.terraform.io/docs/providers/azurerm/r/application_insights.html#application_type
variable "app_insights_app_type" {
  type        = string
  description = "The type of Application Insights to create."
  default     = "other"
}

# https://azure.microsoft.com/en-gb/pricing/details/app-service/linux/
variable "app_service_plan_tier" {
  type        = string
  description = "App service plan's tier"
  default     = "PremiumV2"
}

variable "app_service_plan_size" {
  type        = string
  description = "App service plan's size"
  default     = "P1v2"
}

locals {
  cleansed_prefix = replace(var.name_prefix, "/[^a-zA-Z0-9]+/", "")
}

# ── outputs.tf ──────────────────────────────────────────
output "app_service_name" {
  description = "This is the unique name of the App Service that was created"
  value       = azurerm_app_service.current.name
}

output "app_service_url" {
  description = "This is the URL of the App Service that was created"
  value       = azurerm_app_service.current.default_site_hostname
}

output "container_registry" {
  value = azurerm_container_registry.current.login_server
}

# ── access_policies.tf ──────────────────────────────────────────
# Key vault access for the current client principal
resource "azurerm_key_vault_access_policy" "principal" {
  key_vault_id = azurerm_key_vault.current.id

  tenant_id = data.azurerm_client_config.current.tenant_id
  object_id = data.azurerm_client_config.current.object_id

  secret_permissions = [
    "get",
    "set",
    "delete"
  ]
}

# Key vault access for the App Service
resource "azurerm_key_vault_access_policy" "app_service" {
  key_vault_id = azurerm_key_vault.current.id

  tenant_id = data.azurerm_client_config.current.tenant_id
  object_id = azurerm_app_service.current.identity.0.principal_id

  secret_permissions = [
    "get",
  ]
}

# Key vault access for the App Service's next slot
resource "azurerm_key_vault_access_policy" "app_service_next_slot" {
  key_vault_id = azurerm_key_vault.current.id

  tenant_id = data.azurerm_client_config.current.tenant_id
  object_id = azurerm_app_service_slot.next.identity.0.principal_id

  secret_permissions = [
    "get",
  ]
}

# Pull access for the app service
resource "azurerm_role_assignment" "app_service_acr_pull" {
  scope                = azurerm_container_registry.current.id
  role_definition_name = "AcrPull"
  principal_id         = azurerm_app_service.current.identity.0.principal_id
}

# Pull access for the app service's next slot
resource "azurerm_role_assignment" "app_service_next_slot_acr_pull" {
  scope                = azurerm_container_registry.current.id
  role_definition_name = "AcrPull"
  principal_id         = azurerm_app_service_slot.next.identity.0.principal_id
}

# ── app_service.tf ──────────────────────────────────────────
locals {
  # Service plan needs to be unique only within the resource group
  app_service_plan_name = "${var.name_prefix}app-service-plan"
  # Needs to be globally unique
  app_service_name = "${var.name_prefix}${var.app_service_name}"

  # https://github.com/projectkudu/kudu/wiki/Configurable-settings
  app_service_settings = {
    # Enable if you need a persistant file storage (/home/ directory)
    WEBSITES_ENABLE_APP_SERVICE_STORAGE = false

    # Prevent recycling of the app when storage infra changes
    # https://github.com/projectkudu/kudu/wiki/Configurable-settings#disable-the-generation-of-bindings-in-applicationhostconfig
    WEBSITE_ADD_SITENAME_BINDINGS_IN_APPHOST_CONFIG = 1

    APPINSIGHTS_INSTRUMENTATIONKEY = "@Microsoft.KeyVault(SecretUri=${azurerm_key_vault.current.vault_uri}secrets/app-insights-key)"
  }

  app_service_site_config = {
    always_on                 = true
    min_tls_version           = "1.2"
    health_check_path         = "/api/healthcheck"
    use_32_bit_worker_process = false
  }
}

resource "azurerm_app_service_plan" "current" {
  name                = local.app_service_plan_name
  location            = data.azurerm_resource_group.current.location
  resource_group_name = data.azurerm_resource_group.current.name
  kind                = "linux"
  reserved            = true

  sku {
    tier = var.app_service_plan_tier
    size = var.app_service_plan_size
  }
}

# App service
resource "azurerm_app_service" "current" {
  name                = local.app_service_name
  location            = data.azurerm_resource_group.current.location
  resource_group_name = data.azurerm_resource_group.current.name
  app_service_plan_id = azurerm_app_service_plan.current.id

  https_only = true

  site_config {
    always_on                 = local.app_service_site_config.always_on
    min_tls_version           = local.app_service_site_config.min_tls_version
    health_check_path         = local.app_service_site_config.health_check_path
    use_32_bit_worker_process = local.app_service_site_config.use_32_bit_worker_process
  }

  app_settings = local.app_service_settings

  identity {
    type = "SystemAssigned"
  }

  lifecycle {
    ignore_changes = [
      app_settings["DOCKER_CUSTOM_IMAGE_NAME"],
      site_config.0.scm_type,
    ]
  }

  logs {
    http_logs {
      file_system {
        retention_in_days = 7
        retention_in_mb   = 100
      }
    }
  }

  # Use managed identity to login to ACR
  # https://github.com/Azure/app-service-linux-docs/blob/master/HowTo/use_system-assigned_managed_identities.md
  provisioner "local-exec" {
    command = "az resource update --ids ${azurerm_app_service.current.id} --set properties.acrUseManagedIdentityCreds=True -o none"
  }

  # Configure if you need EasyAuth
  # auth_settings {
  # }
}

# Deployment slot for better availability during deployments
resource "azurerm_app_service_slot" "next" {
  name                = "${local.app_service_name}-next"
  resource_group_name = data.azurerm_resource_group.current.name
  location            = data.azurerm_resource_group.current.location
  app_service_name    = azurerm_app_service.current.name
  app_service_plan_id = azurerm_app_service_plan.current.id

  site_config {
    always_on                 = local.app_service_site_config.always_on
    min_tls_version           = local.app_service_site_config.min_tls_version
    health_check_path         = local.app_service_site_config.health_check_path
    use_32_bit_worker_process = local.app_service_site_config.use_32_bit_worker_process
  }

  app_settings = local.app_service_settings

  identity {
    type = "SystemAssigned"
  }

  lifecycle {
    ignore_changes = [
      app_settings["DOCKER_CUSTOM_IMAGE_NAME"],
      site_config.0.scm_type,
    ]
  }
}

# ── data.tf ──────────────────────────────────────────
data "azurerm_client_config" "current" {}

data "azurerm_resource_group" "current" {
  name = var.resource_group_name
}

# ── monitoring.tf ──────────────────────────────────────────
locals {
  healthcheck_endpoint = "https://${azurerm_app_service.current.default_site_hostname}/api/healthcheck"
}

# Action group to send an email for alerts
resource "azurerm_monitor_action_group" "current" {
  name                = "SendAlertEmail"
  resource_group_name = data.azurerm_resource_group.current.name
  short_name          = "Alert"

  email_receiver {
    name          = "sendtoemail"
    email_address = var.alert_email_address
  }
}

# Availability ping
resource "azurerm_application_insights_web_test" "app_availability" {
  name                    = "availability-${azurerm_app_service.current.name}"
  resource_group_name     = data.azurerm_resource_group.current.name
  location                = data.azurerm_resource_group.current.location
  application_insights_id = azurerm_application_insights.current.id
  kind                    = "ping"
  frequency               = 300
  timeout                 = 60
  enabled                 = true
  geo_locations           = ["emea-nl-ams-azr", "emea-ru-msa-edge", "emea-gb-db3-azr", "emea-fr-pra-edge", "us-va-ash-azr"]

  configuration = <<XML
<WebTest Name="Availability" Id="9a572603-75a7-4754-8f17-74d3a428d7fa" Enabled="True" CssProjectStructure="" CssIteration="" Timeout="120" WorkItemIds="" xmlns="http://microsoft.com/schemas/VisualStudio/TeamTest/2010" Description="" CredentialUserName="" CredentialPassword="" PreAuthenticate="True" Proxy="default" StopOnError="False" RecordedResultFile="" ResultsLocale="">
  <Items>
    <Request Method="GET" Guid="a3e2335b-cee0-ecd3-c892-ca25c94275b4" Version="1.1" Url="${local.healthcheck_endpoint}" ThinkTime="0" Timeout="120" ParseDependentRequests="False" FollowRedirects="True" RecordResult="True" Cache="False" ResponseTimeGoal="0" Encoding="utf-8" ExpectedHttpStatusCode="200" ExpectedResponseUrl="" ReportingName="" IgnoreHttpStatusCode="False" />
  </Items>
</WebTest>
XML

  lifecycle {
    ignore_changes = [
      tags
    ]
  }
}

# Availability ping failed alert
resource "azurerm_monitor_metric_alert" "app_availability" {
  name                = "${azurerm_app_service.current.name} server availability"
  resource_group_name = data.azurerm_resource_group.current.name
  # Both the availability web test AND the application insights need to be in the scope
  # https://github.com/terraform-providers/terraform-provider-azurerm/issues/8551
  scopes = [
    azurerm_application_insights_web_test.app_availability.id,
    azurerm_application_insights.current.id
  ]

  # Every 1 mins in 5 min window
  frequency   = "PT1M"
  window_size = "PT5M"
  # Critical
  severity = 0

  application_insights_web_test_location_availability_criteria {
    web_test_id           = azurerm_application_insights_web_test.app_availability.id
    component_id          = azurerm_application_insights.current.id
    failed_location_count = 3
  }

  action {
    action_group_id = azurerm_monitor_action_group.current.id
  }
}

# HTTP 5xx errors
resource "azurerm_monitor_metric_alert" "ms_5xx_errors" {
  name                = "${azurerm_app_service.current.name} server had HTTP 5xx errors"
  resource_group_name = data.azurerm_resource_group.current.name
  scopes = [
    azurerm_app_service.current.id
  ]

  # Every 15 mins in 15 min window
  frequency   = "PT15M"
  window_size = "PT15M"
  # Error
  severity = 1

  criteria {
    metric_namespace = "Microsoft.Web/sites"
    metric_name      = "Http5xx"
    aggregation      = "Total"
    operator         = "GreaterThan"
    threshold        = 0
  }

  action {
    action_group_id = azurerm_monitor_action_group.current.id
  }
}

# Dependency failures (e.g. HTTP request to another service or database query failed)
resource "azurerm_monitor_scheduled_query_rules_alert" "dependency_failures_in_app_service" {
  name                = "${azurerm_app_service.current.name} had dependency failures"
  resource_group_name = data.azurerm_resource_group.current.name
  location            = data.azurerm_resource_group.current.location
  data_source_id      = azurerm_application_insights.current.id
  frequency           = 15
  time_window         = 15
  # Error
  severity = 1
  query    = <<-QUERY
  dependencies
  | where resultCode == "False"
QUERY

  trigger {
    operator  = "GreaterThan"
    threshold = 0
  }

  action {
    action_group = [
      azurerm_monitor_action_group.current.id
    ]
  }
}

# ── provider.tf ──────────────────────────────────────────
# Configure the Azure Provider
provider "azurerm" {
  version                    = "= 2.37.0"
  skip_provider_registration = true
  features {}
}

provider "random" {
  version = "~> 2.3"
}

provider "template" {
  version = "~> 2.1"
}

# ── secrets.tf ──────────────────────────────────────────
# Application insights instrumentation key
resource "azurerm_key_vault_secret" "app_insights_instrumentation_key" {
  key_vault_id = azurerm_key_vault.current.id
  name         = "app-insights-key"
  value        = azurerm_application_insights.current.instrumentation_key

  depends_on = [azurerm_key_vault_access_policy.principal]
}

# ── shared.tf ──────────────────────────────────────────
# Since many services require a globally unique name (such as keyvault),
# generate random suffix for the resources
resource "random_string" "suffix" {
  length  = 8
  special = false
  upper   = false
}

locals {
  # Key vault and ACR required globally unique names. Only alphanumeric characters allowed
  key_vault_name = "${local.cleansed_prefix}${random_string.suffix.result}"
  acr_name       = "${local.cleansed_prefix}${random_string.suffix.result}"

  # App insights needs to be unique only within the resource group
  app_insights_name = "${var.name_prefix}app-insights"
}

resource "azurerm_key_vault" "current" {
  name                = local.key_vault_name
  location            = data.azurerm_resource_group.current.location
  resource_group_name = data.azurerm_resource_group.current.name
  tenant_id           = data.azurerm_client_config.current.tenant_id

  soft_delete_enabled        = true
  soft_delete_retention_days = 7
  purge_protection_enabled   = false

  sku_name = "standard"
}

resource "azurerm_container_registry" "current" {
  name                = local.acr_name
  resource_group_name = data.azurerm_resource_group.current.name
  location            = data.azurerm_resource_group.current.location
  sku                 = "Standard"

  # We'll be using AD login
  admin_enabled = false
}

resource "azurerm_application_insights" "current" {
  name                = local.app_insights_name
  resource_group_name = data.azurerm_resource_group.current.name
  location            = data.azurerm_resource_group.current.location
  application_type    = var.app_insights_app_type
}

# ── main.tf ──────────────────────────────────────────
provider "azuread" {
  version = "=0.7.0"
}

provider "random" {
  version = "=2.2.1"
}

provider "null" {
  version = "=2.1.2"
}

resource "azurerm_resource_group" "network" {
  name     = "${var.resource_name_prefix}-network-rgroup"
  location = var.location
}

resource "azurerm_virtual_network" "network" {
  name                = "${var.resource_name_prefix}-network"
  location            = var.location
  resource_group_name = azurerm_resource_group.network.name
  address_space       = ["10.137.0.0/16"]
}

resource "azurerm_subnet" "subnet" {
  name                 = "${var.resource_name_prefix}-subnet"
  virtual_network_name = azurerm_virtual_network.network.name
  resource_group_name  = azurerm_resource_group.network.name
  address_prefix       = "10.137.1.0/24"
  service_endpoints    = ["Microsoft.KeyVault"]

  lifecycle {
    ignore_changes = [
      network_security_group_id,
      route_table_id
    ]
  }
}

resource "azurerm_resource_group" "storage" {
  name     = "${var.resource_name_prefix}-storage-rgroup"
  location = var.location
}

resource "azurerm_storage_account" "storage" {
  name                      = "${var.resource_name_prefix}storage"
  resource_group_name       = azurerm_resource_group.storage.name
  location                  = var.location
  account_tier              = "Standard"
  account_replication_type  = "LRS"
  enable_https_traffic_only = true
}

resource "azurerm_storage_container" "storage" {
  name                  = "${var.resource_name_prefix}container"
  storage_account_name  = azurerm_storage_account.storage.name
  container_access_type = "private"
}

resource "azurerm_storage_blob" "a_file" {
  name                   = "hello.txt"
  storage_account_name   = azurerm_storage_account.storage.name
  storage_container_name = azurerm_storage_container.storage.name
  type                   = "Block"
  source_content         = "Hello, Blob!"
}

# ── variables.tf ──────────────────────────────────────────
variable "resource_name_prefix" {
  type    = string
  default = "trylayers"
}

variable "location" {
  type    = string
  default = "westeurope"
}

# ── layers.tf ──────────────────────────────────────────
/*
    You may need service principals for eg. managing access to Key Vault.
    However, that requires privileges to manage AD, which is outside of focus of this example.

resource "null_resource" "service_principal_layer" {
  provisioner "local-exec" {
    command = "echo === Created all Service Principals"
  }

  depends_on = [
    azuread_service_principal.keyvault_sp,
    azuread_service_principal_password.keyvault_sp_password
  ]
}
*/

resource "null_resource" "resource_group_layer" {
  provisioner "local-exec" {
    command = "echo === Created all resource groups"
  }

  depends_on = [
    # null_resource.service_principal_layer,
    azurerm_resource_group.network,
    azurerm_resource_group.storage
  ]
}

resource "null_resource" "network_layer" {
  provisioner "local-exec" {
    command = "echo === Created all virtual networks"
  }

  depends_on = [
    null_resource.resource_group_layer,
    azurerm_virtual_network.network
  ]
}

resource "null_resource" "subnet_layer" {
  provisioner "local-exec" {
    command = "echo === Created all subnets"
  }

  depends_on = [
    null_resource.network_layer,
    azurerm_subnet.subnet
  ]
}

resource "null_resource" "monitoring_layer" {
  provisioner "local-exec" {
    command = "echo === Created monitoring components"
  }

  depends_on = [
    null_resource.subnet_layer,
    # monitoring is a bit out of scope, but it would go here
  ]
}

resource "null_resource" "storage_layer" {
  provisioner "local-exec" {
    command = "echo === Created storages"
  }
  depends_on = [
    null_resource.monitoring_layer,
    azurerm_storage_account.storage
  ]
}

/*
Resources outside layers can be created by not targeting anything
once the layers have been created.

Resources can use depends_on to ensure associated layers have been created for them.
*/

# ── variables.tf ──────────────────────────────────────────
variable "config" {
  type = any
}

# ── outputs.tf ──────────────────────────────────────────
output "prober_ingress_table" {
  value = google_bigquery_table.prober_ingress
}

output "control_dataset" {
  value = google_bigquery_dataset.ingress
}
output "unified_values_table" {
  value = google_bigquery_table.unified_values
}
output "current_totals_latest_table" {
  value = google_bigquery_table.current_totals_latest
}

output "historical_totals_latest_table" {
  value = google_bigquery_table.historical_totals_latest
}

output "current_totals_table" {
  value = google_bigquery_table.current_totals
}

output "historical_totals_table" {
  value = google_bigquery_table.historical_totals
}

output "ingress_dataset" {
  value = google_bigquery_dataset.ingress
}

# ── controls.tf ──────────────────────────────────────────
locals {
  control_fields = ["multiplier"]
  control_types  = ["FLOAT"]
  default_value  = ["1.0"]
}

resource "google_bigquery_table" "control_operations" {
  count = length(local.control_fields)
  dataset_id = google_bigquery_dataset.ingress.dataset_id
  table_id   = "control_${element(local.control_fields, count.index)}"
  schema = templatefile(
      "${path.module}/schemas/control.template.schema.json", {
          FIELD = element(local.control_fields, count.index)
          TYPE = element(local.control_types, count.index)
      })
  time_partitioning {
    field = "timestamp"
    type = "DAY"
    require_partition_filter = false
  }
  lifecycle {
    prevent_destroy = true
  }
}

resource "google_bigquery_table" "control_range_view" {
  count = length(local.control_fields)
  dataset_id = google_bigquery_dataset.views.dataset_id
  table_id   = "control_value_range_${element(local.control_fields, count.index)}"
  view {
    query = templatefile("${path.module}/sql/control_range_view.sql", {
          NAME = element(local.control_fields, count.index),
          DEFAULT = element(local.default_value, count.index)
          OPERATIONS = "${var.config.project}.${google_bigquery_table.control_operations[count.index].dataset_id}.${google_bigquery_table.control_operations[count.index].table_id}"
    })
    use_legacy_sql = false
  }
}

# ── ingress.tf ──────────────────────────────────────────
resource "google_bigquery_dataset" "ingress" {
  dataset_id                  = "ingress"
  description                 = "Raw event data"
  location                    = "EU"
}

resource "google_bigquery_table" "vendor1_ingress" {
  dataset_id = google_bigquery_dataset.ingress.dataset_id
  table_id   = "vendor1_ingress"
  schema = file("${path.module}/schemas/vendor1.schema.json")
  time_partitioning {
    field = "timestamp"
    type = "DAY"
    require_partition_filter = true
  }
  lifecycle {
    prevent_destroy = true
  }
}

resource "google_bigquery_table" "prober_ingress" {
  dataset_id = google_bigquery_dataset.ingress.dataset_id
  table_id   = "prober_ingress"
  schema = "${file("${path.module}/schemas/prober.schema.json")}"
  time_partitioning {
    field = "timestamp"
    type = "DAY"
    require_partition_filter = true
  }
  lifecycle {
    prevent_destroy = true
  }
}

# ── reports.tf ──────────────────────────────────────────
resource "google_bigquery_dataset" "reports" {
  dataset_id                  = "reports"
  description                 = "Materialized reports"
  location                    = "EU"
}

resource "google_bigquery_table" "current_totals" {
  dataset_id = google_bigquery_dataset.reports.dataset_id
  table_id   = "current_totals"
  schema = "${file("${path.module}/schemas/report.schema.json")}"
}

resource "google_bigquery_table" "historical_totals" {
  dataset_id = google_bigquery_dataset.reports.dataset_id
  table_id   = "historical_totals"
  schema = "${file("${path.module}/schemas/report.schema.json")}"
  time_partitioning {
    field = "day"
    type = "DAY"
    require_partition_filter = true
  }
}

# ── urdf.tf ──────────────────────────────────────────
resource "google_bigquery_dataset" "urdfs" {
  dataset_id                  = "urdfs"
  description                 = "Data processing"
  location                    = "EU"
}
resource "google_storage_bucket_object" "jsonpath" {
  name   = "udf/jsonpath-0.8.0.js"
  source = "${path.module}/udf/jsonpath-0.8.0.js"
  bucket = "${var.config.code_bucket.name}"
}

resource "null_resource" "CUSTOM_JSON_EXTRACT_ARRAY_FLOAT" {
  triggers = {
    version = "0.0.4" // Bump to force apply to this resource
  }
  provisioner "local-exec" {
    command = "bq query --project=${var.config.project} --use_legacy_sql=false '${templatefile("${path.module}/udf/CUSTOM_JSON_EXTRACT_ARRAY_FLOAT.sql", {
        dataset = google_bigquery_dataset.urdfs.dataset_id
        library = "gs://${var.config.code_bucket.name}/${google_storage_bucket_object.jsonpath.output_name}"
    })}'"
  }
}

# ── views.tf ──────────────────────────────────────────
resource "google_bigquery_dataset" "views" {
  dataset_id                  = "views"
  description                 = "Data processing"
  location                    = "EU"
}

resource "google_bigquery_table" "vendor1" {
  dataset_id = google_bigquery_dataset.views.dataset_id
  table_id   = "vendor1"
  view {
    query = templatefile("${path.module}/sql/vendor1_cleanup.sql", {
      urdfs = "${var.config.project}.${google_bigquery_dataset.urdfs.dataset_id}"
      ingress = "${var.config.project}.${google_bigquery_table.vendor1_ingress.dataset_id}.${google_bigquery_table.vendor1_ingress.table_id}"
    })
    use_legacy_sql = false
  }
  depends_on = [null_resource.CUSTOM_JSON_EXTRACT_ARRAY_FLOAT]
}

resource "google_bigquery_table" "unified_values" {
  dataset_id = google_bigquery_dataset.views.dataset_id
  table_id   = "unified_values"
  view {
    query = templatefile("${path.module}/sql/unified_values.sql", {
      prober = "${var.config.project}.${google_bigquery_table.prober_ingress.dataset_id}.${google_bigquery_table.prober_ingress.table_id}",
      vendor1 = "${var.config.project}.${google_bigquery_table.vendor1.dataset_id}.${google_bigquery_table.vendor1.table_id}"
    })
    use_legacy_sql = false
  }
}

resource "google_bigquery_table" "daily_adjusted_totals" {
  dataset_id = google_bigquery_dataset.views.dataset_id
  table_id   = "daily_adjusted_totals"
  view {
    query = templatefile("${path.module}/sql/daily_adjusted_totals.sql", {
      values = "${var.config.project}.${google_bigquery_table.unified_values.dataset_id}.${google_bigquery_table.unified_values.table_id}",
      control_prefix = "${var.config.project}.${google_bigquery_table.control_range_view[0].dataset_id}.control_value_range_",
      control_fields = ["multiplier"]
    })
    use_legacy_sql = false
  }
}

resource "google_bigquery_table" "current_totals_latest" {
  dataset_id = google_bigquery_dataset.views.dataset_id
  table_id   = "current_totals"
  view {
    query = templatefile("${path.module}/sql/last_n_days_totals.sql", {
      n_days = 1
      PREFIX = "current_totals/"
      daily_totals = "${var.config.project}.${google_bigquery_table.daily_adjusted_totals.dataset_id}.${google_bigquery_table.daily_adjusted_totals.table_id}"
    })
    use_legacy_sql = false
  }
}

resource "google_bigquery_table" "historical_totals_latest" {
  dataset_id = google_bigquery_dataset.views.dataset_id
  table_id   = "historical_totals"
  view {
    query = templatefile("${path.module}/sql/last_n_days_totals.sql", {
      n_days = "${var.config.retention_days}"
      PREFIX = "historic_totals/"
      daily_totals = "${var.config.project}.${google_bigquery_table.daily_adjusted_totals.dataset_id}.${google_bigquery_table.daily_adjusted_totals.table_id}"
    })
    use_legacy_sql = false
  }
}

# ── variables.tf ──────────────────────────────────────────
variable "config" {
  type = any
}

variable "prober_ingress_table" {
  type = any
}

variable "control_dataset" {
  type = any
}

variable "unified_values_table" {
  type = any
}

variable "current_totals_latest_table" {
  type = any
}

variable "historical_totals_latest_table" {
  type = any
}

variable "current_totals_table" {
  type = any
}

variable "historical_totals_table" {
  type = any
}

variable "memorystore_host" {
  type = any
}

# ── function_memorystoreloader.tf ──────────────────────────────────────────
locals {
  memorystoreloader_function_name = "memorystoreload"
}

resource "google_cloudfunctions_function" "memorystoreloader" {
  name    = "memorystoreloader"
  runtime = "nodejs10"
  /* Testing has minimal resource requirements */
  max_instances       = 2
  available_memory_mb = 2048 // Cache loading speed is improved with better instance type, linearly
  timeout             = 60
  entry_point         = "memorystoreload"
  region              = var.config.region

  source_archive_bucket = var.config.code_bucket.name
  source_archive_object = google_storage_bucket_object.memorystoreload_code.name

  // Function triggered by mutations in the upload bucket
  event_trigger {
    event_type = "providers/cloud.storage/eventTypes/object.change"
    resource   = google_storage_bucket.memorystore_uploads.name
    failure_policy {
      retry = false
    }
  }

  provider      = "google-beta"
  vpc_connector = google_vpc_access_connector.serverless_vpc_connector.name

  environment_variables = {
    REDIS_HOST = var.memorystore_host
    REDIS_PORT = 6379
    EXPIRY     = 60 * 60 * 24 * 30 // 30d expiry for keys
  }
}

data "archive_file" "memorystoreload_zip" {
  type        = "zip"
  source_dir  = "${path.module}/src/memorystoreload"
  output_path = ".tmp/${local.memorystoreloader_function_name}.zip"
}

resource "google_storage_bucket_object" "memorystoreload_code" {
  /* Name needs to be mangled to enable functions to be updated */
  name   = "${local.memorystoreloader_function_name}.${data.archive_file.memorystoreload_zip.output_md5}.zip"
  bucket = var.config.code_bucket.name
  source = data.archive_file.memorystoreload_zip.output_path
}

# ── function_prober.tf ──────────────────────────────────────────
locals {
  probe_function_name = "probe"
}

resource "google_cloudfunctions_function" "prober" {
  name    = "prober"
  runtime = "nodejs10"
  /* Probing has minimal resource requirements */
  max_instances       = 1
  available_memory_mb = 128
  timeout             = 30
  entry_point         = "probe"
  region              = var.config.region

  source_archive_bucket = var.config.code_bucket.name
  source_archive_object = google_storage_bucket_object.probe_code.name

  event_trigger {
    event_type = "providers/cloud.pubsub/eventTypes/topic.publish"
    resource   = google_pubsub_topic.version_every_minute.name
    failure_policy {
      retry = false
    }
  }

  environment_variables = {
    PROBE_DATASET   = var.prober_ingress_table.dataset_id
    PROBE_TABLE     = var.prober_ingress_table.table_id
    CONTROLS_DATASET = var.control_dataset.dataset_id
  }
}

data "archive_file" "probe_zip" {
  type        = "zip"
  source_dir  = "${path.module}/src/probe"
  output_path = ".tmp/${local.probe_function_name}.zip"
}

resource "google_storage_bucket_object" "probe_code" {
  /* Name needs to be mangled to enable functions to be updated */
  name   = "${local.probe_function_name}.${data.archive_file.probe_zip.output_md5}.zip"
  bucket = var.config.code_bucket.name
  source = data.archive_file.probe_zip.output_path
}

# ── function_test.tf ──────────────────────────────────────────
locals {
    test_function_name = "test"
}

resource "google_cloudfunctions_function" "test" {
  name                  = "test"
  runtime               = "nodejs10"
  /* Testing has minimal resource requirements */
  max_instances         = 1
  available_memory_mb   = 128
  timeout               = 30
  entry_point           = "test"
  region                = var.config.region

  source_archive_bucket = var.config.code_bucket.name
  source_archive_object = google_storage_bucket_object.test_code.name

  trigger_http = true

  provider      = "google-beta"
  vpc_connector = google_vpc_access_connector.serverless_vpc_connector.name

  environment_variables = {
    CONFIG_BUCKET = var.config.code_bucket.name
    PROBER_DATASET = var.prober_ingress_table.dataset_id
    PROBER_TABLE = var.prober_ingress_table.table_id
    UNIFIED_VALUES_DATASET = var.unified_values_table.dataset_id
    UNIFIED_VALUES_TABLE = var.unified_values_table.table_id
    /*
    UNIFIED_METABOLICS_DATASET = var.unified_metabolics_table.dataset_id
    UNIFIED_METABOLICS_TABLE = var.unified_metabolics_table.table_id
    */
    CURRENT_TOTALS_DATASET = var.current_totals_table.dataset_id
    CURRENT_TOTALS_TABLE = var.current_totals_table.table_id
    /*
    DAILY_METABOLICS_PRECOMPUTE_DATASET = var.daily_metabolics_precompute_table.dataset_id
    DAILY_METABOLICS_PRECOMPUTE_TABLE = var.daily_metabolics_precompute_table.table_id
    */
    MEMORYSTORE_UPLOADS_BUCKET = google_storage_bucket.memorystore_uploads.name
    REDIS_HOST = var.memorystore_host
    REDIS_PORT = 6379
  }
}

data "archive_file" "test_zip" {
  type        = "zip"
  source_dir  = "${path.module}/src/test"
  output_path = ".tmp/${local.test_function_name}.zip"
}

resource "google_storage_bucket_object" "test_code" {
  /* Name needs to be mangled to enable functions to be updated */
  name   = "${local.test_function_name}.${data.archive_file.test_zip.output_md5}.zip"
  bucket = var.config.code_bucket.name
  source = data.archive_file.test_zip.output_path
}

# ── function_update_current.tf ──────────────────────────────────────────
locals {
  materializer_function_name = "materialize"
}

resource "google_cloudfunctions_function" "update_current" {
  name    = "update_current"
  runtime = "nodejs10"
  /* Running BQ client has minimal resource requirements */
  max_instances       = 1
  available_memory_mb = 128
  timeout             = 30
  entry_point         = "materialize"
  region              = var.config.region

  source_archive_bucket = var.config.code_bucket.name
  source_archive_object = google_storage_bucket_object.materialize_code.name

  // Function triggered by mutations in the upload bucket
  event_trigger {
    event_type = "providers/cloud.pubsub/eventTypes/topic.publish"
    resource   = google_pubsub_topic.version_every_two_minutes.name
    failure_policy {
      retry = false
    }
  }

  environment_variables = {
    PROJECT        = var.config.project
    DATASET        = var.current_totals_table.dataset_id
    TABLE          = var.current_totals_table.table_id
    SOURCE_DATASET = var.current_totals_latest_table.dataset_id
    SOURCE_TABLE   = var.current_totals_latest_table.table_id
    BUCKET         = google_storage_bucket.memorystore_uploads.name
    FILE           = "current_totals.json"
  }
}

data "archive_file" "materialize_zip" {
  type        = "zip"
  source_dir  = "${path.module}/src/materialize"
  output_path = ".tmp/${local.materializer_function_name}.zip"
}

resource "google_storage_bucket_object" "materialize_code" {
  /* Name needs to be mangled to enable functions to be updated */
  name   = "${local.materializer_function_name}.${data.archive_file.materialize_zip.output_md5}.zip"
  bucket = var.config.code_bucket.name
  source = data.archive_file.materialize_zip.output_path
}

# ── function_update_historical.tf ──────────────────────────────────────────
resource "google_cloudfunctions_function" "update_historical" {
  name    = "update_historical"
  runtime = "nodejs10"
  /* Running BQ client has minimal resource requirements */
  max_instances       = 1
  available_memory_mb = 128
  timeout             = 30
  entry_point         = "materialize"
  region              = var.config.region

  source_archive_bucket = var.config.code_bucket.name
  // Note we reuse source code setup in function_update_current.tf
  source_archive_object = google_storage_bucket_object.materialize_code.name

  // Function triggered by mutations in the upload bucket
  event_trigger {
    event_type = "providers/cloud.pubsub/eventTypes/topic.publish"
    resource   = google_pubsub_topic.version_every_hour.name
    failure_policy {
      retry = false
    }
  }

  environment_variables = {
    PROJECT        = var.config.project
    DATASET        = var.historical_totals_table.dataset_id
    TABLE          = var.historical_totals_table.table_id
    SOURCE_DATASET = var.historical_totals_latest_table.dataset_id
    SOURCE_TABLE   = var.historical_totals_latest_table.table_id
    N_DAYS         = var.config.retention_days
    BUCKET         = google_storage_bucket.memorystore_uploads.name
    FILE           = "historical_totals.json"
  }
}

# ── gcs.tf ──────────────────────────────────────────
resource "google_storage_bucket" "memorystore_uploads" {
  name     = "${var.config.project}_memorystore_uploads"
  location = "${var.config.region}"
}

# ── pubsub.tf ──────────────────────────────────────────
resource "google_pubsub_topic" "version_every_minute" {
  name = "version_every_minute"
}

resource "google_pubsub_topic" "version_every_two_minutes" {
  name = "version_every_two_minutes"
}

resource "google_pubsub_topic" "version_every_hour" {
  name = "version_every_hour"
}

# ── scheduler.tf ──────────────────────────────────────────
resource "google_cloud_scheduler_job" "version_every_minute" {
  name        = "version_every_minute"
  description = "Pings topic with version once a min"
  schedule    = "* * * * *"
  project     = var.config.project
  region      = var.config.region

  pubsub_target {
    topic_name = "${google_pubsub_topic.version_every_minute.id}"
    data = "${base64encode(jsonencode({
      version = "${var.config.version}"
    }))}"
  }
}

resource "google_cloud_scheduler_job" "version_every_two_minutes" {
  name        = "version_every_two_minutes"
  description = "Pings topic with version once every 2 mins"
  schedule    = "*/2 * * * *"
  project     = "${var.config.project}"
  region      = "${var.config.region}"

  pubsub_target {
    topic_name = "${google_pubsub_topic.version_every_two_minutes.id}"
    data = "${base64encode(jsonencode({
      version = "${var.config.version}"
    }))}"
  }
}

resource "google_cloud_scheduler_job" "version_every_hour" {
  name        = "version_every_hour"
  description = "Pings topic with version once every hour"
  schedule    = "0 * * * *"
  region      = "${var.config.region}"
  project     = "${var.config.project}"

  pubsub_target {
    topic_name = "${google_pubsub_topic.version_every_hour.id}"
    data = "${base64encode(jsonencode({
      version = "${var.config.version}"
    }))}"
  }
}

# ── vpc.tf ──────────────────────────────────────────
resource "google_vpc_access_connector" "serverless_vpc_connector" {
  name          = "${var.config.network}-connector"
  provider      = "google-beta"
  region        = var.config.region
  ip_cidr_range = var.config.ip_cidr_range
  network       = var.config.network
}

# ── variables.tf ──────────────────────────────────────────
variable "config" {
  type = any
}

# ── outputs.tf ──────────────────────────────────────────
output "memorystore_host" {
  value = google_redis_instance.cache.host
}

# ── memorystore.tf ──────────────────────────────────────────
resource "google_redis_instance" "cache" {
  name                    = "redis"
  memory_size_gb          = 1
  project                 = var.config.project
  location_id             = "${var.config.region}-c"
  tier                    = "BASIC"
  authorized_network      = var.config.network
}

# ── main.tf ──────────────────────────────────────────
terraform {
  backend "gcs" {
    prefix = "terraform/state"
    bucket = "terraform-larkworthy-camunda" // Must be pre-provisioned
  }
}

provider "google" {
  project = "larkworthy-tester"
  region  = "europe-west1"
}

locals {
  project = "larkworthy-tester"
  config = {
    project         = local.project
    base_image_name = "camunda/camunda-bpm-platform"
    base_image_tag  = "7.12.0"
    region          = "europe-west1"
  }
}

# ── build.tf ──────────────────────────────────────────
# Copy Camunda base image from Dockerhub image into Google Container Registry
module "docker-mirror-camunda-bpm-platform" {
  source      = "github.com/neomantra/terraform-docker-mirror"
  image_name  = local.config.base_image_name
  image_tag   = local.config.base_image_tag
  dest_prefix = "eu.gcr.io/${local.project}"
}

# Hydrate docker template file into .build directory
resource "local_file" "dockerfile" {
  content = templatefile("${path.module}/Dockerfile.template", {
    project = local.project
    image   = local.config.base_image_name
    tag     = local.config.base_image_tag
  })
  filename = "${path.module}/.build/Dockerfile"
}

# Hydrate bpm-platform config into .build directory
resource "local_file" "bpm-platform" {
  content = templatefile("${path.module}/config/bpm-platform.xml.template", {
    maxJobsPerAcquisition = null
    lockTimeInMillis = null
    waitTimeInMillis = 1
    maxWait = null
    history = "none"
    databaseSchemaUpdate = null # default
    authorizationEnabled = null # default
    jobExecutorDeploymentAware = "false"
    historyCleanupBatchWindowStartTime = null # default
  })
  filename = "${path.module}/.build/bpm-platform.xml"
}

# Build a customized image of Camunda to include the cloud sql postgres socket factory library
# Required to connect to Cloud SQL
# Built using Cloud Build, image stored in GCR
resource "null_resource" "camunda_cloudsql_image" {
  depends_on = [module.docker-mirror-camunda-bpm-platform]
  triggers = {
    # Rebuild if we change the base image, dockerfile, or bpm-platform config
    image = "eu.gcr.io/${local.project}/camunda_cloudsql:${local.config.base_image_tag}_${
      sha1(
        "${sha1(local_file.dockerfile.content)}${sha1(local_file.bpm-platform.content)}"
      )
    }"
  }
  provisioner "local-exec" {
    command = <<-EOT
        gcloud builds submit \
        --project ${local.project} \
        --tag ${self.triggers.image} \
        ${path.module}/.build
    EOT
  }
}

# ── camunda.tf ──────────────────────────────────────────
# Policy to allow public access to Cloud Run endpoint
data "google_iam_policy" "noauth" {
  binding {
    role    = "roles/run.invoker"
    members = ["allUsers"]
  }
}

# Bind public policy to our Camunda Cloud Run service
resource "google_cloud_run_service_iam_policy" "noauth" {
  location    = google_cloud_run_service.camunda.location
  project     = google_cloud_run_service.camunda.project
  service     = google_cloud_run_service.camunda.name
  policy_data = data.google_iam_policy.noauth.policy_data
}

# Create service account to run service
resource "google_service_account" "camunda" {
  account_id   = "camunda-worker"
  display_name = "Camunda Worker"
}

# Give the service account access to Cloud SQL
resource "google_project_iam_member" "project" {
  role   = "roles/cloudsql.client"
  member = "serviceAccount:${google_service_account.camunda.email}"
}

# Cloud Run Camunda service
resource "google_cloud_run_service" "camunda" {
  name     = "camunda"
  location = local.config.region
  template {
    spec {
      # Use locked down Service Account
      service_account_name = google_service_account.camunda.email
      containers {
        image = null_resource.camunda_cloudsql_image.triggers.image
        resources {
          limits = {
            # Default of 256Mb is not enough to start Camunda
            memory = "2Gi"
            cpu    = "1000m"
          }
        }
        env {
          name = "DB_URL"
          # Complicated DB URL to Cloud SQL
          # See https://github.com/GoogleCloudPlatform/cloud-sql-jdbc-socket-factory
          value = "jdbc:postgresql:///${google_sql_database.database.name}?cloudSqlInstance=${google_sql_database_instance.camunda-db.connection_name}&socketFactory=com.google.cloud.sql.postgres.SocketFactory"
        }

        env {
          name  = "DB_DRIVER"
          value = "org.postgresql.Driver"
        }
        env {
          name  = "DB_USERNAME"
          value = google_sql_user.user.name
        }
        env {
          name  = "DB_PASSWORD"
          value = google_sql_user.user.password
        }
        # Test instance of Cloud SQL has low connection limit
        # So we turn down the connection pool size
        env {
          name  = "DB_CONN_MAXACTIVE"
          value = "5"
        }
        env {
          name  = "DB_CONN_MAXIDLE"
          value = "5"
        }
        env {
          name  = "DB_CONN_MINIDLE"
          value = "0"
        }
        env {
          name  = "DB_VALIDATE_ON_BORROW"
          value = "true"
        }
      }
    }

    metadata {
      annotations = {
        "autoscaling.knative.dev/maxScale"      = "1" # no clusting
        "run.googleapis.com/cloudsql-instances" = google_sql_database_instance.camunda-db.connection_name
      }
    }
  }

  traffic {
    percent         = 100
    latest_revision = true
  }
}

# ── cloudsql.tf ──────────────────────────────────────────
resource "google_sql_database_instance" "camunda-db" {
  name             = "camunda-db-postgres"
  database_version = "POSTGRES_11"
  region           = local.config.region

  settings {
    # Very small instance for testing.
    tier = "db-f1-micro"
    ip_configuration {
        ipv4_enabled = true
    }
  }
}

resource "google_sql_user" "user" {
  name     = "camunda"
  instance = google_sql_database_instance.camunda-db.name
  password = "futurice"
}

resource "google_sql_database" "database" {
  name     = "camunda"
  instance = google_sql_database_instance.camunda-db.name
}

# ── main.tf ──────────────────────────────────────────
terraform {
  backend "gcs" {
    prefix = "camunda-secure/state"
    bucket = "terraform-larkworthy-camunda" // Must be pre-provisioned
  }
