}

variable "AWS_ACCOUNT_ID" {
  default   = "Your aws account number"
  type      = string
  sensitive = true
}

# ── API-GW.tf ──────────────────────────────────────────
resource "aws_api_gateway_rest_api" "API" {
  name        = "lambda-api"
  description = "lambda-api"
  endpoint_configuration {
    types = ["REGIONAL"]
  }
}

resource "aws_api_gateway_resource" "Resource" {
  rest_api_id = aws_api_gateway_rest_api.API.id
  parent_id   = aws_api_gateway_rest_api.API.root_resource_id
  path_part   = "verify-json"
}

resource "aws_api_gateway_method" "Method" {
  rest_api_id   = aws_api_gateway_rest_api.API.id
  resource_id   = aws_api_gateway_resource.Resource.id
  http_method   = "POST"
  authorization = "NONE"
}

resource "aws_api_gateway_integration" "Integration" {
  rest_api_id             = aws_api_gateway_rest_api.API.id
  resource_id             = aws_api_gateway_resource.Resource.id
  http_method             = aws_api_gateway_method.Method.http_method
  integration_http_method = "POST"
  type                    = "AWS_PROXY"
  uri                     = aws_lambda_function.lambda-function.invoke_arn
}

resource "aws_lambda_permission" "apigw-lambda" {
  statement_id  = "AllowExecutionFromAPIGateway"
  action        = "lambda:InvokeFunction"
  function_name = aws_lambda_function.lambda-function.function_name
  principal     = "apigateway.amazonaws.com"
  source_arn    = "arn:aws:execute-api:${var.AWS_REGION}:${var.AWS_ACCOUNT_ID}:${aws_api_gateway_rest_api.API.id}/*/${aws_api_gateway_method.Method.http_method}${aws_api_gateway_resource.Resource.path}"
}

resource "aws_api_gateway_method_response" "response_200" {
  rest_api_id = aws_api_gateway_rest_api.API.id
  resource_id = aws_api_gateway_resource.Resource.id
  http_method = aws_api_gateway_method.Method.http_method
  status_code = "200"
}

resource "aws_api_gateway_integration_response" "Integration-Response" {
  rest_api_id = aws_api_gateway_rest_api.API.id
  resource_id = aws_api_gateway_resource.Resource.id
  http_method = aws_api_gateway_method.Method.http_method
  status_code = aws_api_gateway_method_response.response_200.status_code

  depends_on = [
    aws_api_gateway_integration.Integration
  ]

  response_templates = {
    "application/xml" = <<EOF
#set($inputRoot = $input.path('$'))
<?xml version="1.0" encoding="UTF-8"?>
<message>
    $inputRoot.body
</message>
EOF
  }
}

resource "aws_api_gateway_deployment" "example" {
  depends_on = [
    aws_api_gateway_integration.Integration
  ]
  rest_api_id = aws_api_gateway_rest_api.API.id
  stage_name  = "test"
}

# ── iam-policy.tf ──────────────────────────────────────────
resource "aws_iam_role_policy" "iam-policy" {
  name   = "cloudwatch-policy"
  role   = aws_iam_role.iam-role.id
  policy = file("${path.module}/iam-policy.json")
}

# ── iam-role.tf ──────────────────────────────────────────
data "aws_iam_policy_document" "assume_role" {
  statement {
    effect = "Allow"

    principals {
      type        = "Service"
      identifiers = ["lambda.amazonaws.com"]
    }

    actions = ["sts:AssumeRole"]
  }
}

resource "aws_iam_role" "iam-role" {
  name               = "iam-role-lambda-api-gateway"
  assume_role_policy = data.aws_iam_policy_document.assume_role.json
}

# ── lambda-function.tf ──────────────────────────────────────────
resource "aws_lambda_function" "lambda-function" {
  filename      = "${path.module}/code.zip"
  function_name = "api-gw-lambda"
  role          = aws_iam_role.iam-role.arn
  handler       = "code.lambda_handler"
  runtime       = "python3.9"
}

# ── output.tf ──────────────────────────────────────────
output "api-gateway-url" {
  value = aws_api_gateway_deployment.example.invoke_url
}

# ── provider.tf ──────────────────────────────────────────
provider "aws" {
  region = "us-east-1"
}

terraform {
  required_version = ">= 0.11.7"
}

variable "account_code" {
   description = "code of cloud account: can be 1 or 2"
}

# Add fake resource to make sure that TFE runs this each time
resource "null_resource" "fake" {
   triggers {
      uuid = "${uuid()}"
   }
}

data "external" "check_balance" {
  program = ["./check_account.sh", "${var.account_code}"]
}

output "balance" {
  value = "${data.external.check_balance.result["balance"]}"
}

# ── main.tf ──────────────────────────────────────────
terraform {
  required_version = ">= 0.11.0"
}

provider "aws" {
  region = "${var.aws_region}"
}

resource "aws_instance" "ubuntu" {
  ami           = "${var.ami_id}"
  instance_type = "${var.instance_type}"
  availability_zone = "${var.aws_region}a"

  tags {
    Name = "${var.name}"
  }
}

# ── variables.tf ──────────────────────────────────────────
variable "aws_region" {
  description = "AWS region"
  default = "us-west-1"
}

variable "ami_id" {
  description = "ID of the AMI to provision. Default is Ubuntu 14.04 Base Image"
  default = "ami-2e1ef954"
}

variable "instance_type" {
  description = "type of EC2 instance to provision."
  default = "t2.micro"
}

variable "name" {
  description = "name to pass to Name tag"
  default = "Provisioned by Terraform"
}

# ── outputs.tf ──────────────────────────────────────────
output "public_dns" {
  value = "${aws_instance.ubuntu.public_dns}"
}

terraform {
  required_version = ">= 0.11.1"
}

variable "location" {
  description = "Azure location in which to create resources"
  default = "East US"
}

variable "windows_dns_prefix" {
  description = "DNS prefix to add to to public IP address for Windows VM"
}

variable "admin_password" {
  description = "admin password for Windows VM"
  default = "pTFE1234!"
}

module "windowsserver" {
  source              = "Azure/compute/azurerm"
  version             = "1.1.5"
  location            = "${var.location}"
  resource_group_name = "${var.windows_dns_prefix}-rc"
  vm_hostname         = "pwc-ptfe"
  admin_password      = "${var.admin_password}"
  vm_os_simple        = "WindowsServer"
  public_ip_dns       = ["${var.windows_dns_prefix}"]
  vnet_subnet_id      = "${module.network.vnet_subnets[0]}"
}

module "network" {
  source              = "Azure/network/azurerm"
  version             = "1.1.1"
  location            = "${var.location}"
  resource_group_name = "${var.windows_dns_prefix}-rc"
  allow_ssh_traffic   = true
}

output "windows_vm_public_name"{
  value = "${module.windowsserver.public_ip_dns_name}"
}

# ── main.tf ──────────────────────────────────────────
terraform {
  required_version = ">= 0.11.0"
}

// Vault provider
// Set VAULT_ADDR and VAULT_TOKEN environment variables
provider "vault" {}

// AWS credentials from Vault
data "vault_aws_access_credentials" "aws_creds" {
  backend = "aws"
  role = "deploy"
}

//  Setup the core provider information.
provider "aws" {
  access_key = "${data.vault_aws_access_credentials.aws_creds.access_key}"
  secret_key = "${data.vault_aws_access_credentials.aws_creds.secret_key}"
  region  = "${var.region}"
}

data "aws_availability_zones" "main" {}

# ── variables.tf ──────────────────────────────────────────
# Required variables
variable "environment_name" {
  description = "Environment Name"
  default = "Acme"
}

variable "region" {
  description = "AWS region"
  default = "us-west-2"
}

# Optional variables
variable "vpc_cidr" {
  default = "172.19.0.0/16"
}

variable "vpc_cidrs_public" {
  default = [
    "172.19.0.0/20",
  ]
}

# ── outputs.tf ──────────────────────────────────────────
# Outputs
output "vpc_id" {
  value = "${aws_vpc.main.id}"
}

output "subnet_public_ids" {
  value = ["${aws_subnet.public.*.id}"]
}

output "security_group_apps" {
  value = "${aws_security_group.egress_public.id}"
}

# ── networks-firewalls-ingress.tf ──────────────────────────────────────────
resource "aws_security_group_rule" "ssh" {
  security_group_id = "${aws_security_group.egress_public.id}"
  type              = "ingress"
  protocol          = "tcp"
  from_port         = 22
  to_port           = 22
  cidr_blocks       = ["0.0.0.0/0"]
}

# ── networks-firewalls.tf ──────────────────────────────────────────
resource "aws_security_group" "egress_public" {
  name        = "${var.environment_name}-egress_public"
  description = "${var.environment_name}-egress_public"
  vpc_id      = "${aws_vpc.main.id}"
}

resource "aws_security_group_rule" "egress_public" {
  security_group_id = "${aws_security_group.egress_public.id}"
  type              = "egress"
  protocol          = "-1"
  from_port         = 0
  to_port           = 0
  cidr_blocks       = ["0.0.0.0/0"]
}

resource "aws_security_group_rule" "ingress_internal" {
  security_group_id = "${aws_security_group.egress_public.id}"
  type              = "ingress"
  protocol          = "-1"
  from_port         = 0
  to_port           = 0
  self              = "true"
}

# ── networks-gateways.tf ──────────────────────────────────────────
resource "aws_internet_gateway" "main" {
  vpc_id = "${aws_vpc.main.id}"

  tags {
    Name = "${var.environment_name}"
  }
}

resource "aws_nat_gateway" "nat" {
  count = "${length(var.vpc_cidrs_public)}"

  allocation_id = "${element(aws_eip.nat.*.id,count.index)}"
  subnet_id     = "${element(aws_subnet.public.*.id,count.index)}"
}

resource "aws_eip" "nat" {
  count = "${length(var.vpc_cidrs_public)}"

  vpc = true
}

# ── networks-routes.tf ──────────────────────────────────────────
#
# Public
#
resource "aws_route_table" "public" {
  vpc_id = "${aws_vpc.main.id}"

  route {
    cidr_block = "0.0.0.0/0"
    gateway_id = "${aws_internet_gateway.main.id}"
  }

  tags {
    Name = "${var.environment_name}-public"
  }
}

resource "aws_route_table_association" "public" {
  count = "${length(var.vpc_cidrs_public)}"

  subnet_id      = "${element(aws_subnet.public.*.id,count.index)}"
  route_table_id = "${aws_route_table.public.id}"
}

# ── networks-subnets.tf ──────────────────────────────────────────
resource "aws_subnet" "public" {
  count = "${length(var.vpc_cidrs_public)}"

  vpc_id                  = "${aws_vpc.main.id}"
  availability_zone       = "${element(data.aws_availability_zones.main.names,count.index)}"
  cidr_block              = "${element(var.vpc_cidrs_public,count.index)}"
  map_public_ip_on_launch = true

  tags {
    Name = "${var.environment_name}-public-${count.index}"
  }
}

# ── networks.tf ──────────────────────────────────────────
resource "aws_vpc" "main" {
  cidr_block           = "${var.vpc_cidr}"
  enable_dns_hostnames = true

  tags {
    Name = "${var.environment_name}"
  }
}

variable "name" { default = "dynamic-aws-creds-consumer" }
variable "path" { default = "../producer-workspace/terraform.tfstate" }
variable "ttl"  { default = "1" }

terraform {
  backend "local" {
    path = "terraform.tfstate"
  }
}

data "terraform_remote_state" "producer" {
  backend = "local"

  config = {
    path = "${var.path}"
  }
}

data "vault_aws_access_credentials" "creds" {
  backend = "${data.terraform_remote_state.producer.outputs.backend}"
  role    = "${data.terraform_remote_state.producer.outputs.role}"
}

provider "aws" {
  access_key = "${data.vault_aws_access_credentials.creds.access_key}"
  secret_key = "${data.vault_aws_access_credentials.creds.secret_key}"
}

data "aws_ami" "ubuntu" {
  most_recent = true

  filter {
    name   = "name"
    values = ["ubuntu/images/hvm-ssd/ubuntu-trusty-14.04-amd64-server-*"]
  }

  filter {
    name   = "virtualization-type"
    values = ["hvm"]
  }

  owners = ["099720109477"] # Canonical
}

# Create AWS EC2 Instance
resource "aws_instance" "main" {
  ami           = "${data.aws_ami.ubuntu.id}"
  instance_type = "t2.nano"

  tags = {
    Name  = "${var.name}"
    TTL   = "${var.ttl}"
    owner = "${var.name}-guide"
  }
}

variable "aws_access_key" { }
variable "aws_secret_key" { }
variable "name"           { default = "dynamic-aws-creds-producer" }

terraform {
  backend "local" {
    path = "terraform.tfstate"
  }
}

provider "vault" {}

resource "vault_aws_secret_backend" "aws" {
  access_key = "${var.aws_access_key}"
  secret_key = "${var.aws_secret_key}"
  path       = "${var.name}-path"

  default_lease_ttl_seconds = "120"
  max_lease_ttl_seconds     = "240"
}

resource "vault_aws_secret_backend_role" "producer" {
  backend = "${vault_aws_secret_backend.aws.path}"
  name    = "${var.name}-role"
  credential_type = "iam_user"

  policy_document = <<EOF
{
  "Version": "2012-10-17",
  "Statement": [
    {
      "Effect": "Allow",
      "Action": [
        "iam:*", "ec2:*"
      ],
      "Resource": "*"
    }
  ]
}
EOF
}

output "backend" {
  value = "${vault_aws_secret_backend.aws.path}"
}

output "role" {
  value = "${vault_aws_secret_backend_role.producer.name}"
}

terraform {
  required_version = ">= 0.11.1"
}

variable "gcp_credentials" {
  description = "GCP credentials needed by google provider"
}

variable "gcp_project" {
  description = "GCP project name"
}

variable "gcp_region" {
  description = "GCP region, e.g. us-east1"
  default = "us-east1"
}

variable "gcp_zone" {
  description = "GCP zone, e.g. us-east1-a"
  default = "us-east1-b"
}

variable "machine_type" {
  description = "GCP machine type"
  default = "n1-standard-1"
}

variable "instance_name" {
  description = "GCP instance name"
  default = "demo"
}

variable "image" {
  description = "image to build instance from"
  default = "debian-cloud/debian-9"
}

provider "google" {
  credentials = "${var.gcp_credentials}"
  project     = "${var.gcp_project}"
  region      = "${var.gcp_region}"
}

resource "google_compute_instance" "demo" {
  name         = "${var.instance_name}"
  machine_type = "${var.machine_type}"
  zone         = "${var.gcp_zone}"

  boot_disk {
    initialize_params {
      image = "${var.image}"
    }
  }

  network_interface {
    network = "default"

    access_config {
      // Ephemeral IP
    }
  }

}

output "external_ip"{
  value = "${google_compute_instance.demo.network_interface.0.access_config.0.nat_ip}"
}

# ── main.tf ──────────────────────────────────────────
resource "tls_private_key" "main" {
  algorithm = "RSA"
}

resource "null_resource" "main" {
  provisioner "local-exec" {
    command = "echo \"${tls_private_key.main.private_key_pem}\" > ${var.private_key_filename}"
  }

  provisioner "local-exec" {
    command = "chmod 600 ${var.private_key_filename}"
  }
}

# ── _interface.tf ──────────────────────────────────────────
# Optional Variables
variable "private_key_filename" {
  default     = "private_key.pem"
  description = "Filename to write the private key data to eg key.pem"
}

# Outputs
output "private_key_pem" {
  value = "${tls_private_key.main.private_key_pem}"
}

output "public_key_data" {
  value = "${tls_private_key.main.public_key_openssh}"
}

# ── main.tf ──────────────────────────────────────────
# Set environment name
resource "random_id" "environment_name" {
  byte_length = 4
  prefix      = "${var.environment_name_prefix}-"
}

provider "google" {
  region = "${var.gcp_region}"
  project = "${var.project_name}"
  credentials = "${file(var.account_file_json)}"
}

module "network-gcp" {
  source           = "git::ssh://git@github.com/hashicorp-modules/network-gcp"
  environment_name = "${random_id.environment_name.hex}"
  os               = "${var.os}"
  os_version       = "${var.os_version}"
  ssh_key_data     = "${module.ssh-keypair-data.public_key_data}"
  ssh_user         = "${var.ssh_user}"
}

module "hashistack-gcp" {
  source           = "git::ssh://git@github.com/hashicorp-modules/hashistack-gcp"
  region           = "${var.gcp_region}"
  project_name     = "${var.project_name}"
  image_bucket_name = "${var.image_bucket_name}"
  account_file_json = "${var.account_file_json}"
  nomad_version     = "${var.nomad_version}"
  vault_version     = "${var.vault_version}"
  consul_version    = "${var.consul_version}"
  environment_name = "${random_id.environment_name.hex}"
  cluster_name     = "${random_id.environment_name.hex}"
  cluster_size     = "${var.cluster_size}"
  os               = "${var.os}"
  os_version       = "${var.os_version}"
  ssh_user         = "${var.ssh_user}"
  ssh_key_data     = "${module.ssh-keypair-data.public_key_data}"
  # Terraform currently does not let you specify a network and subnet which the
  # Google  API requires.  As such this only works in the default network.
  #subnet           = "${module.network-gcp.subnet_private_names[0]}"
  #network          = "${module.network-gcp.network_name}"
  machine_type     = "${var.machine_type}"
  environment      = "${var.environment}"
}

module "ssh-keypair-data" {
  source               = "git::git@github.com:hashicorp-modules/ssh-keypair-data.git"
  private_key_filename = "${random_id.environment_name.hex}"
}

# ── _interface.tf ──────────────────────────────────────────
# Required variables
variable "account_file_json" {
  description = "Path to the JSON file used to authenticate."
}

variable "gcp_region" {
  description = "Region where resources will be provisioned"
}

variable "project_name" {
  description = "The project to install into."
}

variable "image_bucket_name" {
  description = "The bucket that contains the image.  See hashistack.tf for expected path structure."
}

# Optional variables
variable "environment_name_prefix" {
  default     = "hashistack"
  description = "Environment Name prefix eg my-hashistack-env"
}

variable "environment" {
  description = "Prod, test, QA, dev, etc"
  default     = "production"
}

variable "cluster_size" {
  default     = "3"
  description = "Number of instances to launch in the cluster"
}

variable "consul_version" {
  default     = "1.0.0"
  description = "Consul version to use ie 0.8.4"
}

variable "nomad_version" {
  default     = "0.7.0"
  description = "Nomad version to use ie 0.5.6"
}

variable "vault_version" {
  default     = "0.8.3"
  description = "Vault version to use ie 0.7.1"
}

variable "machine_type" {
  default     = "n1-standard-1"
  description = "GCP machine type to use; e.g. n1-standard-1"
}

variable "os" {
  # case sensitive for AMI lookup
  default     = "Ubuntu"
  description = "Operating System to use ie RHEL or Ubuntu"
}

variable "os_version" {
  default     = "16.04"
  description = "Operating System version to use ie 7.3 (for RHEL) or 16.04 (for Ubuntu)"
}

variable "ssh_user" {
  default     = "gcp-user"
  description = "The name of the SSH user to provision."
}

## Outputs
output "network_name" {
  value = "${module.network-gcp.network_name}"
}

output "subnet_public_names" {
  value = ["${module.network-gcp.subnet_public_names}"]
}

output "subnet_private_names" {
  value = ["${module.network-gcp.subnet_private_names}"]
}

output "bastion_username" {
  value = "${module.network-gcp.bastion_username}"
}

output "bastion_ips_public" {
  value = ["${module.network-gcp.bastion_ips_public}"]
}

output "nat_ips_public" {
  value = ["${module.network-gcp.nat_ips_public}"]
}

output "hashistack_instance_group" {
  value = "${module.hashistack-gcp.instance_group_manager}"
}

output "consul_client_firewall" {
  value = "${module.hashistack-gcp.consul_firewall}"
}

output "hashistack_server_firewall" {
  value = "${module.hashistack-gcp.hashistack_server_firewall}"
}

output "ssh_key" {
  value = "${module.ssh-keypair-data.private_key_pem}"
}

output "ssh_user" {
  value = "${var.ssh_user}"
}

# ── main.tf ──────────────────────────────────────────
terraform {
  required_version = ">= 0.11.11"
}

resource "tls_private_key" "ssh_key" {
  algorithm = "RSA"
}

provider "vault" {
  address = "${var.vault_addr}"
}

data "vault_generic_secret" "azure_credentials" {
  path = "secret/${var.vault_user}/azure/credentials"
}

provider "azurerm" {
  subscription_id = "${data.vault_generic_secret.azure_credentials.data["subscription_id"]}"
  tenant_id       = "${data.vault_generic_secret.azure_credentials.data["tenant_id"]}"
  client_id       = "${data.vault_generic_secret.azure_credentials.data["client_id"]}"
  client_secret   = "${data.vault_generic_secret.azure_credentials.data["client_secret"]}"
}

# Azure Resource Group
resource "azurerm_resource_group" "k8sexample" {
  name     = "${var.resource_group_name}"
  location = "${var.azure_location}"
}

# Azure Container Service (AKS) Cluster
resource "azurerm_kubernetes_cluster" "k8sexample" {
  name = "${var.vault_user}-k8sexample-cluster"
  location = "${azurerm_resource_group.k8sexample.location}"
  resource_group_name = "${azurerm_resource_group.k8sexample.name}"
  dns_prefix = "${var.dns_prefix}"
  kubernetes_version = "${var.k8s_version}"

  linux_profile {
    admin_username = "${var.admin_user}"
    ssh_key {
      key_data = "${chomp(tls_private_key.ssh_key.public_key_openssh)}"
    }
  }

  agent_pool_profile {
    name       = "${var.agent_pool_name}"
    count      =  "${var.agent_count}"
    os_type    = "${var.os_type}"
    os_disk_size_gb = "${var.os_disk_size}"
    vm_size    = "${var.vm_size}"
  }

  service_principal {
    client_id     = "${data.vault_generic_secret.azure_credentials.data["client_id"]}"
    client_secret = "${data.vault_generic_secret.azure_credentials.data["client_secret"]}"
  }

  tags {
    Environment = "${var.environment}"
  }
}

# ── variables.tf ──────────────────────────────────────────
variable "resource_group_name" {
  description = "Azure Resource Group Name"
}

variable "azure_location" {
  description = "Azure Location, e.g. North Europe"
  default = "East US"
}

variable "dns_prefix" {
  description = "DNS prefix for your cluster"
}

variable "k8s_version" {
  description = "Version of Kubernetes to use"
  default = "1.12.7"
}

variable "admin_user" {
  description = "Administrative username for the VMs"
  default = "azureuser"
}

variable "agent_pool_name" {
  description = "Name of the K8s agent pool"
  default = "default"
}

variable "agent_count" {
  description = "Number of agents to create"
  default = 1
}

variable "vm_size" {
  description = "Azure VM type"
  default = "Standard_D2"
}

variable "os_type" {
  description = "OS type for agents: Windows or Linux"
  default = "Linux"
}

variable "os_disk_size" {
  description = "OS disk size in GB"
  default = "30"
}

variable "environment" {
  description = "value passed to Environment tag and used in name of Vault k8s auth backend in the associated k8s-vault-config workspace"
  default = "aks-dev"
}

variable "vault_user" {
  description = "Vault userid: determines location of secrets and affects path of k8s auth backend that is created in the associated k8s-vault-config workspace"
}

variable "vault_addr" {
  description = "Address of Vault server including port that is used in the associated k8s-vault-config and k8s-services workspaces"
}

# ── outputs.tf ──────────────────────────────────────────
output "private_key_pem" {
  value = "${chomp(tls_private_key.ssh_key.private_key_pem)}"
}

output "k8s_id" {
  value = "${azurerm_kubernetes_cluster.k8sexample.id}"
}

output "k8s_endpoint" {
  value = "${azurerm_kubernetes_cluster.k8sexample.fqdn}"
}

output "k8s_master_auth_client_certificate" {
  value = "${azurerm_kubernetes_cluster.k8sexample.kube_config.0.client_certificate}"
}

output "k8s_master_auth_client_key" {
  value = "${azurerm_kubernetes_cluster.k8sexample.kube_config.0.client_key}"
}

output "k8s_master_auth_cluster_ca_certificate" {
  value = "${azurerm_kubernetes_cluster.k8sexample.kube_config.0.cluster_ca_certificate}"
}

output "environment" {
  value = "${var.environment}"
}

output "vault_user" {
  value = "${var.vault_user}"
}

output "vault_addr" {
  value = "${var.vault_addr}"
}

# ── main.tf ──────────────────────────────────────────
terraform {
  required_version = ">= 0.11.11"
}

provider "vault" {
  address = "${var.vault_addr}"
}

data "vault_generic_secret" "gcp_credentials" {
  path = "secret/${var.vault_user}/gcp/credentials"
}

provider "google" {
  credentials = "${data.vault_generic_secret.gcp_credentials.data[var.gcp_project]}"
  project     = "${var.gcp_project}"
  region      = "${var.gcp_region}"
}

resource "google_container_cluster" "k8sexample" {
  name               = "${var.vault_user}-k8s-cluster"
  description        = "example k8s cluster"
  zone               = "${var.gcp_zone}"
  initial_node_count = "${var.initial_node_count}"
  enable_kubernetes_alpha = "true"
  enable_legacy_abac = "true"

  master_auth {
    username = "${var.master_username}"
    password = "${var.master_password}"

    client_certificate_config {
      issue_client_certificate = true
    }
  }

  node_config {
    machine_type = "${var.node_machine_type}"
    disk_size_gb = "${var.node_disk_size}"
    oauth_scopes = [
      "https://www.googleapis.com/auth/compute",
      "https://www.googleapis.com/auth/devstorage.read_only",
      "https://www.googleapis.com/auth/logging.write",
      "https://www.googleapis.com/auth/monitoring"
    ]
  }
}

# ── variables.tf ──────────────────────────────────────────
variable "gcp_region" {
  description = "GCP region, e.g. us-east1"
  default = "us-east1"
}

variable "gcp_zone" {
  description = "GCP zone, e.g. us-east1-b (which must be in gcp_region)"
  default = "us-east1-b"
}

variable "gcp_project" {
  description = "GCP project name"
}

variable "initial_node_count" {
  description = "Number of worker VMs to initially create"
  default = 1
}

variable "master_username" {
  description = "Username for accessing the Kubernetes master endpoint"
  default = "k8smaster"
}

variable "master_password" {
  description = "Password for accessing the Kubernetes master endpoint"
  default = "k8smasterk8smaster"
}

variable "node_machine_type" {
  description = "GCE machine type"
  default = "n1-standard-1"
}

variable "node_disk_size" {
  description = "Node disk size in GB"
  default = "20"
}

variable "environment" {
  description = "value passed to Environment tag and used in name of Vault auth backend later"
  default = "gke-dev"
}

variable "vault_user" {
  description = "Vault userid: determines location of secrets and affects path of k8s auth backend"
}

variable "vault_addr" {
  description = "Address of Vault server including port"
}

# ── outputs.tf ──────────────────────────────────────────
output "k8s_endpoint" {
  value = "${google_container_cluster.k8sexample.endpoint}"
}

output "k8s_master_version" {
  value = "${google_container_cluster.k8sexample.master_version}"
}

output "k8s_instance_group_urls" {
  value = "${google_container_cluster.k8sexample.instance_group_urls.0}"
}

output "k8s_master_auth_client_certificate" {
  value = "${google_container_cluster.k8sexample.master_auth.0.client_certificate}"
}

output "k8s_master_auth_client_key" {
  value = "${google_container_cluster.k8sexample.master_auth.0.client_key}"
}

output "k8s_master_auth_cluster_ca_certificate" {
  value = "${google_container_cluster.k8sexample.master_auth.0.cluster_ca_certificate}"
}

output "environment" {
  value = "${var.environment}"
}

output "vault_user" {
  value = "${var.vault_user}"
}

output "vault_addr" {
  value = "${var.vault_addr}"
}

# ── main.tf ──────────────────────────────────────────
terraform {
  required_version = ">= 0.11.11"
}

# Set VAULT_TOKEN environment variable
provider "vault" {
  address = "${var.vault_addr}"
  max_lease_ttl_seconds = 7200
}

# AWS credentials from Vault
# Must set up AWS backend in Vault on path aws with role deploy
data "vault_aws_access_credentials" "aws_creds" {
  backend = "aws-tf"
  role = "deploy"
}

# Insert 15 second delay so AWS credentials definitely available
# at all AWS endpoints
data "external" "region" {
  # Delay so that new keys are available across AWS
  program = ["./delay-vault-aws", "${var.region}"]
}

# Vault Kubernetes Auth Backend
resource "vault_auth_backend" "k8s" {
  type = "kubernetes"
  path = "${var.vault_k8s_auth_path}"
  description = "Vault Auth Backend for OpenShift"
}

#  Setup the core provider information.
provider "aws" {
  access_key = "${data.vault_aws_access_credentials.aws_creds.access_key}"
  secret_key = "${data.vault_aws_access_credentials.aws_creds.secret_key}"
  region  = "${data.external.region.result["region"]}"
  version = "~> 2.0"
}

#  Create the OpenShift cluster using our module.
module "openshift" {
  source          = "./modules/openshift"
  region          = "${var.region}"
  amisize         = "t2.large" //  Smallest that meets OS specs
  vpc_cidr        = "${var.vpc_cidr}"
  subnet_cidr     = "${var.subnet_cidr}"
  subnetaz        = "${var.subnetaz}"
  key_name        = "${var.key_name}"
  private_key_data = "${var.private_key_data}"
  name_tag_prefix = "${var.vault_user}"
  owner           = "${var.owner}"
  ttl             = "${var.ttl}"
}

resource "null_resource" "post-install-master" {
  provisioner "remote-exec" {
    script = "${path.root}/scripts/postinstall-master.sh"
    connection {
      host = "${module.openshift.master_public_dns}"
      type = "ssh"
      agent = false
      user = "ec2-user"
      private_key = "${var.private_key_data}"
      bastion_host = "${module.openshift.bastion_public_dns}"
    }
  }
}

resource "null_resource" "post-install-node1" {
  provisioner "remote-exec" {
    script = "${path.root}/scripts/postinstall-node.sh"
    connection {
      host = "${module.openshift.node1_public_dns}"
      type = "ssh"
      agent = false
      user = "ec2-user"
      private_key = "${var.private_key_data}"
      bastion_host = "${module.openshift.bastion_public_dns}"
    }
  }
}

resource "null_resource" "get_config" {
  provisioner "remote-exec" {
    inline = [
      "scp -o StrictHostKeyChecking=no -i ~/.ssh/private-key.pem ec2-user@${module.openshift.master_public_dns}:~/.kube/config ~/config"
    ]

    connection {
      host = "${module.openshift.bastion_public_dns}"
      type = "ssh"
      agent = false
      user = "ec2-user"
      private_key = "${var.private_key_data}"
    }
  }

  provisioner "local-exec" {
    command = "echo \"${var.private_key_data}\" > private-key.pem"
  }

  provisioner "local-exec" {
    command = "chmod 400 private-key.pem"
  }

  provisioner "local-exec" {
    command = "scp -o StrictHostKeyChecking=no -i private-key.pem  ec2-user@${module.openshift.bastion_public_dns}:~/config config"
  }
  provisioner "local-exec" {
    command = "sed -n 4,4p config | cut -d ':' -f 2 | sed 's/ //' > ca_certificate"
  }
  provisioner "local-exec" {
    command = "sed -n 28,28p config | cut -d ':' -f 2 | sed 's/ //' > client_certificate"
  }
  provisioner "local-exec" {
    command = "sed -n 29,29p config | cut -d ':' -f 2 | sed 's/ //' > client_key"
  }

  depends_on = ["null_resource.post-install-master"]
}

resource "null_resource" "configure_k8s" {
  provisioner "file" {
    source = "vault-reviewer.yaml"
    destination = "~/vault-reviewer.yaml"
  }

  provisioner "file" {
    source = "vault-reviewer-rbac.yaml"
    destination = "~/vault-reviewer-rbac.yaml"
  }

  provisioner "remote-exec" {
    inline = [
      "sleep 180",
      "kubectl create -f vault-reviewer.yaml",
      "kubectl create -f vault-reviewer-rbac.yaml",
      "kubectl get serviceaccount vault-reviewer -o yaml > vault-reviewer-service.yaml",
      "kubectl get secret $(grep \"vault-reviewer-token\" vault-reviewer-service.yaml | cut -d ':' -f 2 | sed 's/ //') -o yaml > vault-reviewer-secret.yaml",
      "sed -n 6,6p vault-reviewer-secret.yaml | cut -d ':' -f 2 | sed 's/ //' | base64 -d > vault-reviewer-token"
    ]
  }

  connection {
    host = "${module.openshift.master_public_dns}"
    type = "ssh"
    agent = false
    user = "ec2-user"
    private_key = "${var.private_key_data}"
    bastion_host = "${module.openshift.bastion_public_dns}"
  }

  depends_on = ["null_resource.get_config"]

}

resource "null_resource" "get_vault_reviewer_token" {
  provisioner "remote-exec" {
    inline = [
      "scp -o StrictHostKeyChecking=no -i ~/.ssh/private-key.pem ec2-user@${module.openshift.master_public_dns}:~/vault-reviewer-token vault-reviewer-token"
    ]

    connection {
      host = "${module.openshift.bastion_public_dns}"
      type = "ssh"
      agent = false
      user = "ec2-user"
      private_key = "${var.private_key_data}"
    }
  }

  provisioner "local-exec" {
    command = "scp -o StrictHostKeyChecking=no -i private-key.pem  ec2-user@${module.openshift.bastion_public_dns}:~/vault-reviewer-token vault-reviewer-token"
  }

  depends_on = ["null_resource.configure_k8s"]
}

data "null_data_source" "get_certs" {
  inputs = {
    client_certificate = "${file("client_certificate")}"
    client_key = "${file("client_key")}"
    ca_certificate = "${file("ca_certificate")}"
    vault_reviewer_token = "${file("vault-reviewer-token")}"
  }
  depends_on = ["null_resource.get_vault_reviewer_token"]
}

# Use the vault_kubernetes_auth_backend_config resource
# instead of the a curl command in local-exec
resource "vault_kubernetes_auth_backend_config" "auth_config" {
  backend = "${vault_auth_backend.k8s.path}"
  kubernetes_host = "https://${module.openshift.master_public_ip}.xip.io:8443"
  kubernetes_ca_cert = "${chomp(base64decode(data.null_data_source.get_certs.outputs["ca_certificate"]))}"
  token_reviewer_jwt = "${data.null_data_source.get_certs.outputs["vault_reviewer_token"]}"
}

# Use vault_kubernetes_auth_backend_role instead of
# vault_generic_secret
resource "vault_kubernetes_auth_backend_role" "role" {
  backend = "${vault_auth_backend.k8s.path}"
  role_name = "demo"
  bound_service_account_names = ["cats-and-dogs"]
  bound_service_account_namespaces = ["default", "cats-and-dogs"]
  token_policies = ["${var.vault_user}"]
  token_ttl = 7200
}

# ── variables.tf ──────────────────────────────────────────
//  The region we will deploy our cluster into.
variable "region" {
  description = "Region to deploy the cluster into"
  default = "us-east-1"
}

variable "key_name" {
  description = "The name of the key to user for ssh access"
}

variable "private_key_data" {
  description = "contents of the private key"
}

variable "vpc_cidr" {
  description = "VPC CIDR"
  default = "10.0.0.0/16"
}

variable "subnet_cidr" {
  description = "Subnet CIDR"
  default = "10.0.1.0/24"
}

//  This map defines which AZ to put the 'Public Subnet' in, based on the
//  region defined. You will typically not need to change this unless
//  you are running in a new region!
variable "subnetaz" {
  type = "map"

  default = {
    us-east-1 = "us-east-1a"
    us-east-2 = "us-east-2a"
    us-west-1 = "us-west-1a"
    us-west-2 = "us-west-2a"
    eu-west-1 = "eu-west-1a"
    eu-west-2 = "eu-west-2a"
    eu-central-1 = "eu-central-1a"
    ap-southeast-1 = "ap-southeast-1a"
  }
}

variable "owner" {
  description = "value set on EC2 owner tag"
  default = ""
}

variable "ttl" {
  description = "value set on EC2 TTL tag. -1 means forever. Measured in hours."
  default = "-1"
}

variable "vault_k8s_auth_path" {
  description = "The path of the Vault k8s auth backend"
  default = "openshift"
}

variable "vault_user" {
  description = "Vault userid: determines location of secrets and affects path of k8s auth backend"
}

variable "vault_addr" {
  description = "Address of Vault server including port"
}

# ── outputs.tf ──────────────────────────────────────────
# Output some useful variables for quick SSH access etc.
output "master_url" {
  value = "https://${module.openshift.master_public_ip}.xip.io:8443"
}
output "master_public_dns" {
  value = "${module.openshift.master_public_dns}"
}
output "master_public_ip" {
  value = "${module.openshift.master_public_ip}"
}
output "master_private_ip" {
  value = "${module.openshift.master_private_ip}"
}
output "bastion_public_dns" {
  value = "${module.openshift.bastion_public_dns}"
}
output "bastion_public_ip" {
  value = "${module.openshift.bastion_public_ip}"
}

output "k8s_endpoint" {
  value = "https://${module.openshift.master_public_ip}.xip.io:8443"
}

output "k8s_master_auth_client_certificate" {
  value = "${data.null_data_source.get_certs.outputs["client_certificate"]}"
}

output "k8s_master_auth_client_key" {
  value = "${data.null_data_source.get_certs.outputs["client_key"]}"
}

output "k8s_master_auth_cluster_ca_certificate" {
  value = "${data.null_data_source.get_certs.outputs["ca_certificate"]}"
}

output "vault_k8s_auth_backend" {
  value = "${vault_auth_backend.k8s.path}"
}

output "vault_user" {
  value = "${var.vault_user}"
}

output "vault_addr" {
  value = "${var.vault_addr}"
}

# ── 00-variables.tf ──────────────────────────────────────────
variable "region" {
  description = "The region to deploy the cluster in, e.g: us-east-1."
}

variable "amisize" {
  description = "The size of the cluster nodes, e.g: t2.large. Note that OpenShift will not run on anything smaller than t2.large"
}

variable "vpc_cidr" {
  description = "The CIDR block for the VPC, e.g: 10.0.0.0/16"
}

variable "subnetaz" {
  description = "The AZ for the public subnet, e.g: us-east-1a"
  type = "map"
}

variable "subnet_cidr" {
  description = "The CIDR block for the public subnet, e.g: 10.0.1.0/24"
}

variable "key_name" {
  description = "The name of the key to user for ssh access"
}

variable "private_key_data" {
  description = "contents of the private key"
}

variable "name_tag_prefix" {
  description = "prefixed to Name tag added to EC2 instances and other AWS resources"
}

variable "owner" {
  description = "value set on EC2 owner tag"
}

variable "ttl" {
  description = "value set on EC2 TTL tag. -1 means forever. Measured in hours."
}

# ── 01-amis.tf ──────────────────────────────────────────
# Define the RHEL 7.2 AMI by:
# RedHat, Latest, x86_64, EBS, HVM, RHEL 7.5
data "aws_ami" "rhel7_5" {
  most_recent = true

  owners = ["309956199498"] // Red Hat's account ID.

  filter {
    name   = "architecture"
    values = ["x86_64"]
  }

  filter {
    name   = "root-device-type"
    values = ["ebs"]
  }

  filter {
    name   = "virtualization-type"
    values = ["hvm"]
  }

  filter {
    name   = "name"
    values = ["RHEL-7.5*"]
  }
}

# Define an Amazon Linux AMI.
data "aws_ami" "amazonlinux" {
  most_recent = true

  owners = ["137112412989"]

  filter {
    name   = "architecture"
    values = ["x86_64"]
  }

  filter {
    name   = "root-device-type"
    values = ["ebs"]
  }

  filter {
    name   = "virtualization-type"
    values = ["hvm"]
  }

  filter {
    name   = "name"
    values = ["amzn-ami-hvm-2018.03.0.20190611-x86_64-gp2"]
  }
}

# ── 02-vpc.tf ──────────────────────────────────────────
//  Define the VPC.
resource "aws_vpc" "openshift" {
  cidr_block           = "${var.vpc_cidr}"
  enable_dns_hostnames = true

  tags {
    Name    = "${var.name_tag_prefix}-openshift VPC"
    Project = "openshift"
  }
}

//  Create an Internet Gateway for the VPC.
resource "aws_internet_gateway" "openshift" {
  vpc_id = "${aws_vpc.openshift.id}"

  tags {
    Name    = "${var.name_tag_prefix}-openshift IGW"
    Project = "openshift"
  }
}

//  Create a public subnet.
resource "aws_subnet" "public-subnet" {
  vpc_id                  = "${aws_vpc.openshift.id}"
  cidr_block              = "${var.subnet_cidr}"
  availability_zone       = "${lookup(var.subnetaz, var.region)}"
  map_public_ip_on_launch = true
  depends_on              = ["aws_internet_gateway.openshift"]

  tags {
    Name    = "${var.name_tag_prefix}-openshift Public Subnet"
    Project = "openshift"
  }
}

//  Create a route table allowing all addresses access to the IGW.
resource "aws_route_table" "public" {
  vpc_id = "${aws_vpc.openshift.id}"

  route {
    cidr_block = "0.0.0.0/0"
    gateway_id = "${aws_internet_gateway.openshift.id}"
  }

  tags {
    Name    = "${var.name_tag_prefix}-openshift Public Route Table"
    Project = "openshift"
  }
}

//  Now associate the route table with the public subnet - giving
//  all public subnet instances access to the internet.
resource "aws_route_table_association" "public-subnet" {
  subnet_id      = "${aws_subnet.public-subnet.id}"
  route_table_id = "${aws_route_table.public.id}"
}

# ── 03-security-groups.tf ──────────────────────────────────────────
//  This security group allows intra-node communication on all ports with all
//  protocols.
resource "aws_security_group" "openshift-vpc" {
  name        = "${var.name_tag_prefix}-openshift-vpc"
  description = "Default security group that allows all instances in the VPC to talk to each other over any port and protocol."
  vpc_id      = "${aws_vpc.openshift.id}"

  ingress {
    from_port = "0"
    to_port   = "0"
    protocol  = "-1"
    self      = true
  }

  egress {
    from_port = "0"
    to_port   = "0"
    protocol  = "-1"
    self      = true
  }

  tags {
    Name    = "OpenShift Internal VPC"
    Project = "openshift"
  }
}

//  This security group allows public ingress to the instances for HTTP, HTTPS
//  and common HTTP/S proxy ports.
resource "aws_security_group" "openshift-public-ingress" {
  name        = "${var.name_tag_prefix}-openshift-public-ingress"
  description = "Security group that allows public ingress to instances, HTTP, HTTPS and more."
  vpc_id      = "${aws_vpc.openshift.id}"

  //  HTTP
  ingress {
    from_port   = 80
    to_port     = 80
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  //  HTTP Proxy
  ingress {
    from_port   = 8080
    to_port     = 8080
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  //  HTTPS
  ingress {
    from_port   = 443
    to_port     = 443
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  //  HTTPS Proxy
  ingress {
    from_port   = 8443
    to_port     = 8443
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags {
    Name    = "OpenShift Public Access"
    Project = "openshift"
  }
}

//  This security group allows public egress from the instances for HTTP and
//  HTTPS, which is needed for yum updates, git access etc etc.
// Also for Vault on port 8200
resource "aws_security_group" "openshift-public-egress" {
  name        = "${var.name_tag_prefix}-openshift-public-egress"
  description = "Security group that allows egress to the internet for instances over HTTP and HTTPS."
  vpc_id      = "${aws_vpc.openshift.id}"

  //  HTTP
  egress {
    from_port   = 80
    to_port     = 80
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  //  HTTPS
  egress {
    from_port   = 443
    to_port     = 443
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  //  Vault
  egress {
    from_port   = 8200
    to_port     = 8200
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags {
    Name    = "OpenShift Public Access"
    Project = "openshift"
  }
}

//  Security group which allows SSH access to a host. Used for the bastion.
resource "aws_security_group" "openshift-ssh" {
  name        = "${var.name_tag_prefix}-openshift-ssh"
  description = "Security group that allows public ingress over SSH."
  vpc_id      = "${aws_vpc.openshift.id}"

  //  SSH
  ingress {
    from_port   = 22
    to_port     = 22
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags {
    Name    = "OpenShift SSH Access"
    Project = "openshift"
  }
}

# ── 04-roles.tf ──────────────────────────────────────────
//  Create a role which OpenShift instances will assume.
//  This role has a policy saying it can be assumed by ec2
//  instances.
resource "aws_iam_role" "openshift-instance-role" {
  name = "${var.name_tag_prefix}-openshift-instance-role"

  assume_role_policy = <<EOF
{
    "Version": "2012-10-17",
    "Statement": [
        {
            "Action": "sts:AssumeRole",
            "Principal": {
                "Service": "ec2.amazonaws.com"
            },
            "Effect": "Allow",
            "Sid": ""
        }
    ]
}
EOF
}

//  This policy allows an instance to forward logs to CloudWatch, and
//  create the Log Stream or Log Group if it doesn't exist.
resource "aws_iam_policy" "openshift-policy-forward-logs" {
  name        = "${var.name_tag_prefix}-openshift-instance-forward-logs"
  path        = "/"
  description = "Allows an instance to forward logs to CloudWatch"

  policy = <<EOF
{
  "Version": "2012-10-17",
  "Statement": [
    {
      "Effect": "Allow",
      "Action": [
        "logs:CreateLogGroup",
        "logs:CreateLogStream",
        "logs:PutLogEvents",
        "logs:DescribeLogStreams"
    ],
      "Resource": [
        "arn:aws:logs:*:*:*"
    ]
  }
 ]
}
EOF
}

//  Attach the policies to the role.
resource "aws_iam_policy_attachment" "openshift-attachment-forward-logs" {
  name       = "${var.name_tag_prefix}-openshift-attachment-forward-logs"
  roles      = ["${aws_iam_role.openshift-instance-role.name}"]
  policy_arn = "${aws_iam_policy.openshift-policy-forward-logs.arn}"
}

//  Create a instance profile for the role.
resource "aws_iam_instance_profile" "openshift-instance-profile" {
  name  = "${var.name_tag_prefix}-openshift-instance-profile"
  role = "${aws_iam_role.openshift-instance-role.name}"
}

# ── 05-nodes.tf ──────────────────────────────────────────
//  Create the master userdata script.
data "template_file" "setup-master" {
  template = "${file("${path.module}/files/setup-master.sh")}"

  //  Currently, no vars needed.
}

//  Launch configuration for the master
resource "aws_instance" "master" {
  ami                  = "${data.aws_ami.rhel7_5.id}"
  # Master nodes require at least 16GB of memory.
  instance_type        = "m4.xlarge"
  subnet_id            = "${aws_subnet.public-subnet.id}"
  iam_instance_profile = "${aws_iam_instance_profile.openshift-instance-profile.id}"
  user_data            = "${data.template_file.setup-master.rendered}"

  vpc_security_group_ids = [
    "${aws_security_group.openshift-vpc.id}",
    "${aws_security_group.openshift-public-ingress.id}",
    "${aws_security_group.openshift-public-egress.id}",
  ]

  //  We need at least 30GB for OpenShift, let's be greedy...
  root_block_device {
    volume_size = 50
  }

  # Storage for Docker, see:
  # https://docs.openshift.org/latest/install_config/install/host_preparation.html#configuring-docker-storage
  ebs_block_device {
    device_name = "/dev/sdf"
    volume_size = 80
  }

  key_name = "${var.key_name}"

  tags {
    Name    = "${var.name_tag_prefix} OpenShift Master"
    Project = "openshift"
    owner = "${var.owner}"
    TTL = "${var.ttl}"
  }
}

//  Create the node userdata script.
data "template_file" "setup-node" {
  template = "${file("${path.module}/files/setup-node.sh")}"

  //  Currently, no vars needed.
}

//  Create the two nodes.
resource "aws_instance" "node1" {
  ami                  = "${data.aws_ami.rhel7_5.id}"
  instance_type        = "${var.amisize}"
  subnet_id            = "${aws_subnet.public-subnet.id}"
  iam_instance_profile = "${aws_iam_instance_profile.openshift-instance-profile.id}"
  user_data            = "${data.template_file.setup-node.rendered}"

  vpc_security_group_ids = [
    "${aws_security_group.openshift-vpc.id}",
    "${aws_security_group.openshift-public-ingress.id}",
    "${aws_security_group.openshift-public-egress.id}",
  ]

  //  We need at least 30GB for OpenShift, let's be greedy...
  root_block_device {
    volume_size = 50
  }

  # Storage for Docker, see:
  # https://docs.openshift.org/latest/install_config/install/host_preparation.html#configuring-docker-storage
  ebs_block_device {
    device_name = "/dev/sdf"
    volume_size = 80
  }

  key_name = "${var.key_name}"

  tags {
    Name    = "${var.name_tag_prefix} OpenShift Node 1"
    Project = "openshift"
    owner = "${var.owner}"
    TTL = "${var.ttl}"
  }
}

# ── 06-dns.tf ──────────────────────────────────────────
//  Notes: We could make the internal domain a variable, but not sure it is
//  really necessary.

//  Create the internal DNS.
resource "aws_route53_zone" "internal" {
  name = "${var.name_tag_prefix}-openshift.local"
  comment = "OpenShift Cluster Internal DNS"
  vpc {
    vpc_id = "${aws_vpc.openshift.id}"
  }
  tags {
    Name    = "OpenShift Internal DNS"
    Project = "openshift"
  }
}

//  Routes for 'master' and 'node1'.
resource "aws_route53_record" "master-a-record" {
    zone_id = "${aws_route53_zone.internal.zone_id}"
    name = "master.${var.name_tag_prefix}-openshift.local"
    type = "A"
    ttl  = 300
    records = [
        "${aws_instance.master.private_ip}"
    ]
}
resource "aws_route53_record" "node1-a-record" {
    zone_id = "${aws_route53_zone.internal.zone_id}"
    name = "node1.${var.name_tag_prefix}-openshift.local"
    type = "A"
    ttl  = 300
    records = [
        "${aws_instance.node1.private_ip}"
    ]
}

# ── 07-bastion.tf ──────────────────────────────────────────
data "external" "delay" {
  program = ["./modules/openshift/delay-aws"]

  depends_on = ["aws_instance.master", "aws_instance.node1"]
}

data "template_file" "inventory" {
  template = "${file("${path.module}/files/install-from-bastion.sh")}"

  vars {
    wait = "${data.external.delay.result["wait"]}"
    master_ip = "${aws_instance.master.public_ip}"
    private_key = "${var.private_key_data}"
    name_tag_prefix = "${var.name_tag_prefix}"
    region = "${var.region}"
  }
}

resource "local_file" "inventory" {
  content = "${data.template_file.inventory.rendered}"
  filename = "${path.module}/files/install-openshift.sh"
}

//  Launch configuration for the bastion.
resource "aws_instance" "bastion" {
  ami                  = "${data.aws_ami.amazonlinux.id}"
  instance_type        = "t2.micro"
  subnet_id            = "${aws_subnet.public-subnet.id}"

  vpc_security_group_ids = [
    "${aws_security_group.openshift-vpc.id}",
    "${aws_security_group.openshift-ssh.id}",
    "${aws_security_group.openshift-public-egress.id}",
  ]

  key_name = "${var.key_name}"

  tags {
    Name    = "${var.name_tag_prefix} OpenShift Bastion"
    Project = "openshift"
    owner = "${var.owner}"
    TTL = "${var.ttl}"
  }

  provisioner "remote-exec" {
    script = "${local_file.inventory.filename}"
    on_failure = "continue"
    connection {
      type     = "ssh"
      user     = "ec2-user"
      private_key = "${var.private_key_data}"
    }
  }
}

# ── 08-outputs.tf ──────────────────────────────────────────
//  Output some useful variables for quick SSH access etc.
output "master_public_dns" {
  value = "${aws_instance.master.public_dns}"
}
output "master_public_ip" {
  value = "${aws_instance.master.public_ip}"
}
output "master_private_dns" {
  value = "${aws_instance.master.private_dns}"
}
output "master_private_ip" {
  value = "${aws_instance.master.private_ip}"
}

output "node1_public_dns" {
  value = "${aws_instance.node1.public_dns}"
}
output "node1_public_ip" {
  value = "${aws_instance.node1.public_ip}"
}
output "node1_private_dns" {
  value = "${aws_instance.node1.private_dns}"
}
output "node1_private_ip" {
  value = "${aws_instance.node1.private_ip}"
}

output "bastion_public_dns" {
  value = "${aws_instance.bastion.public_dns}"
}
output "bastion_public_ip" {
  value = "${aws_instance.bastion.public_ip}"
}
output "bastion_private_dns" {
  value = "${aws_instance.bastion.private_dns}"
}
output "bastion_private_ip" {
  value = "${aws_instance.bastion.private_ip}"
}

# ── main.tf ──────────────────────────────────────────
terraform {
  required_version = ">= 0.11.11"
}

resource "vault_auth_backend" "k8s" {
  type = "kubernetes"
  path = "${data.terraform_remote_state.k8s_cluster.vault_user}-${data.terraform_remote_state.k8s_cluster.environment}"
  description = "Vault Auth backend for Kubernetes"
}

provider "vault" {
  address = "${data.terraform_remote_state.k8s_cluster.vault_addr}"
}

data "terraform_remote_state" "k8s_cluster" {
  backend = "atlas"
  config {
    name = "${var.tfe_organization}/${var.k8s_cluster_workspace}"
  }
}

provider "kubernetes" {
  host = "${data.terraform_remote_state.k8s_cluster.k8s_endpoint}"
  client_certificate = "${base64decode(data.terraform_remote_state.k8s_cluster.k8s_master_auth_client_certificate)}"
  client_key = "${base64decode(data.terraform_remote_state.k8s_cluster.k8s_master_auth_client_key)}"
  cluster_ca_certificate = "${base64decode(data.terraform_remote_state.k8s_cluster.k8s_master_auth_cluster_ca_certificate)}"
}

resource "kubernetes_service_account" "vault_reviewer" {
  metadata {
    name = "vault-reviewer"
  }
}

data "kubernetes_secret" "vault_reviewer_token" {
  metadata {
    name = "${kubernetes_service_account.vault_reviewer.default_secret_name}"
  }
}

resource "null_resource" "write_token" {
  provisioner "local-exec" {
    command = "echo ${data.kubernetes_secret.vault_reviewer_token.data.token} > vault-reviewer-token"
  }
}

data "null_data_source" "read_token" {
  inputs = {
    token = "${chomp(file("vault-reviewer-token"))}"
  }
  depends_on = ["null_resource.write_token"]
}

# Use the vault_kubernetes_auth_backend_config resource
# instead of the a curl command in local-exec
resource "vault_kubernetes_auth_backend_config" "auth_config" {
  backend = "${vault_auth_backend.k8s.path}"
  kubernetes_host = "https://${data.terraform_remote_state.k8s_cluster.k8s_endpoint}:443"
  kubernetes_ca_cert = "${chomp(base64decode(data.terraform_remote_state.k8s_cluster.k8s_master_auth_cluster_ca_certificate))}"
  token_reviewer_jwt = "${data.null_data_source.read_token.outputs["token"]}"
}

# Use vault_kubernetes_auth_backend_role instead of
# vault_generic_secret
resource "vault_kubernetes_auth_backend_role" "role" {
  backend = "${vault_auth_backend.k8s.path}"
  role_name = "demo"
  bound_service_account_names = ["cats-and-dogs"]
  bound_service_account_namespaces = ["default", "cats-and-dogs"]
  policies = ["${data.terraform_remote_state.k8s_cluster.vault_user}"]
  ttl = 7200
}

