# ── terraform.tf ──────────────────────────────────────────
terraform {
  required_providers {
    local = {
      source  = "hashicorp/local"
      version = "~>2.0"
    }
  }
}

variable "my_str" {
    type = string

    default = "my-string"
}

variable "complex_object" {
    type = list(object({
        name = string
        start_port = number
        end_port = number
        protocol = string
    }))

    default = [
        {
            name = "http"
            start_port = 80
            end_port = 80
            protocol = "tcp"
        }
    ]
}

output "complex_output" {
    value = var.complex_object
}

variable "my_str" {
    type = string

    validation {
        condition = length(var.my_str) > 3
        error_message = "String must be over 3 characters in length."
    }
    default = "my-string"
}

output "my_str" {
    value = var.my_str
}

data "external" "example" {
  program = ["powershell.exe", "./program.ps1"]

  query = {
    # arbitrary map from strings to strings, passed
    # to the external program as the data query.
    name = "Ned"
  }
}

output "result" {
    value = data.external.example.result["Message"]
}

data "http" "my_ip" {
  url = "http://ifconfig.me"
}

output "my_ip" {
    value = data.http.my_ip.body
}

output "response_header" {
    value = data.http.my_ip.response_headers
}

output "response_date" {
    value = data.http.my_ip.response_headers["Date"]
}

