###########################
# CONFIGURATION
###########################

terraform {
  required_providers {
    azurerm = {
      source  = "hashicorp/azurerm"
      version = "~> 2.0"

    }
  }
}

###########################
# VARIABLES
###########################

variable "region" {
  type        = string
  description = "Region in Azure"
  default     = "eastus"
}

variable "prefix" {
  type        = string
  description = "prefix for naming"
  default     = "tacos"
}

###########################
# PROVIDERS
###########################

provider "azurerm" {
  features {}
}

###########################
# DATA SOURCES
###########################

locals {
  name = "${var.prefix}-demo"
}

###########################
# RESOURCES
###########################

resource "azurerm_resource_group" "vnet" {
  name     = local.name
  location = var.region
}

module "network" {
  source              = "Azure/network/azurerm"
  version             = "3.1.1"
  resource_group_name = azurerm_resource_group.vnet.name
  vnet_name           = local.name
  address_space       = "10.0.0.0/16"
  subnet_prefixes     = ["10.0.1.0/24", "10.0.2.0/24", "10.0.3.0/24"]
  subnet_names        = ["subnet1", "subnet2", "subnet3"]

  tags = {
    environment = "dev"
    costcenter  = "it"
    day         = "tuesday"
    viewer      = "robert"
  }

  depends_on = [azurerm_resource_group.vnet]
}

variable "vault_aws_backend" {
    type = string
    description = "path to aws secrets engine"
    default = "aws"
}

variable "vault_aws_role" {
    type = string
    description = "name of aws role for credentials"
    default = "ec2-admin"
}

provider "vault" {
}

data "vault_generic_secret" "appkey" {
  path = "secret/appkey"
}

data "vault_aws_access_credentials" "creds" {
  backend = var.vault_aws_backend
  role    = var.vault_aws_role
  type = "sts"
}

output "data_json" {
    value = data.vault_generic_secret.appkey.data_json
}

output "vault_aws_creds" {
    value = data.vault_aws_access_credentials.creds
}

