  type    = list(string)
  default = ["10.0.0.0/24", "10.0.1.0/24"]
}

variable "vpc2_cidr_range" {
  type    = string
  default = "10.1.0.0/16"
}

variable "vpc2_public_subnets" {
  type    = list(string)
  default = ["10.1.0.0/24", "10.1.1.0/24"]
}

