# PROVIDERS
#############################################################################

provider "aws" {
  version = "~> 2.0"
  region  = var.region_1
}

provider "aws" {
  version = "~> 2.0"
  region  = var.region_2
  alias = "region2"
}

#############################################################################
# DATA SOURCES
#############################################################################

data "aws_availability_zones" "azs_1" {}

data "aws_availability_zones" "azs_2" {
    provider = aws.region2
}

#############################################################################
# RESOURCES
#############################################################################

module "vpc1" {
  source  = "terraform-aws-modules/vpc/aws"
  version = "2.64.0"

  name = "vpc1"
  cidr = var.vpc1_cidr_range
  enable_nat_gateway = false

  azs            = slice(data.aws_availability_zones.azs_1.names, 0, 2)
  public_subnets = var.vpc1_public_subnets

}

module "vpc2" {
  source  = "terraform-aws-modules/vpc/aws"
  version = "2.64.0"

  providers = {
      aws = aws.region2
  }

  name = "vpc2"
  cidr = var.vpc2_cidr_range
  enable_nat_gateway = false

  azs            = slice(data.aws_availability_zones.azs_2.names, 0, 2)
  public_subnets = var.vpc2_public_subnets

}

