################ TACO TACO TACO ############################

variable "meat" {
  type = string
  default = "chicken"
  description = "Type of meat to put on the taco."

  validation {
    condition = contains(["chicken","beef","fish","sofritas"], var.meat)
    error_message = "The meat must be in the list chicken, beef, pork, sofritas."
  }
}

variable "cheese" {
  type = string
  default = "jack"
  description = "Type of cheese to put on the taco."

  validation {
    condition = contains(["cheddar","jack","blanco","fresco"], var.cheese)
    error_message = "The cheese must be in the list cheddar, jack, blanco, fresco."
  }
}

variable "shell" {
  type = string
  default = "crunchy"
  description = "Type of shell to use for the taco."

  validation {
    condition = contains(["corn","flour","crunchy"], var.shell)
    error_message = "The shell must be in the list corn, flour, crunchy."
  }
}

module "my_salsa" {
    source = "./salsa"

    meat = var.meat
}

module "vpc" {
  source  = "terraform-aws-modules/vpc/aws"
  version = "~> 3.1.0"
}

locals {
  taco = {
      meat = var.meat
      cheese = var.cheese
      shell = var.shell
      salsa = module.my_salsa.salsa
  }
}

output "taco" {
  value = local.taco
}

variable "meat" {
  type = string
  description = "The type of meat used on the taco, should match a value used in the local salsa variable."
}

locals {
  salsa = {
      chicken = "tomatillo"
      beef = "picante"
      fish = "pineapple"
      sofritas = "pico"
  }
}

output "salsa" {
  description = "Returns the type of salsa you should pair with your meat choice."
  value = local.salsa[var.meat]
}

