# CONFIGURATION
###########################

terraform {
  required_providers {
    azurerm = {
      source  = "hashicorp/azurerm"
      version = "~> 2.0"

    }
  }
}

###########################
# VARIABLES
###########################

variable "region" {
  type        = string
  description = "Region in Azure"
  default     = "eastus"
}

variable "prefix" {
  type        = string
  description = "prefix for naming"
  default     = "tacos"
}

variable "subnet_names" {
  type        = list(string)
  description = "list of subnet names"
  sensitive   = true
  default     = ["secret0", "secret1", "secret2"]
}

###########################
# PROVIDERS
###########################

provider "azurerm" {
  features {}
}

###########################
# DATA SOURCES
###########################

locals {
  name0 = "${var.prefix}-0"
  name1 = "${var.prefix}-1"
  name2 = "${var.prefix}-2"
}

###########################
# RESOURCES
###########################

resource "azurerm_resource_group" "vnet0" {
  name     = local.name0
  location = var.region
}

resource "azurerm_resource_group" "vnet1" {
  name     = local.name1
  location = var.region
}

resource "azurerm_resource_group" "vnet2" {
  name     = local.name2
  location = var.region
}

module "network" {
  source              = "Azure/network/azurerm"
  version             = "~> 3.0"
  resource_group_name = azurerm_resource_group.vnet0.name
  vnet_name           = local.name0
  address_space       = "10.0.0.0/16"
  subnet_prefixes     = ["10.0.1.0/24", "10.0.2.0/24", "10.0.3.0/24"]
  subnet_names        = ["sub1","sub2","sub3"]

  tags = {
    environment = "dev"
    costcenter  = "finance"
  }

  depends_on = [azurerm_resource_group.vnet0]
}

variable "my_secret" {
  type = string
  sensitive = true
}

variable "plaintext" {
  type = string
}

resource "local_file" "my_secret" {
  content = var.my_secret
  filename = "${path.module}/${var.my_secret}.txt"
}

resource "local_file" "plaintext" {
  content = var.plaintext
  filename = "${path.module}/${var.plaintext}.txt"
}

output "secret" {
  value = var.my_secret
  sensitive = true
}

output "plaintext" {
  value = var.plaintext
}

###########################
# CONFIGURATION
###########################

terraform {
  required_providers {
    azurerm = {
      source  = "hashicorp/azurerm"
      version = "~> 2.0"

    }
  }
}

#############################################################################
# VARIABLES
#############################################################################

variable "location" {
  type    = string
  default = "eastus"
}

variable "naming_prefix" {
  type    = string
  default = "tacos"
}

locals {
  resource_group_name  = "${var.naming_prefix}${random_integer.sa_num.result}"
  storage_account_name = "${lower(var.naming_prefix)}${random_integer.sa_num.result}"
}

##################################################################################
# PROVIDERS
##################################################################################

provider "azurerm" {
  features {}
}

##################################################################################
# RESOURCES
##################################################################################
resource "random_integer" "sa_num" {
  min = 10000
  max = 99999
}

resource "azurerm_resource_group" "setup" {
  name     = local.resource_group_name
  location = var.location
}

resource "azurerm_storage_account" "sa" {
  name                     = local.storage_account_name
  resource_group_name      = azurerm_resource_group.setup.name
  location                 = var.location
  account_tier             = "Standard"
  account_replication_type = "LRS"

}

resource "azurerm_storage_container" "ct" {
  name                 = "terraform-state"
  storage_account_name = azurerm_storage_account.sa.name

}

data "azurerm_storage_account_sas" "state" {
  connection_string = azurerm_storage_account.sa.primary_connection_string
  https_only        = true

  resource_types {
    service   = true
    container = true
    object    = true
  }

  services {
    blob  = true
    queue = false
    table = false
    file  = false
  }

  start  = timestamp()
  expiry = timeadd(timestamp(), "17520h")

  permissions {
    read    = true
    write   = true
    delete  = true
    list    = true
    add     = true
    create  = true
    update  = false
    process = false
  }
}

#############################################################################
# PROVISIONERS
#############################################################################

resource "local_file" "post-config" {
    filename = "${path.module}/backend-config.txt"
    content = <<EOT
storage_account_name = "${azurerm_storage_account.sa.name}"
container_name = "terraform-state"
key = "terraform.tfstate"
sas_token = "${data.azurerm_storage_account_sas.state.sas}"
EOT
     depends_on = [azurerm_storage_container.ct]
}

##################################################################################
# OUTPUT
##################################################################################

output "storage_account_name" {
  value = azurerm_storage_account.sa.name
}

output "resource_group_name" {
  value = azurerm_resource_group.setup.name
}

#############################################################################
# VARIABLES
#############################################################################

variable "location" {
  type    = string
  default = "eastus"
}

variable "naming_prefix" {
  type    = string
  default = "frontend"
}

locals {
  resource_group_name  = "${var.naming_prefix}${random_integer.sa_num.result}"
}

##################################################################################
# RESOURCES
##################################################################################
resource "random_integer" "sa_num" {
  min = 10000
  max = 99999
}

resource "azurerm_resource_group" "setup" {
  name     = local.resource_group_name
  location = var.location
}

