    #  version = "=0.11.0"
    #}
  }
}

###########################
# VARIABLES
###########################

variable "region" {
  type        = string
  description = "Region in Azure"
  default     = "eastus"
}

variable "prefix" {
  type        = string
  description = "prefix for naming"
  default     = "tacos"
}

###########################
# PROVIDERS
###########################

provider "azurerm" {
  features {}
}

provider "azuread" {}

###########################
# DATA SOURCES
###########################

locals {
  name = "${var.prefix}-cli"
}

###########################
# RESOURCES
###########################

resource "azurerm_resource_group" "vnet" {
  name     = local.name
  location = var.region
}

module "network" {
  source              = "Azure/network/azurerm"
  version             = "3.1.1"
  resource_group_name = azurerm_resource_group.vnet.name
  vnet_name           = local.name
  address_space       = "10.0.0.0/16"
  subnet_prefixes     = ["10.0.1.0/24", "10.0.2.0/24", "10.0.3.0/24"]
  subnet_names        = ["subnet1", "subnet2", "subnet3"]

  tags = {
    environment = "dev"
    costcenter  = "it"
  }

  depends_on = [azurerm_resource_group.vnet]
}

terraform {
    required_providers {
        azurerm = {
            source = "hashicorp/azurerm"
            version = "2.41.0"
        }
    }
}

provider "azurerm" {
    features {}
    alias = "malibu"
}

resource "azurerm_resource_group" "tacos" {
    name = "tacotest"
    location = "East US"
    provider = azurerm.malibu
}

# You used to set the provider version in the provider block
# But that is no longer the case, you now specify it in the
# terraform.required_providers block

# You can also do silly things, like name the provider whatever you want.
# I'm annoyed it's called AzureRM, so I'm calling it Azure.
terraform {
    required_providers {
        azure = {
            source = "hashicorp/azurerm"
            version = "2.41.0"
        }
    }
}

# Which means I can refer to it as Azure in my provider declaration
provider "azure" {
    features {}
    alias = "malibu"
}

resource "azurerm_resource_group" "tacos" {
    name = "tacotest"
    location = "East US"
    # I also have to use the proper addressing of the provider alias, since
    # I have changed the name
    provider = azure.malibu
}

# Lots of providers require some additional information for config
# So you need to explicitly add them in a block. It also gives you
# the opportunity to add some meta-arguments like giving the provider
# an alias

provider "azurerm" {
    features {}
    alias = "malibu"
}

# Now I can reference my alias in a resource, after all what's
# better than some malibu fish tacos? Actually I have no idea.
resource "azurerm_resource_group" "tacos" {
    name = "tacotest"
    location = "East US"
    provider = azurerm.malibu
}

# ── variables.tf ──────────────────────────────────────────
variable "location" {
  default = "eastus"
  type = string
}

variable "address_space" {
  type    = list(string)
  default = ["10.0.0.0/16"]
}

variable "subnet_prefixes" {
  type = list(string)
  default = [
    "10.0.0.0/24",
    "10.0.1.0/24",
    "10.0.2.0/24",
  ]
}

variable "subnet_names" {
  type = list(string)
  default = [
    "controllers",
    "subnet2",
    "subnet3",
  ]
}

variable "controller_vm_size" {
  type    = string
  default = "Standard_D2as_v4"
}

variable "controller_vm_count" {
  type    = number
  default = 1
}

variable "worker_vm_size" {
  type    = string
  default = "Standard_D2as_v4"
}

variable "worker_vm_count" {
  type    = number
  default = 3
}

resource "random_id" "id" {
  byte_length = 4
}

locals {
  controller_nic_nsg = "controller-nic-${random_id.id.hex}"
  worker_nic_nsg     = "worker-nic-${random_id.id.hex}"
  controller_vm = "controller-${random_id.id.hex}"
  worker_vm     = "worker-${random_id.id.hex}"
}

# ── network.tf ──────────────────────────────────────────
terraform {
    required_providers {
        azurerm = {
            source = "hashicorp/azurerm"
            version = "2.41.0"
        }
    }
}

provider "azurerm" {
    features {}
}

resource "azurerm_resource_group" "cka" {
    name = "cka"
    location = var.location
}

# Virtual network with three subnets for controller, workers, and backends
module "vnet" {
  source              = "Azure/vnet/azurerm"
  version = "~> 2.0"
  resource_group_name = azurerm_resource_group.cka.name
  vnet_name = azurerm_resource_group.cka.name
  address_space       = var.address_space
  subnet_prefixes     = var.subnet_prefixes
  subnet_names        = var.subnet_names

  depends_on = [ azurerm_resource_group.cka ]
}

# Create Network Security Groups for NICs

resource "azurerm_network_security_group" "controller_nics" {
  name                = local.controller_nic_nsg
  location            = var.location
  resource_group_name = azurerm_resource_group.cka.name
}

resource "azurerm_network_security_group" "worker_nics" {
  name                = local.worker_nic_nsg
  location            = var.location
  resource_group_name = azurerm_resource_group.cka.name
}

# ── nsgs.tf ──────────────────────────────────────────
resource "azurerm_network_security_rule" "controller_nic_ssh" {
  name                        = "allow_ssh"
  priority                    = 100
  direction                   = "Inbound"
  access                      = "Allow"
  protocol                    = "Tcp"
  source_port_range           = "*"
  destination_port_range      = "22"
  source_address_prefix       = "*"
  destination_address_prefix = "*"
  resource_group_name         = azurerm_resource_group.cka.name
  network_security_group_name = azurerm_network_security_group.controller_nics.name
}

resource "azurerm_network_security_rule" "controller_nic_allow_worker" {
    name = "allow_worker"
    priority = 101
    direction = "Inbound"
    access = "Allow"
    protocol = "*"
    source_port_range           = "*"
    destination_port_range      = "*"
    source_address_prefix       = var.address_space[0]
    destination_address_prefix = "*"
    resource_group_name         = azurerm_resource_group.cka.name
  network_security_group_name = azurerm_network_security_group.controller_nics.name
}

resource "azurerm_network_security_rule" "worker_nic_ssh" {
  name                        = "allow_ssh_local"
  priority                    = 100
  direction                   = "Inbound"
  access                      = "Allow"
  protocol                    = "Tcp"
  source_port_range           = "*"
  destination_port_range      = "22"
  source_address_prefix       = "*"
  destination_address_prefix = "*"
  resource_group_name         = azurerm_resource_group.cka.name
  network_security_group_name = azurerm_network_security_group.worker_nics.name
}

resource "azurerm_network_security_rule" "worker_nic_allow_controller" {
    name = "allow_controller"
    priority = 101
    direction = "Inbound"
    access = "Allow"
    protocol = "*"
    source_port_range           = "*"
    destination_port_range      = "*"
    source_address_prefix       = var.address_space[0]
    destination_address_prefix = "*"
    resource_group_name         = azurerm_resource_group.cka.name
  network_security_group_name = azurerm_network_security_group.worker_nics.name
}

# ── vms.tf ──────────────────────────────────────────
# Generate key pair for all VMs
resource "tls_private_key" "cka" {
  algorithm = "RSA"
  rsa_bits  = "2048"
}

# Write private key out to a file
resource "local_file" "private_key" {
  content  = tls_private_key.cka.private_key_pem
  filename = "${path.root}/azure_vms_private_key.pem"
}

##################### CONTROLLER VM RESOURCES ###################################
resource "azurerm_availability_set" "controller" {
  name                         = local.controller_vm
  location                     = var.location
  resource_group_name          = azurerm_resource_group.cka.name
  platform_fault_domain_count  = 3
  platform_update_domain_count = 2
  managed                      = true
}

resource "azurerm_public_ip" "controller" {
    count               = var.controller_vm_count
    name = "controllerPublicIP-${count.index}"
    resource_group_name = azurerm_resource_group.cka.name
    location = var.location
    allocation_method = "Static"
    sku = "Standard"
}

resource "azurerm_network_interface" "controller" {
  count               = var.controller_vm_count
  name                = "${local.controller_vm}-${count.index}"
  location            = var.location
  resource_group_name = azurerm_resource_group.cka.name

  ip_configuration {
    name                          = "public"
    subnet_id                     = module.vnet.vnet_subnets[0]
    private_ip_address_allocation = "Dynamic"
    public_ip_address_id = azurerm_public_ip.controller[count.index].id
  }
}

resource "azurerm_network_interface_security_group_association" "controller" {
  count                     = var.controller_vm_count
  network_interface_id      = azurerm_network_interface.controller[count.index].id
  network_security_group_id = azurerm_network_security_group.controller_nics.id
}

resource "azurerm_linux_virtual_machine" "controller" {
  count               = var.controller_vm_count
  name                = "${local.controller_vm}-${count.index}"
  location            = var.location
  resource_group_name = azurerm_resource_group.cka.name
  size                = var.controller_vm_size
  admin_username      = "azureuser"
  computer_name       = "controller-${count.index}"
  availability_set_id = azurerm_availability_set.controller.id
  network_interface_ids = [
    azurerm_network_interface.controller[count.index].id,
  ]

  admin_ssh_key {
    username   = "azureuser"
    public_key = tls_private_key.cka.public_key_openssh
  }

  # Using Standard SSD tier storage
  # Accepting the standard disk size from image
  # No data disk is being used
  os_disk {
    caching              = "ReadWrite"
    storage_account_type = "StandardSSD_LRS"
  }

  #Source image is hardcoded b/c I said so
  source_image_reference {
    publisher = "Canonical"
    offer     = "UbuntuServer"
    sku       = "18.04-LTS"
    version   = "latest"
  }

}

##################### WORKER VM RESOURCES ###################################

resource "azurerm_network_interface" "worker" {
  count               = var.worker_vm_count
  name                = "${local.worker_vm}-${count.index}"
  location            = var.location
  resource_group_name = azurerm_resource_group.cka.name

  ip_configuration {
    name                          = "internal"
    subnet_id                     = module.vnet.vnet_subnets[0]
    private_ip_address_allocation = "Dynamic"
  }
}

resource "azurerm_network_interface_security_group_association" "worker" {
  count                     = var.worker_vm_count
  network_interface_id      = azurerm_network_interface.worker[count.index].id
  network_security_group_id = azurerm_network_security_group.worker_nics.id
}

resource "azurerm_linux_virtual_machine" "worker" {
  count               = var.worker_vm_count
  name                = "${local.worker_vm}-${count.index}"
  location            = var.location
  resource_group_name = azurerm_resource_group.cka.name
  size                = var.worker_vm_size
  admin_username      = "azureuser"
  computer_name       = "worker-${count.index}"
  availability_set_id = azurerm_availability_set.controller.id
  network_interface_ids = [
    azurerm_network_interface.worker[count.index].id,
  ]

  admin_ssh_key {
    username   = "azureuser"
    public_key = tls_private_key.cka.public_key_openssh
  }

  # Using Standard SSD tier storage
  # Accepting the standard disk size from image
  # No data disk is being used
  os_disk {
    caching              = "ReadWrite"
    storage_account_type = "StandardSSD_LRS"
  }

  #Source image is hardcoded b/c I said so
  source_image_reference {
    publisher = "Canonical"
    offer     = "UbuntuServer"
    sku       = "18.04-LTS"
    version   = "latest"
  }

}

# ── network.tf ──────────────────────────────────────────
locals {
  # Load all of the data from json
  vnet_json_data = jsondecode(file("config_data.json")).VirtualNetworks

  network_subnets = flatten([
      for network_key, network in local.vnet_json_data : [
          for subnet in network.Subnets : {
              vnet = network_key
              subnet = subnet.Name
              cidr_block = cidrsubnet(network.AddressSpace, 8, subnet.Priority)
          }
      ]
  if network_key != "hub-vnet" ])
}

# ── vm.tf ──────────────────────────────────────────
locals {
  # Load all of the data from json
  vm_json_data = jsondecode(file("config_data.json")).VirtualMachines
}

locals {
  # Load all of the data from json
  all_json_data = jsondecode(file("config_data.json"))

  # Load the first list of data directly
  list1_data = jsondecode(file("config_data.json")).List1

  # Load the first map indirectly
  map1_data = local.all_json_data.Map1
}

#map of maps for creating subnets
variable "subnet_map" {
   type = map
   default = {
      subnet-1 = {
         az = "us-west-1a"
         cidr = "10.0.198.0/24"
      }
      subnet-2 = {
         az = "us-east-1a"
         cidr = "10.0.199.0/24"
      }
      subnet-3 = {
         az = "us-east-2a"
         cidr = "10.0.200.0/24"
      }
   }
}

# We need to create all the same resources we have from the ARM template
# Here's the list
# 1 - virtual network
# 2 - two subnets in the vnet
# 3 - two NICs
# 4 - two NSGs (first NSG allows RDP from anywhere)
# 5 - one storage account for diagnostics
# 6 - one public IP address
# 7 - one virtual machine with just the OS disk

# Start with the terraform block and provider block
terraform {
    required_providers {
        azurerm = {
            source = "hashicorp/azurerm"
            version = "2.41.0"
        }
    }
}

provider "azurerm" {
    features {}
}

# We're going to need variables that align to the template
variable "location" {
  default = "eastus"
}

variable "prefix" {
  default = "tacos"
}

variable "id" {
    type = string
    description = "You'll need this value from the deployment script"
}

variable "adminUsername" {
  default = "azureadmin"
}

variable "adminPassword" {
  type = string
  description = "Whatever value you used in the parameters script"
  sensitive = true
}

variable "diagStorageAccountName" {
  type = string
  description = "Name of diagnostic storage account from template"
}

# Let's construct the other values

locals {
  resource_group_name = "${var.prefix}-${var.id}"
  virtualMachineSize = "Standard_DS1_v2"
  virtualMachineName = "VM-MultiNic"
  nic1 = "nic-1"
  nic2 = "nic-2"
  virtualNetworkName = "virtualNetwork"
  subnet1Name = "subnet-1"
  subnet2Name = "subnet-2"
  virtualNetworkAddressSpace = "10.0.0.0/16"
  subnet1AddressSpace = "10.0.0.0/24"
  subnet2AddressSpace = "10.0.1.0/24"
  publicIPAddressName = "publicIp"
  networkSecurityGroupName = "NSG"
  networkSecurityGroupName2 = "${local.subnet2Name}-nsg"
}

# Now the resource group

resource "azurerm_resource_group" "tacos" {
    name = local.resource_group_name
    location = var.location
}

# Vnet configuration
resource "azurerm_virtual_network" "vnet" {
  name = local.virtualNetworkName
  location = azurerm_resource_group.tacos.location
  resource_group_name = azurerm_resource_group.tacos.name

  address_space = [local.virtualNetworkAddressSpace]

  subnet {
    address_prefix = local.subnet1AddressSpace
    name = local.subnet1Name
  }

  subnet {
    address_prefix = local.subnet2AddressSpace
    name = local.subnet2Name
    security_group = TBD
  }
}

resource "azurerm_subnet" "subnet1" {
  name = local.subnet1Name
  resource_group_name  = azurerm_resource_group.tacos.name
  virtual_network_name = azurerm_virtual_network.vnet.name
  address_prefixes     = [local.subnet1AddressSpace]
}

resource "azurerm_subnet" "subnet2" {
  name = local.subnet2Name
  resource_group_name  = azurerm_resource_group.tacos.name
  virtual_network_name = azurerm_virtual_network.vnet.name
  address_prefixes     = [local.subnet2AddressSpace]

}

# Network security groups
resource "azurerm_network_security_group" "NSG" {
  name                = local.networkSecurityGroupName
  location            = azurerm_resource_group.tacos.location
  resource_group_name = azurerm_resource_group.tacos.name

  security_rule {
    name                       = "RDP"
    priority                   = 1000
    direction                  = "Inbound"
    access                     = "Allow"
    protocol                   = "Tcp"
    source_port_range          = "*"
    destination_port_range     = "3389"
    source_address_prefix      = "*"
    destination_address_prefix = "*"
  }
}

resource "azurerm_network_security_group" "NSG2" {
  name                = local.networkSecurityGroupName2
  location            = azurerm_resource_group.tacos.location
  resource_group_name = azurerm_resource_group.tacos.name
}

resource "azurerm_subnet_network_security_group_association" "NSG2" {
  subnet_id                 = azurerm_subnet.subnet2.id
  network_security_group_id = azurerm_network_security_group.NSG2.id
}

resource "azurerm_network_interface_security_group_association" "nic1" {
  network_interface_id      = azurerm_network_interface.nic1.id
  network_security_group_id = azurerm_network_security_group.NSG.id
}

# Public IP Address
resource "azurerm_public_ip" "pip" {
  name                = local.publicIPAddressName
  resource_group_name = azurerm_resource_group.tacos.name
  location            = azurerm_resource_group.tacos.location
  allocation_method   = "Dynamic"

}

# Virtual NICs
resource "azurerm_network_interface" "nic1" {
  name                = local.nic1
  location            = azurerm_resource_group.tacos.location
  resource_group_name = azurerm_resource_group.tacos.name

  ip_configuration {
    name                          = "ipconfig1"
    subnet_id                     = azurerm_subnet.subnet1.id
    private_ip_address_allocation = "Dynamic"
    public_ip_address_id = azurerm_public_ip.pip.id
  }
}

resource "azurerm_network_interface" "nic2" {
  name                = local.nic2
  location            = azurerm_resource_group.tacos.location
  resource_group_name = azurerm_resource_group.tacos.name

  ip_configuration {
    name                          = "ipconfig1"
    subnet_id                     = azurerm_subnet.subnet2.id
    private_ip_address_allocation = "Dynamic"
  }
}

# Diagnostics storage account
resource "azurerm_storage_account" "VMDiag" {
  name = var.diagStorageAccountName
  location            = azurerm_resource_group.tacos.location
  resource_group_name = azurerm_resource_group.tacos.name
  account_kind = "StorageV2"
  account_tier = "Standard"
  account_replication_type = "LRS"

}

# Virtual Machine
resource "azurerm_windows_virtual_machine" "VM" {
  name                = local.virtualMachineName
  resource_group_name = azurerm_resource_group.tacos.name
  location            = azurerm_resource_group.tacos.location
  size                = local.virtualMachineSize
  admin_username      = var.adminUsername
  admin_password      = var.adminPassword
  network_interface_ids = [
    azurerm_network_interface.nic1.id,
    azurerm_network_interface.nic2.id,
  ]

  os_disk {
    caching              = "ReadWrite"
    storage_account_type = "Premium_LRS"
  }

  source_image_reference {
    publisher = "MicrosoftWindowsServer"
    offer     = "WindowsServer"
    sku       = "2019-Datacenter"
    version   = "latest"
  }

  boot_diagnostics {
    storage_account_uri = azurerm_storage_account.VMDiag.primary_blob_endpoint
  }
}

###########################
# CONFIGURATION
###########################

terraform {
  required_providers {
    azurerm = {
      source  = "hashicorp/azurerm"
      version = "~>2.0"

    }
  }
}

###########################
# VARIABLES
###########################

variable "region" {
  type        = string
  description = "Region in Azure"
  default     = "eastus"
}

variable "resource_group_name" {
  type        = string
  description = "Name of resource group to create."
  default     = "tacos"
}

variable "vnet_name" {
  description = "Name of the vnet to create."
  type        = string
  default     = "taconet"
}

variable "address_space" {
  description = "The address space that is used by the virtual network."
  type        = string
  default     = "10.0.0.0/16"
}

variable "subnet_prefixes" {
  description = "The address prefix to use for the subnet."
  type        = list(string)
  default     = ["10.0.0.0/24","10.0.1.0/24"]
}

variable "subnet_names" {
  description = "A list of public subnets inside the vNet."
  type        = list(string)
  default     = ["subnet1","subnet2"]
}

###########################
# PROVIDERS
###########################

provider "azurerm" {
  features {}
}

###########################
# RESOURCES
###########################

resource "azurerm_resource_group" "vnet" {
  name     = var.resource_group_name
  location = var.region
}

resource "azurerm_virtual_network" "vnet" {
  name                = var.vnet_name
  resource_group_name = azurerm_resource_group.vnet.name
  location            = azurerm_resource_group.vnet.location
  address_space       = [var.address_space]
  #tags = {
  #  environment = "dev"
  #}
}

resource "azurerm_subnet" "subnets" {
    count = length(var.subnet_names)
    name = var.subnet_names[count.index]
    resource_group_name = azurerm_resource_group.vnet.name
    address_prefixes = [ var.subnet_prefixes[count.index] ]
    virtual_network_name = azurerm_virtual_network.vnet.name
}

# ── variables.tf ──────────────────────────────────────────
variable "region" {
  default = "us-east-1"
}

# Consul variables

variable "consul_address" {
  type = string
  description = "Address of Consul server"
  default = "127.0.0.1"
}

variable "consul_port" {
  type = number
  description = "Port Consul server is listening on"
  default = "8500"
}

variable "consul_datacenter" {
  type = string
  description = "Name of the Consul datacenter"
  default = "dc1"
}

# Application variables

variable "ip_range" {
  default = "0.0.0.0/0"
}

variable "rds_username" {
  default     = "ddtuser"
  description = "User name"
}

variable "rds_password" {
  default     = "TerraformIsNumber1!"
  description = "password, provide through your ENV variables"
}

# ── backend.tf ──────────────────────────────────────────
##################################################################################
# BACKENDS
##################################################################################
terraform {
  backend "consul" {
    address = "127.0.0.1:8500"
    scheme = "http"
  }
}

# ── datasources.tf ──────────────────────────────────────────
##################################################################################
# DATA SOURCES
##################################################################################

data "consul_keys" "applications" {
  key {
      name = "applications"
      path = terraform.workspace == "default" ? "applications/configuration/globo-primary/app_info" : "applications/configuration/globo-primary/${terraform.workspace}/app_info"
  }

  key {
    name = "common_tags"
    path = "applications/configuration/globo-primary/common_tags"
  }
}

data "terraform_remote_state" "networking" {
  backend = "consul"

  config = {
    address = "127.0.0.1:8500"
    scheme = "http"
    path     = terraform.workspace == "default" ? "networking/state/globo-primary" : "networking/state/globo-primary-env:${terraform.workspace}"
  }
}

data "aws_ami" "aws_linux" {
  most_recent = true
  owners = ["amazon"]

  filter {
    name   = "name"
    values = ["amzn-ami-hvm-20*"]
  }

  filter {
    name   = "architecture"
    values = ["x86_64"]
  }

  filter {
    name   = "virtualization-type"
    values = ["hvm"]
  }

  filter {
    name   = "root-device-type"
    values = ["ebs"]
  }
}

# ── resources.tf ──────────────────────────────────────────
#Based on the work from https://github.com/arbabnazar/terraform-ansible-aws-vpc-ha-wordpress

##################################################################################
# CONFIGURATION - added for Terraform 0.14
##################################################################################

terraform {
  required_providers {
    aws = {
      source = "hashicorp/aws"
      version = "~>3.0"
    }
    consul = {
      source = "hashicorp/consul"
      version = "~>2.0"
    }
  }
}

##################################################################################
# PROVIDERS
##################################################################################

provider "aws" {
  profile = "deep-dive"
  region  = var.region
}

provider "consul" {
  address    = "${var.consul_address}:${var.consul_port}"
  datacenter = var.consul_datacenter
}

##################################################################################
# LOCALS
##################################################################################

locals {
  asg_instance_size = jsondecode(data.consul_keys.applications.var.applications)["asg_instance_size"]
  asg_max_size = jsondecode(data.consul_keys.applications.var.applications)["asg_max_size"]
  asg_min_size = jsondecode(data.consul_keys.applications.var.applications)["asg_min_size"]
  rds_storage_size = jsondecode(data.consul_keys.applications.var.applications)["rds_storage_size"]
  rds_engine = jsondecode(data.consul_keys.applications.var.applications)["rds_engine"]
  rds_version = jsondecode(data.consul_keys.applications.var.applications)["rds_version"]
  rds_instance_size = jsondecode(data.consul_keys.applications.var.applications)["rds_instance_size"]
  rds_multi_az = jsondecode(data.consul_keys.applications.var.applications)["rds_multi_az"]
  rds_db_name = jsondecode(data.consul_keys.applications.var.applications)["rds_db_name"]

  common_tags = merge(jsondecode(data.consul_keys.applications.var.common_tags),
    {
      Environment = terraform.workspace
    }
  )
}

##################################################################################
# RESOURCES
##################################################################################

resource "aws_launch_configuration" "webapp_lc" {
  lifecycle {
    create_before_destroy = true
  }

  name_prefix   = "${terraform.workspace}-ddt-lc-"
  image_id      = data.aws_ami.aws_linux.id
  instance_type = local.asg_instance_size

  security_groups = [
    aws_security_group.webapp_http_inbound_sg.id,
    aws_security_group.webapp_ssh_inbound_sg.id,
    aws_security_group.webapp_outbound_sg.id,
  ]

  user_data                   = file("./templates/userdata.sh")
  associate_public_ip_address = true
  iam_instance_profile = aws_iam_instance_profile.asg.name
}

resource "aws_elb" "webapp_elb" {
  name    = "ddt-webapp-elb-${terraform.workspace}"
  subnets = data.terraform_remote_state.networking.outputs.public_subnets

  listener {
    instance_port     = 80
    instance_protocol = "http"
    lb_port           = 80
    lb_protocol       = "http"
  }

  health_check {
    healthy_threshold   = 2
    unhealthy_threshold = 2
    timeout             = 3
    target              = "HTTP:80/"
    interval            = 10
  }

  security_groups = [aws_security_group.webapp_http_inbound_sg.id]

  tags = local.common_tags
}

resource "aws_autoscaling_group" "webapp_asg" {
  lifecycle {
    create_before_destroy = true
    #create_before_destroy = false
  }

  vpc_zone_identifier   = data.terraform_remote_state.networking.outputs.public_subnets
  name                  = "ddt_webapp_asg-${terraform.workspace}"
  max_size              = local.asg_max_size
  min_size              = local.asg_min_size
  wait_for_elb_capacity = local.asg_min_size
  force_delete          = true
  launch_configuration  = aws_launch_configuration.webapp_lc.id
  load_balancers        = [aws_elb.webapp_elb.name]

  dynamic "tag" {
    for_each = local.common_tags
    content {
      key = tag.key
      value = tag.value
      propagate_at_launch = true
    }
  }
}

#
# Scale Up Policy and Alarm
#
resource "aws_autoscaling_policy" "scale_up" {
  name                   = "ddt_asg_scale_up-${terraform.workspace}"
  scaling_adjustment     = 2
  adjustment_type        = "ChangeInCapacity"
  cooldown               = 300
  autoscaling_group_name = aws_autoscaling_group.webapp_asg.name
}

resource "aws_cloudwatch_metric_alarm" "scale_up_alarm" {
  alarm_name                = "ddt-high-asg-cpu-${terraform.workspace}"
  comparison_operator       = "GreaterThanThreshold"
  evaluation_periods        = "2"
  metric_name               = "CPUUtilization"
  namespace                 = "AWS/EC2"
  period                    = "120"
  statistic                 = "Average"
  threshold                 = "80"
  insufficient_data_actions = []

  dimensions = {
    AutoScalingGroupName = aws_autoscaling_group.webapp_asg.name
  }

  alarm_description = "EC2 CPU Utilization"
  alarm_actions     = [aws_autoscaling_policy.scale_up.arn]
}

#
# Scale Down Policy and Alarm
#
resource "aws_autoscaling_policy" "scale_down" {
  name                   = "ddt_asg_scale_down-${terraform.workspace}"
  scaling_adjustment     = -1
  adjustment_type        = "ChangeInCapacity"
  cooldown               = 600
  autoscaling_group_name = aws_autoscaling_group.webapp_asg.name
}

resource "aws_cloudwatch_metric_alarm" "scale_down_alarm" {
  alarm_name                = "ddt-low-asg-cpu-${terraform.workspace}"
  comparison_operator       = "LessThanThreshold"
  evaluation_periods        = "5"
  metric_name               = "CPUUtilization"
  namespace                 = "AWS/EC2"
  period                    = "120"
  statistic                 = "Average"
  threshold                 = "30"
  insufficient_data_actions = []

  dimensions = {
    AutoScalingGroupName = aws_autoscaling_group.webapp_asg.name
  }

  alarm_description = "EC2 CPU Utilization"
  alarm_actions     = [aws_autoscaling_policy.scale_down.arn]
}

## Database Config

resource "aws_db_subnet_group" "db_subnet_group" {
  name       = "${terraform.workspace}-ddt-rds-subnet-group"
  subnet_ids = data.terraform_remote_state.networking.outputs.private_subnets
}

resource "aws_db_instance" "rds" {
  identifier             = "${terraform.workspace}-ddt-rds"
  allocated_storage      = local.rds_storage_size
  engine                 = local.rds_engine
  engine_version         = local.rds_version
  instance_class         = local.rds_instance_size
  multi_az               = local.rds_multi_az
  name                   = "${terraform.workspace}${local.rds_db_name}"
  username               = var.rds_username
  password               = var.rds_password
  db_subnet_group_name   = aws_db_subnet_group.db_subnet_group.id
  vpc_security_group_ids = [aws_security_group.rds_sg.id]
  skip_final_snapshot    = true

  tags = local.common_tags
}

# ── s3.tf ──────────────────────────────────────────
#### S3 buckets
variable "aws_bucket_prefix" {
  type    = strings
  #type = string

  default = "globo"
}

resource "random_integer" "rand" {
  min = 10000
  max = 99999
}

locals {
  bucket_name         = "${var.aws_bucket_prefix}_${random_integer.rand.result}"
  #bucket_name         = "${var.aws_bucket_prefix}-${random_integer.rand.result}"
}

resource "aws_s3_bucket" "logs_bucket" {
  bucket        = local.bucket_name
  acl           = "private"
  force_destroy = true

  versioning {
    enabled = true
  }

}

#### Instance profiles

resource "aws_iam_instance_profile" "asg" {

  lifecycle {
    create_before_destroy = false
  }

  name = "${terraform.workspace}_asg_profile_bug"
  role = "aws_iam_role.asg.name"
  #role = aws_iam_role.asg.name
}

#### Instance roles

resource "aws_iam_role" "asg" {
  name = "${terraform.workspace}_asg_role"
  path = "/"

  assume_role_policy = <<EOF
{
  "Version": "2012-10-17",
  "Statement": [
    {
      "Action": "sts:AssumeRole",
      "Principal": {
        "Service": "ec2.amazonaws.com"
      },
      "Effect": "Allow",
      "Sid": ""
    }
  ]
}
  EOF
}

#### S3 policies

resource "aws_iam_role_policy" "asg" {
  name = "${terraform.workspace}-globo-primary-rds"
  role = aws_iam_role.asg.ids
  #role = aws_iam_role.asg.id

  policy = <<-EOF
  {
    "Version": "2012-10-17",
    "Statement": [
      {
        "Action": [
          "s3:*"
        ],
        "Effect": "Allow",
        "Resource": [
                "arn:aws:s3:::${local.bucket_name}",
                "arn:aws:s3:::${local.bucket_name}/*"
            ]
      }
    ]
  }
  EOF
}

# ── security_groups.tf ──────────────────────────────────────────
##################################################################################
# RESOURCES
##################################################################################

resource "aws_security_group" "webapp_http_inbound_sg" {
  name        = "demo_webapp_http_inbound"
  description = "Allow HTTP from Anywhere"

  ingress {
    from_port   = 80
    to_port     = 80
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  vpc_id = data.terraform_remote_state.networking.outputs.vpc_id

  tags = {
    Name = "terraform_demo_webapp_http_inbound"
  }
}

resource "aws_security_group" "webapp_ssh_inbound_sg" {
  name        = "demo_webapp_ssh_inbound"
  description = "Allow SSH from certain ranges"

  ingress {
    from_port   = 22
    to_port     = 22
    protocol    = "tcp"
    cidr_blocks = [var.ip_range]
  }

  vpc_id = data.terraform_remote_state.networking.outputs.vpc_id

  tags = merge(local.common_tags,{
    Name = "terraform_demo_webapp_ssh_inbound"
  })
}

resource "aws_security_group" "webapp_outbound_sg" {
  name        = "demo_webapp_outbound"
  description = "Allow outbound connections"

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  vpc_id = data.terraform_remote_state.networking.outputs.vpc_id

  tags = merge(local.common_tags,{
    Name = "terraform_demo_webapp_outbound"
  })
}

resource "aws_security_group" "rds_sg" {
  name        = "demo_rds_inbound"
  description = "Allow inbound from web tier"
  vpc_id      = data.terraform_remote_state.networking.outputs.vpc_id

  tags = {
    Name = "demo_rds_inbound"
  }

  // allows traffic from the SG itself
  ingress {
    from_port = 0
    to_port   = 0
    protocol  = "-1"
    self      = true
  }

  // allow traffic for TCP 3306
  ingress {
    from_port       = 3306
    to_port         = 3306
    protocol        = "tcp"
    security_groups = [aws_security_group.webapp_http_inbound_sg.id]
  }

  // outbound internet access
  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

# In this example we will create a basic VNet and then an NSG for
# one of the subnets. This is one way to do it, and we are going
# to parse some JSON to create a dynamic set of blocks

###########################
# CONFIGURATION
###########################

terraform {
  required_providers {
    azurerm = {
      source  = "hashicorp/azurerm"
      version = "~>2.0"

    }
  }
}

###########################
# VARIABLES
###########################

variable "region" {
  type        = string
  description = "Region in Azure"
  default     = "eastus"
}

variable "resource_group_name" {
  type        = string
  description = "Name of resource group to create."
  default     = "tacos"
}

variable "vnet_name" {
  description = "Name of the vnet to create."
  type        = string
  default     = "taconet"
}

variable "address_space" {
  description = "The address space that is used by the virtual network."
  type        = string
  default     = "10.0.0.0/16"
}

variable "subnet_prefixes" {
  description = "The address prefix to use for the subnet."
  type        = list(string)
  default     = ["10.0.0.0/24","10.0.1.0/24"]
}

variable "subnet_names" {
  description = "A list of public subnets inside the vNet."
  type        = list(string)
  default     = ["subnet1","subnet2"]
}

###########################
# LOCALS
###########################

locals {
  rules = jsondecode(file("rules.json")).Rules
  rule_mapping = {
      vnet = var.address_space
      private = "${data.http.my_ip.body}/32"
      subnet = var.subnet_prefixes[0]
      all = "*"
  }
}

###########################
# DATA
###########################

data "http" "my_ip" {
  url = "http://ifconfig.me"
}

###########################
# PROVIDERS
###########################

provider "azurerm" {
  features {}
}

###########################
# RESOURCES
###########################

resource "azurerm_resource_group" "vnet" {
  name     = var.resource_group_name
  location = var.region
}

resource "azurerm_virtual_network" "vnet" {
  name                = var.vnet_name
  resource_group_name = azurerm_resource_group.vnet.name
  location            = azurerm_resource_group.vnet.location
  address_space       = [var.address_space]

  dynamic "subnet" {
    for_each = zipmap(var.subnet_names,var.subnet_prefixes)
      content {
          name = subnet.key
          address_prefix = subnet.value
      }
  }
}

resource "azurerm_network_security_group" "public" {
    name = "publicSubnet"
    location = azurerm_resource_group.vnet.location
    resource_group_name = azurerm_resource_group.vnet.name

    dynamic "security_rule" {
        for_each = local.rules
        content {
            name = security_rule.value["name"]
            priority = security_rule.value["priority"]
            direction = security_rule.value["direction"]
            access = security_rule.value["access"]
            protocol = security_rule.value["protocol"]
            source_port_range = security_rule.value["source_port_range"]
            destination_port_range = security_rule.value["destination_port_range"]
            source_address_prefix = local.rule_mapping[security_rule.value["source_address_prefix"]]
            destination_address_prefix = local.rule_mapping[security_rule.value["destination_address_prefix"]]
        }
    }
}

# In this example we will create a basic VNet and then an NSG for
# one of the subnets. This is one way to do it, and we are going
# to parse some JSON to create a set of NSG rules associated with
# the NSG

###########################
# CONFIGURATION
###########################

terraform {
  required_providers {
    azurerm = {
      source  = "hashicorp/azurerm"
      version = "~>2.0"

    }
  }
}

###########################
# VARIABLES
###########################

variable "region" {
  type        = string
  description = "Region in Azure"
  default     = "eastus"
}

variable "resource_group_name" {
  type        = string
  description = "Name of resource group to create."
  default     = "tacos"
}

variable "vnet_name" {
  description = "Name of the vnet to create."
  type        = string
  default     = "taconet"
}

variable "address_space" {
  description = "The address space that is used by the virtual network."
  type        = string
  default     = "10.0.0.0/16"
}

variable "subnet_prefixes" {
  description = "The address prefix to use for the subnet."
  type        = list(string)
  default     = ["10.0.0.0/24", "10.0.1.0/24"]
}

variable "subnet_names" {
  description = "A list of public subnets inside the vNet."
  type        = list(string)
  default     = ["subnet1", "subnet2"]
}

###########################
# LOCALS
###########################

locals {
  rules = jsondecode(file("rules.json")).Rules
  rule_mapping = {
    vnet    = var.address_space
    private = "${data.http.my_ip.body}/32"
    subnet  = var.subnet_prefixes[0]
    all     = "*"
  }
}

###########################
# DATA
###########################

data "http" "my_ip" {
  url = "http://ifconfig.me"
}

###########################
# PROVIDERS
###########################

provider "azurerm" {
  features {}
}

###########################
# RESOURCES
###########################

resource "azurerm_resource_group" "vnet" {
  name     = var.resource_group_name
  location = var.region
}

resource "azurerm_virtual_network" "vnet" {
  name                = var.vnet_name
  resource_group_name = azurerm_resource_group.vnet.name
  location            = azurerm_resource_group.vnet.location
  address_space       = [var.address_space]
}

resource "azurerm_subnet" "subnets" {
  count                = length(var.subnet_names)
  name                 = var.subnet_names[count.index]
  resource_group_name  = azurerm_resource_group.vnet.name
  address_prefixes     = [var.subnet_prefixes[count.index]]
  virtual_network_name = azurerm_virtual_network.vnet.name
}

resource "azurerm_network_security_group" "public" {
  name                = "publicSubnet"
  location            = azurerm_resource_group.vnet.location
  resource_group_name = azurerm_resource_group.vnet.name
}

resource "azurerm_network_security_rule" "rules" {
  for_each                    = { for r in local.rules : r.name=>r }
  name                        = each.value["name"]
  priority                    = each.value["priority"]
  direction                   = each.value["direction"]
  access                      = each.value["access"]
  protocol                    = each.value["protocol"]
  source_port_range           = each.value["source_port_range"]
  destination_port_range      = each.value["destination_port_range"]
  source_address_prefix       = local.rule_mapping[each.value["source_address_prefix"]]
  destination_address_prefix  = local.rule_mapping[each.value["destination_address_prefix"]]
  resource_group_name         = azurerm_resource_group.vnet.name
  network_security_group_name = azurerm_network_security_group.public.name
}

# ── main.tf ──────────────────────────────────────────
# Let's try and render the test template using the template_file data source
data "template_file" "test" {
  template = file("test.tmpl")
  vars = {
    "mystring" = local.mystring
    #"mylist"  = local.mylist # This won't work b/c it's not a string
    "mylist" = join(",", local.mylist)
    # We also cannot pass a map for the same reason
    # First we can get the keys
    "mapkeys" = join(",", keys(local.mymap))
    "mapvalues" = join(",", values(local.mymap))

    # Let's try my set
    "myset" = join(",",local.myset)
  }
}

output "template" {
  value = data.template_file.test.rendered
}

