variable "prefix" {
  type = string
  default = "taco"
}

resource "oci_identity_compartment" "testing" {
  compartment_id = var.parent_compartment_id
  description = "Testing compartment"
  name = "${var.prefix}-testing"
  enable_delete = true
}

# Now we'll create the VCN

module "vcn" {
  source  = "oracle-terraform-modules/vcn/oci"
