# ── variables.tf ──────────────────────────────────────────
variable "prefix" {
  description = "Naming prefix for Vault Cluster"
  type = string
  default = "taco"
}

variable "public_endpoint" {
  description = "Whether or not to create a public endpoint for Vault"
  type = bool
  default = false
}

variable "hvn_id" {
  description = "ID of the HVN to used with Vault"
  type = string
}

# ── outputs.tf ──────────────────────────────────────────
output "vault_private_endpoint_url" {
  value = hcp_vault_cluster.vault.vault_private_endpoint_url
}

output "vault_public_endpoint_url" {
  value = hcp_vault_cluster.vault.vault_public_endpoint_url
}

output "vault_admin_token" {
  value = hcp_vault_cluster_admin_token.vault.token
  sensitive = true
}

# ── resources.tf ──────────────────────────────────────────
locals {
  name = "${lower(var.prefix)}-${random_id.seed.hex}"
}

resource "random_id" "seed" {
  byte_length = 4
}

resource "hcp_vault_cluster" "vault" {
  cluster_id = local.name
  hvn_id     = var.hvn_id
  public_endpoint = var.public_endpoint
}

resource "hcp_vault_cluster_admin_token" "vault" {
  cluster_id = hcp_vault_cluster.vault.cluster_id
}

# ── terraform.tf ──────────────────────────────────────────
terraform {
  required_providers {
      hcp = {
          source = "hashicorp/hcp"
          version = "~> 0.5"
      }
  }
}

# ── variables.tf ──────────────────────────────────────────
variable "peer_vpc_id" {
  description = "VPC ID of the VPC to be paired with the HVN"
  type = string
}

variable "hvn_id" {
  description = "ID of the HVN to be paired with the VPC"
  type = string
}

variable "route_table_ids" {
  description = "Route Table IDs to associate the peering connection with."
  type = list(string)
}

variable "hvn_cidr_block" {
  description = "CIDR Block of HVN for peered routing."
  type = string
}

# ── outputs.tf ──────────────────────────────────────────

# ── resources.tf ──────────────────────────────────────────
data "aws_vpc" "peer" {
  id = var.peer_vpc_id
}

data "aws_arn" "peer" {
  arn = data.aws_vpc.peer.arn
}

resource "hcp_aws_network_peering" "peer" {
  hvn_id              = var.hvn_id
  peer_vpc_id         = data.aws_vpc.peer.id
  peer_account_id     = data.aws_vpc.peer.owner_id
  peer_vpc_region     = data.aws_arn.peer.region
  peer_vpc_cidr_block = data.aws_vpc.peer.cidr_block_associations[0].cidr_block
}

resource "aws_vpc_peering_connection_accepter" "peer" {
  vpc_peering_connection_id = hcp_aws_network_peering.peer.provider_peering_id
  auto_accept               = true
}

resource "aws_route" "peer" {
  count = length(var.route_table_ids)
  route_table_id = var.route_table_ids[count.index]
  destination_cidr_block = var.hvn_cidr_block
  vpc_peering_connection_id = hcp_aws_network_peering.peer.provider_peering_id
}

