# In this configuration we are going to access the outputs from the
# remote state stored for the networking.

data "terraform_remote_state" "network" {
  backend = "remote"

  config = {
    organization = "ned-in-the-cloud"

    workspaces = {
      name = "terraform-tuesday-modules-setup"
    }
   }
}

output "resource_group_name" {
  value = data.terraform_remote_state.network.outputs.resource_group_name
}

output "subnet_prefixes" {
  value = data.terraform_remote_state.network.outputs.subnet_prefixes
}

output "all_outputs" {
  value = data.terraform_remote_state.network.outputs
}

# We are going to create a local value and expose it with an output

locals {
  my_string = "string value"
  my_list = ["one","two","three"]
  my_map = {
      one = "1"
      two = "2"
      three = "3"
  }
}

resource "random_integer" "random" {
  min = 10000
  max = 99999
}

output "my_string_out" {
  value = local.my_string
}

output "my_list_out" {
  value = local.my_list
}

output "my_map_out" {
  value = local.my_map
}

output "random_out" {
  value = random_integer.random
}

# ── azuread.tf ──────────────────────────────────────────
# Set the reply URL
variable "reply_url" {
  type = string
  description = "Reply URL of Boundary authentication"
  default = "http://localhost:9200/v1/auth-methods/oidc:authenticate:callback"
}

# Get the Microsoft Graph API ID
data "azuread_service_principal" "microsoft_graph" {
  display_name = "Microsoft Graph"
}

# Get the tenant ID for output
data "azuread_client_config" "current" {}

# Generate a random number for naming
resource "random_integer" "suffix" {
  min = 10000
  max = 99999
}

locals {
  app_name = "boundary-${random_integer.suffix.result}"
  boundary_group_name = "boundary-admins-${random_integer.suffix.result}"
}

# Create application in Azure AD
resource "azuread_application" "boundary_oidc" {
  display_name               = local.app_name

  group_membership_claims = ["All"]
  owners = [data.azuread_client_config.current.object_id]

  required_resource_access {
    resource_app_id = "00000003-0000-0000-c000-000000000000" # Microsoft Graph

    resource_access {
      id   = "df021288-bdef-4463-88db-98f22de89214" # User.Read.All
      type = "Role"
    }

    resource_access {
      id   = "b4e74841-8e56-480b-be8b-910348b18b4c" # User.ReadWrite
      type = "Scope"
    }

    resource_access {
      id = "98830695-27a2-44f7-8c18-0c3ebc9698f6" # GroupMember.Read.All
      type = "Scope"
    }
  }

  web {
    redirect_uris = [var.reply_url]
  }
}

# Create a service principal for the application
resource "azuread_service_principal" "boundary_oidc" {
  application_id               = azuread_application.boundary_oidc.application_id
  owners = [data.azuread_client_config.current.object_id]
}

resource "azuread_service_principal_password" "boundary_oidc" {
  service_principal_id = azuread_service_principal.boundary_oidc.object_id
}

resource "azuread_group" "boundary_admin" {
  display_name = local.boundary_group_name
  security_enabled = true
  members = [data.azuread_client_config.current.object_id]

}
output "tenant_id" {
  value = azuread_service_principal.boundary_oidc.application_tenant_id
}

output "client_id" {
  value = azuread_service_principal.boundary_oidc.application_id
}

output "client_secret" {
  value = azuread_service_principal_password.boundary_oidc.value
  sensitive = true
}

output "group_id" {
  value = azuread_group.boundary_admin.object_id
}

output "grant_command" {
  value = "az ad app permission grant --id ${azuread_service_principal.boundary_oidc.application_id}  --api ${data.azuread_service_principal.microsoft_graph.id}"
}

# ── terraform.tf ──────────────────────────────────────────
terraform {
  required_providers {
      azuread = {
      source = "hashicorp/azuread"
      version = "~> 2.0"
    }
  }
}

# ── variables.tf ──────────────────────────────────────────
variable "region" {
  type        = string
  description = "Region in Azure"
  default     = "eastus"
}

variable "prefix" {
  type        = string
  description = "prefix for naming"
  default     = "tacos"
}

variable "hypervisor_vm_size" {
  type        = string
  description = "Size for VM, must be Dv3 or Ev3"
  default     = "Standard_D4s_v3"
}

variable "data_disk_size" {
  type        = number
  description = "Size of data disk for VMs"
  default     = 256
}

variable "data_disk_storage_class" {
  type        = string
  description = "Storage class for the data disk"
  default     = "Premium_LRS"
}

resource "random_id" "seed" {
  byte_length = 4
}

locals {
  name          = "${var.prefix}-${random_id.seed.hex}"
  hypervisor_vm = "hypervisor-${random_id.seed.hex}"
}

# ── outputs.tf ──────────────────────────────────────────
output "hypervisor_fqdn" {
  value = azurerm_public_ip.hypervisor.fqdn
}

output "hypervisor_public_ip" {
  value = azurerm_public_ip.hypervisor.ip_address
}

# ── terraform.tf ──────────────────────────────────────────
terraform {
  required_providers {
    azurerm = {
      source  = "hashicorp/azurerm"
      version = "~> 2.0"

    }
  }
}

provider "azurerm" {
  features {}
}

# ── vm.tf ──────────────────────────────────────────
resource "tls_private_key" "hypervisor" {
  algorithm = "RSA"
  rsa_bits  = "2048"
}

# Write private key out to a file
resource "local_file" "private_key" {
  content  = tls_private_key.hypervisor.private_key_pem
  filename = "${path.root}/azure_vms_private_key.pem"
}

resource "azurerm_availability_set" "hypervisor" {
  name                         = local.hypervisor_vm
  location                     = azurerm_resource_group.vnet.location
  resource_group_name          = azurerm_resource_group.vnet.name
  platform_fault_domain_count  = 3
  platform_update_domain_count = 2
  managed                      = true
}

resource "azurerm_public_ip" "hypervisor" {
  name                = "${local.hypervisor_vm}-primary"
  resource_group_name = azurerm_resource_group.vnet.name
  location            = azurerm_resource_group.vnet.location
  sku                 = "Basic"
  allocation_method   = "Dynamic"
  domain_name_label   = "${local.hypervisor_vm}-primary"
}

resource "azurerm_public_ip" "nested" {
  name                = "${local.hypervisor_vm}-nested"
  resource_group_name = azurerm_resource_group.vnet.name
  location            = azurerm_resource_group.vnet.location
  sku                 = "Basic"
  allocation_method   = "Dynamic"
  domain_name_label   = "${local.hypervisor_vm}-nested"
}

resource "azurerm_network_interface" "hypervisor" {
  name                = local.hypervisor_vm
  location            = azurerm_resource_group.vnet.location
  resource_group_name = azurerm_resource_group.vnet.name

  ip_configuration {
    name                          = "primary"
    subnet_id                     = module.network.vnet_subnets[0]
    private_ip_address_allocation = "Dynamic"
    public_ip_address_id          = azurerm_public_ip.hypervisor.id
    primary                       = true
  }

  ip_configuration {
    name                          = "nested"
    subnet_id                     = module.network.vnet_subnets[0]
    private_ip_address_allocation = "Dynamic"
    public_ip_address_id          = azurerm_public_ip.nested.id

  }
}

resource "azurerm_network_interface_security_group_association" "hypervisor" {
  network_interface_id      = azurerm_network_interface.hypervisor.id
  network_security_group_id = azurerm_network_security_group.hypervisor_nics.id
}

resource "azurerm_linux_virtual_machine" "hypervisor" {
  name                = local.hypervisor_vm
  location            = azurerm_resource_group.vnet.location
  resource_group_name = azurerm_resource_group.vnet.name
  size                = var.hypervisor_vm_size
  admin_username      = "azureuser"
  computer_name       = local.hypervisor_vm
  availability_set_id = azurerm_availability_set.hypervisor.id
  network_interface_ids = [
    azurerm_network_interface.hypervisor.id,
  ]

  admin_ssh_key {
    username   = "azureuser"
    public_key = tls_private_key.hypervisor.public_key_openssh
  }

  os_disk {
    caching              = "ReadWrite"
    storage_account_type = "StandardSSD_LRS"
  }

  #Source image is hardcoded b/c I said so
  source_image_reference {
    publisher = "Canonical"
    offer     = "UbuntuServer"
    sku       = "18.04-LTS"
    version   = "latest"
  }

  custom_data = filebase64("${path.module}/setup.tpl")
}

resource "azurerm_managed_disk" "hypervisor" {
  name                 = "${local.hypervisor_vm}-vms"
  location             = azurerm_resource_group.vnet.location
  resource_group_name  = azurerm_resource_group.vnet.name
  storage_account_type = var.data_disk_storage_class
  create_option        = "Empty"
  disk_size_gb         = var.data_disk_size
}

resource "azurerm_virtual_machine_data_disk_attachment" "hypervisor" {
  managed_disk_id    = azurerm_managed_disk.hypervisor.id
  virtual_machine_id = azurerm_linux_virtual_machine.hypervisor.id
  lun                = "3"
  caching            = "ReadWrite"
}

# ── vnet.tf ──────────────────────────────────────────
resource "azurerm_resource_group" "vnet" {
  name     = local.name
  location = var.region
}

# Create a vnet with a single subnet for the Azure VM
module "network" {
  source              = "Azure/network/azurerm"
  version             = "~> 3.0"
  resource_group_name = azurerm_resource_group.vnet.name
  vnet_name           = local.name
  address_space       = "10.0.0.0/16"
  subnet_prefixes     = ["10.0.0.0/24"]
  subnet_names        = ["hypervisors"]

  depends_on = [azurerm_resource_group.vnet]
}

# Create a network security group for the VM allowing SSH
resource "azurerm_network_security_group" "hypervisor_nics" {
  name                = local.hypervisor_vm
  location            = azurerm_resource_group.vnet.location
  resource_group_name = azurerm_resource_group.vnet.name
}

resource "azurerm_network_security_rule" "hypervisor_nic_ssh" {
  name                        = "allow_ssh"
  priority                    = 100
  direction                   = "Inbound"
  access                      = "Allow"
  protocol                    = "Tcp"
  source_port_range           = "*"
  destination_port_range      = "22"
  source_address_prefix       = "*"
  destination_address_prefix  = "*"
  resource_group_name         = azurerm_resource_group.vnet.name
  network_security_group_name = azurerm_network_security_group.hypervisor_nics.name
}

# ── main.tf ──────────────────────────────────────────
# Random id for naming
resource "random_id" "id" {
  byte_length = 4
  prefix      = var.prefix
}

# Create a Google project for Compute Engine
resource "google_project" "project" {
  name            = random_id.id.hex
  project_id      = random_id.id.hex
  billing_account = var.billing_account
  org_id          = var.org_id
}

# Enable the necessary services on the project for deployments
resource "google_project_service" "service" {
  for_each = toset([
    "compute.googleapis.com",
    "appengine.googleapis.com",
    "appengineflex.googleapis.com",
    "cloudbuild.googleapis.com",
    "secretmanager.googleapis.com"
  ])

  service = each.key

  project            = google_project.project.project_id
  disable_on_destroy = false
}

# ── variables.tf ──────────────────────────────────────────
variable "billing_account" {
  type        = string
  description = "Billing account to associate with the project being created."
}

variable "org_id" {
  type        = string
  description = "Organization ID to associate with the project being created"
}
variable "region" {
  type        = string
  description = "Default region to use for the project"
  default     = "us-central1"
}

variable "prefix" {
  type        = string
  description = "Prefix for naming the project and other resources"
  default     = "taco"
}

# ── output.tf ──────────────────────────────────────────
# Provide the project information for another user
output "project_id" {
  value = google_project.project.project_id
}

# ── terraform.tf ──────────────────────────────────────────
terraform {
  required_providers {
    google = {
      source  = "hashicorp/google"
      version = "~>3.0"
    }
  }
}

provider "google" {
  region = var.region
}

# ── main.tf ──────────────────────────────────────────
/**
