output "mig-instance-group" {
  description = "The instance group url of the created MIG"
  value       = module.mig.instance_group
}

output "mig-name" {
  description = "The name of the MIG"
  value       = local.instance_name
}

output "mig-instance-template" {
  description = "The name of the MIG Instance Template"
  value       = module.mig_template.name
}

output "network_name" {
  description = "Name of VPC"
  value       = local.network_name
}

output "subnet_name" {
  description = "Name of VPC"
  value       = local.subnet_name
}

output "gh_secret_id" {
  description = "Secret Manager ID and version of the github secrets (token, repo_name,repo_owner)"
  value       = google_secret_manager_secret_version.gh-secret-version.name
}

# ── variables.tf ──────────────────────────────────────────
variable "region" {
  type        = string
  description = "Region in Azure"
  default     = "eastus"
}

variable "naming_prefix" {
  type    = string
  default = "taco"
}

# ── locals.tf ──────────────────────────────────────────
resource "random_id" "seed" {
  byte_length = 4
}

locals {
  prefix = "${var.naming_prefix}-${random_id.seed.hex}"
}

# ── terraform.tf ──────────────────────────────────────────
terraform {
  required_providers {
    azurerm = {
      source  = "hashicorp/azurerm"
      version = "~> 2.0"

    }
  }
}

provider "azurerm" {
  features {}
}

# ── vnet.tf ──────────────────────────────────────────
locals {
  vnet_info = {
    name    = "${local.prefix}-vnet"
    address = "10.0.0.0/16"
  }
  subnets = [
    {
      name    = "app"
      address = "10.0.0.0/24"
    },
    {
      name    = "web"
      address = "10.0.1.0/24"
    },
    {
      name    = "db"
      address = "10.0.2.0/24"
    }
  ]
}

resource "azurerm_resource_group" "vnet" {
  name     = local.prefix
  location = var.region
}

module "network" {
  source              = "Azure/network/azurerm"
  version             = "~> 3.0"
  resource_group_name = azurerm_resource_group.vnet.name
  vnet_name           = local.vnet_info.name
  address_space       = local.vnet_info.address
  subnet_prefixes     = local.subnets.*.address
  subnet_names        = local.subnets.*.name

  depends_on = [azurerm_resource_group.vnet]
}

locals {
  shell = ["crunchy", "soft"]
  tags = {
    number = 42
    item   = "towel"
    planet = "Earth"
    poetry = "Vogon"
  }
  meaning_of_life = "What is 6 x 7? ${local.tags["number"]}"
}

