  display_name          = "${module.oidc_sp.service_principal.display_name}-pr"
  description           = "GitHub OIDC for ${var.repository_name} PRs."
  audiences             = ["api://AzureADTokenExchange"]
  issuer                = "https://token.actions.githubusercontent.com"
