# ── main.tf ──────────────────────────────────────────
provider "azurerm" {
  features {}
}

variable "region" {
  type        = string
  default     = "eastus"
  description = "Azure region to deploy resources."
}

variable "resource_group_name" {
  type        = string
  description = "Name of the resource group in which to create resources."
}

variable "vnet_address_space" {
  type        = string
  description = "Address space for the virtual network."
  default     = "10.0.0.0/16"
}

variable "app_config_store_id" {
  type        = string
  description = "ID of the App Configuration store."
}

variable "environment_tag" {
  type        = string
  description = "Tag to use for Environment"
}

data "azurerm_resource_group" "main" {
  name = var.resource_group_name

  lifecycle {
    postcondition {
      condition     = length(self.tags) > 0 && contains(keys(self.tags), "Environment")
      error_message = "The resource group ${var.resource_group_name} does not have an Environment tag."
    }

    postcondition {
      condition     = self.tags["Environment"] == var.environment_tag
      error_message = "The resource group ${var.resource_group_name} does not have the correct Environment tag."
    }
  }
}

data "azurerm_app_configuration_key" "cidr_list" {
  configuration_store_id = var.app_config_store_id
  key                    = "cidr_lists"
  label                  = var.region
}

resource "azurerm_virtual_network" "main" {
  name                = "taconet"
  location            = var.region
  resource_group_name = data.azurerm_resource_group.main.name
  address_space       = [var.vnet_address_space]

  lifecycle {
    precondition {
      condition     = var.region == data.azurerm_resource_group.main.location
      error_message = "The resource group ${var.resource_group_name} is not in the region ${var.region}"
    }

    precondition {
      condition     = contains(split(",", data.azurerm_app_configuration_key.cidr_list.value), var.vnet_address_space)
      error_message = "The address space ${var.vnet_address_space} is not in the list of allowed address spaces"
    }
  }

  tags = {
    Environment = var.environment_tag
  }
}

# ── terraform.tf ──────────────────────────────────────────
terraform {
  required_version = ">= 1.2.0"
  required_providers {
    azurerm = {
      source  = "hashicorp/azurerm"
      version = "~>3.0"
    }
  }
}

# ── main.tf ──────────────────────────────────────────
resource "azurerm_virtual_network" "main" {
  resource_group_name = var.resource_group_name
  location            = var.azure_region
  name                = var.vnet_name

  address_space = var.address_space
}

resource "azurerm_subnet" "main" {
  for_each             = var.subnets
  resource_group_name  = azurerm_virtual_network.main.resource_group_name
  name                 = each.key
  virtual_network_name = azurerm_virtual_network.main.name

  address_prefixes = [each.value]
}

# ── variables.tf ──────────────────────────────────────────
variable "azure_region" {
  type        = string
  description = "Region of Azure to use for resources."
}

variable "resource_group_name" {
  type        = string
  description = "Name of resource group to use."
}

variable "vnet_name" {
  type        = string
  description = "Name of virtual network to create."
}

variable "address_space" {
  type        = list(string)
  description = "List of address spaces to use with virtual network."
}

variable "subnets" {
  type        = map(string)
  description = "Name of subnet and address prefix"
}

# ── outputs.tf ──────────────────────────────────────────
output "virtual_network_name" {
  value = azurerm_virtual_network.main.name
}

output "virtual_network_id" {
  value = azurerm_virtual_network.main.id
}

output "subnet_ids" {
  value = [for subnet in azurerm_subnet.main : subnet.id]
}

# ── main.tf ──────────────────────────────────────────
# Deploy and Azure Virtual Machine running Ubuntu 22.04
# Include a Public IP address and DNS name

provider "azurerm" {
  features {}
}

resource "azurerm_resource_group" "example" {
  name     = "check-block-example"
  location = "West US"
}

module "main_network" {
  source  = "Azure/vnet/azurerm"
  version = "4.1.0"

  resource_group_name = azurerm_resource_group.example.name
  vnet_location       = azurerm_resource_group.example.location
  use_for_each        = true
  vnet_name           = "check-network"
  address_space       = ["10.42.0.0/16"]
  subnet_names        = ["web"]
  subnet_prefixes     = ["10.42.0.0/24"]

}

resource "tls_private_key" "ssh" {
  algorithm = "RSA"
  rsa_bits  = "4096"
}

resource "azurerm_public_ip" "pip" {
  allocation_method   = "Dynamic"
  location            = azurerm_resource_group.example.location
  name                = "check-pip"
  resource_group_name = azurerm_resource_group.example.name
}

module "ubuntu_server" {
  source  = "Azure/virtual-machine/azurerm"
  version = "1.0.0"

  resource_group_name = azurerm_resource_group.example.name
  size                = "Standard_D2s_v4"
  subnet_id           = module.main_network.vnet_subnets_name_id["web"]
  image_os            = "linux"
  os_simple           = "UbuntuServer"
  os_disk = {
    caching              = "ReadWrite"
    storage_account_type = "StandardSSD_LRS"
  }
  location = azurerm_resource_group.example.location
  name     = "check-vm"

  new_network_interface = {
    ip_forwarding_enabled = false
    ip_configurations = [
      {
        public_ip_address_id = azurerm_public_ip.pip.id
        primary              = true
      }
    ]
  }

  admin_username = "azureuser"
  admin_ssh_keys = [
    {
      public_key = tls_private_key.ssh.public_key_openssh
    }
  ]

  custom_data = base64encode(templatefile("${path.module}/userdata.tpl", {}))

}

resource "azurerm_network_security_group" "allow_web" {
  resource_group_name = azurerm_resource_group.example.name
  location            = azurerm_resource_group.example.location
  name                = "check-example"
}

resource "azurerm_network_security_rule" "http" {
  name                        = "allow-http"
  priority                    = 100
  direction                   = "Inbound"
  access                      = "Allow"
  protocol                    = "Tcp"
  source_port_range           = "*"
  destination_port_range      = "80"
  source_address_prefix       = "*"
  destination_address_prefix  = "*"
  resource_group_name         = azurerm_resource_group.example.name
  network_security_group_name = azurerm_network_security_group.allow_web.name
}

resource "azurerm_network_interface_security_group_association" "allow_web" {
  network_interface_id      = module.ubuntu_server.network_interface_id
  network_security_group_id = azurerm_network_security_group.allow_web.id
}

data "azurerm_public_ip" "pip" {
  name                = azurerm_public_ip.pip.name
  resource_group_name = azurerm_resource_group.example.name

  depends_on = [module.ubuntu_server]
}

# ── outputs.tf ──────────────────────────────────────────
output "linux_public_ip" {
  value = data.azurerm_public_ip.pip.ip_address
}

# ── checks.tf ──────────────────────────────────────────
locals {
  status_code = 200
}

check "website_working" {
  data "http" "web_page" {
    url = "http://${data.azurerm_public_ip.pip.ip_address}"
  }

  assert {
    condition     = data.http.web_page.status_code == local.status_code
    error_message = "${data.http.web_page.url} status is not ${local.status_code}"
  }
}

locals {
  allowed_ports = ["80", "443"]
}

check "allowed_ports_only" {

  data "azurerm_network_security_group" "nsg" {
    name                = azurerm_network_security_group.allow_web.name
    resource_group_name = azurerm_resource_group.example.name
  }

  assert {
    condition     = setunion([for rule in data.azurerm_network_security_group.nsg.security_rule : rule.destination_port_range if rule.direction == "Inbound" && rule.access == "Allow"], local.allowed_ports) == toset(local.allowed_ports)
    error_message = "${data.azurerm_network_security_group.nsg.name} includes port rules that are not in the list: ${join(",", local.allowed_ports)}."
  }
}

check "server_on" {
  data "azurerm_virtual_machine" "web" {
    name                = module.ubuntu_server.vm_name
    resource_group_name = azurerm_resource_group.example.name
  }

  assert {
    condition     = data.azurerm_virtual_machine.web.power_state == "running"
    error_message = "${data.azurerm_virtual_machine.web.name} is not running."
  }
}

data "azurerm_virtual_machine" "web2" {
  name                = module.ubuntu_server.vm_name
  resource_group_name = azurerm_resource_group.example.name
}

# ── terraform.tf ──────────────────────────────────────────
terraform {
  required_version = ">=1.5"

  required_providers {
    azurerm = {
      source  = "hashicorp/azurerm"
      version = "~>3.0"
    }
  }
}

# ── variables.tf ──────────────────────────────────────────
variable "az_identity_name" {
  type        = string
  description = "(Required) Name of application and service principal."
}

variable "az_owner_id" {
  type        = string
  description = "(Optional) Object ID of owner to be assigned to service principal. Assigned to current user if not set."
  default     = null
}

variable "az_subscription_id" {
  type        = string
  description = "(Optional) Subscription ID service principal with received Contributor permissions on. Assigned to current subscription if not set."
  default     = null
}

variable "az_alias" {
  type        = string
  description = "(Optional) Alias for aliased identity. Defaults to security."
  default     = "security"
}

variable "tfc_hostname" {
  type        = string
  description = "(Optional) Hostname of Terraform Cloud instance. Defaults to app.terraform.io."
  default     = "app.terraform.io"
}

variable "tfc_organization_name" {
  type        = string
  description = "(Required) Name of the Terraform Cloud organization."
}

variable "tfc_project_name" {
  type        = string
  description = "(Required) Name of the Terraform Cloud project."
}

variable "tfc_workspace_name" {
  type        = string
  description = "(Required) Name of the Terraform Cloud workspace."
}

# ── azure.tf ──────────────────────────────────────────
# Providers
provider "azurerm" {
  features {

  }
}

provider "azuread" {

}

# Create the necessary resources for the Dynamic Identity
# Create two applications
resource "azuread_application" "default" {
  display_name = "${var.az_identity_name}-default"
}

resource "azuread_application" "security" {
  display_name = "${var.az_identity_name}-security"
}

# Create a federated identity credential for plan and apply

resource "azuread_application_federated_identity_credential" "default" {
  for_each              = toset(["plan", "apply"])
  application_object_id = azuread_application.default.object_id
  display_name          = "${azuread_application.default.display_name}-${each.key}"
  description           = "Default Terraform Cloud credential to run ${each.key} phase on ${var.tfc_organization_name}/${var.tfc_project_name}/${var.tfc_workspace_name}."
  audiences             = ["api://AzureADTokenExchange"]
  issuer                = "https://${var.tfc_hostname}"
  subject               = "organization:${var.tfc_organization_name}:project:${var.tfc_project_name}:workspace:${var.tfc_workspace_name}:run_phase:${each.key}"
}

resource "azuread_application_federated_identity_credential" "security" {
  for_each              = toset(["plan", "apply"])
  application_object_id = azuread_application.security.object_id
  display_name          = "${azuread_application.security.display_name}-${each.key}"
  description           = "Security Terraform Cloud credential to run ${each.key} phase on ${var.tfc_organization_name}/${var.tfc_project_name}/${var.tfc_workspace_name}."
  audiences             = ["api://AzureADTokenExchange"]
  issuer                = "https://${var.tfc_hostname}"
  subject               = "organization:${var.tfc_organization_name}:project:${var.tfc_project_name}:workspace:${var.tfc_workspace_name}:run_phase:${each.key}"
}

# Create a service principal
data "azuread_client_config" "current" {}

locals {
  owner_id = var.az_owner_id != null ? var.az_owner_id : data.azuread_client_config.current.object_id
}

resource "azuread_service_principal" "default" {
  application_id = azuread_application.default.application_id
  owners         = [local.owner_id]
}

resource "azuread_service_principal" "security" {
  application_id = azuread_application.security.application_id
  owners         = [local.owner_id]
}

# Grant the service principal Contributor permissions on the subscription
data "azurerm_subscription" "current" {}

locals {
  subscription_id = var.az_subscription_id != null ? var.az_subscription_id : data.azurerm_subscription.current.id
}

resource "azurerm_role_assignment" "default" {
  scope                = local.subscription_id
  role_definition_name = "Contributor"
  principal_id         = azuread_service_principal.default.object_id
}

resource "azurerm_role_assignment" "security" {
  scope                = local.subscription_id
  role_definition_name = "Contributor"
  principal_id         = azuread_service_principal.security.object_id
}

