variable "naming_prefix" {
  type    = string
  default = "tacos"
}

locals {
  resource_group_name  = "${var.naming_prefix}${random_integer.sa_num.result}"
  storage_account_name = "${lower(var.naming_prefix)}${random_integer.sa_num.result}"
}

##################################################################################
# PROVIDERS
##################################################################################

provider "azurerm" {
  features {}
  storage_use_azuread = true
}

##################################################################################
# RESOURCES
##################################################################################
resource "random_integer" "sa_num" {
  min = 10000
  max = 99999
}

resource "azurerm_resource_group" "setup" {
  name     = local.resource_group_name
  location = var.location
}

resource "azurerm_storage_account" "sa" {
  name                     = local.storage_account_name
  resource_group_name      = azurerm_resource_group.setup.name
  location                 = var.location
  account_tier             = "Standard"
  account_replication_type = "LRS"

}

resource "azurerm_storage_container" "ct" {
  name               = "terraform-state"
  storage_account_id = azurerm_storage_account.sa.id

}

##################################################################################
# OUTPUT
##################################################################################

output "storage_account_name" {
  value = azurerm_storage_account.sa.name
}

output "container_name" {
  value = azurerm_storage_container.ct.name

}

output "resource_group_name" {
  value = azurerm_resource_group.setup.name
}

# ── main.tf ──────────────────────────────────────────
resource "azurerm_resource_group" "backend" {
  name     = "${var.prefix}-be-rg"
  location = var.location
}

resource "azurerm_container_group" "backend" {
  name                = "${var.prefix}-be-cg"
  location            = azurerm_resource_group.backend.location
  resource_group_name = azurerm_resource_group.backend.name
  os_type             = "Linux"
  ip_address_type     = "Private"
  subnet_ids          = [var.subnet_id]

  container {
    name   = "backend-container"
    image  = "mcr.microsoft.com/azuredocs/aci-helloworld:latest"
    cpu    = "0.5"
    memory = "1.5"

    ports {
      port     = 443
      protocol = "TCP"
    }
  }

  tags = var.common_tags
}

# ── variables.tf ──────────────────────────────────────────
variable "common_tags" {
  description = "Common tags to be applied to resources"
  type        = map(string)
}

variable "location" {
  description = "The location where resources will be created"
  type        = string
}

variable "prefix" {
  description = "Prefix for naming resources"
  type        = string
}

variable "subnet_id" {
  description = "The subnet ID to use for the frontend"
  type        = string
}

# ── outputs.tf ──────────────────────────────────────────
output "backend_public_dns" {
  value = azurerm_container_group.backend.fqdn

}

output "backend_ip_address" {
  value = azurerm_container_group.backend.ip_address

}

# ── main.tf ──────────────────────────────────────────
resource "azurerm_resource_group" "postgres" {
  name     = "${var.prefix}-postgres-rg"
  location = var.location

  tags = var.common_tags
}

resource "azurerm_postgresql_server" "postgres" {
  name                = "${var.prefix}-postgres-server"
  location            = azurerm_resource_group.postgres.location
  resource_group_name = azurerm_resource_group.postgres.name

  sku_name = "GP_Gen5_2"

  storage_mb            = 5120
  backup_retention_days = 7

  administrator_login          = "psqladmin"
  administrator_login_password = "H@Sh1CoR3!"
  version                      = "9.5"
  ssl_enforcement_enabled      = true
}

resource "azurerm_postgresql_virtual_network_rule" "postgres" {
  name                                 = "postgresql-vnet-rule"
  resource_group_name                  = azurerm_resource_group.postgres.name
  server_name                          = azurerm_postgresql_server.postgres.name
  subnet_id                            = var.subnet_id
  ignore_missing_vnet_service_endpoint = true
}

# ── variables.tf ──────────────────────────────────────────
variable "common_tags" {
  description = "Common tags to be applied to resources"
  type        = map(string)
}

variable "location" {
  description = "The location where resources will be created"
  type        = string
}

variable "prefix" {
  description = "Prefix for resource names"
  type        = string
}

variable "subnet_id" {
  description = "The ID of the subnet"
  type        = string
}

# ── outputs.tf ──────────────────────────────────────────
output "postgres_fqdn" {
  value = azurerm_postgresql_server.postgres.fqdn

}

# ── main.tf ──────────────────────────────────────────
resource "azurerm_resource_group" "frontend" {
  name     = "${var.prefix}-fe-rg"
  location = var.location
}

resource "azurerm_container_group" "frontend" {
  name                = "${var.prefix}-fe-cg"
  location            = azurerm_resource_group.frontend.location
  resource_group_name = azurerm_resource_group.frontend.name
  os_type             = "Linux"
  ip_address_type     = "Public"
  dns_name_label      = "${var.prefix}-frontend-dns"

  container {
    name   = "frontend-container"
    image  = "mcr.microsoft.com/azuredocs/aci-helloworld:latest"
    cpu    = "0.5"
    memory = "1.5"

    ports {
      port     = 443
      protocol = "TCP"
    }
  }

  tags = var.common_tags
}

# ── variables.tf ──────────────────────────────────────────
variable "common_tags" {
  description = "Common tags to be applied to resources"
  type        = map(string)
}

variable "location" {
  description = "The location where resources will be created"
  type        = string
}

variable "prefix" {
  description = "Prefix for naming resources"
  type        = string
}

# ── outputs.tf ──────────────────────────────────────────
output "frontend_public_dns" {
  value = azurerm_container_group.frontend.fqdn

}

# ── main.tf ──────────────────────────────────────────
resource "azurerm_resource_group" "network" {
  name     = "${var.prefix}-network-rg"
  location = var.location
  tags     = var.common_tags
}

resource "azurerm_virtual_network" "network" {
  name                = "${var.prefix}-network"
  resource_group_name = azurerm_resource_group.network.name
  location            = azurerm_resource_group.network.location
  address_space       = [var.cidr_block]
  tags                = var.common_tags
}

resource "azurerm_subnet" "subnets" {
  for_each = var.subnets

  name                 = each.key
  resource_group_name  = azurerm_resource_group.network.name
  virtual_network_name = azurerm_virtual_network.network.name
  address_prefixes     = [each.value.address_prefixes]
  service_endpoints = each.value.service_endpoints

  dynamic "delegation" {
    for_each = each.value.delegation_name != null ? [each.value] : []

    content {
    name = delegation.value.delegation_name
    service_delegation {
      name    = delegation.value.service_delegation_name
      actions = delegation.value.service_delegation_actions
    }
    }
  }
}

# ── variables.tf ──────────────────────────────────────────
variable "location" {
  description = "The location to use for the network"
  type        = string

}

variable "prefix" {
  description = "The prefix to use for the network"
  type        = string

}

variable "common_tags" {
  description = "The common tags to use for the network"
  type        = map(string)

}

variable "cidr_block" {
  description = "The CIDR block to use for the network"
  type        = string

}

variable "subnets" {
  type = map(object({
    address_prefixes           = string
    delegation_name            = optional(string)
    service_delegation_name    = optional(string)
    service_delegation_actions = optional(list(string))
    service_endpoints          = optional(list(string))
  }))
  description = "Map of subnets to create"
}

# ── outputs.tf ──────────────────────────────────────────
output "vnet_id" {
  description = "ID of the virtual network"
  value       = azurerm_virtual_network.network.id
}

output "vnet_name" {
  description = "Name of the virtual network"
  value       = azurerm_virtual_network.network.name
}

output "subnet_id_map" {
  description = "Map of subnet IDs"
  value       = { for k, v in azurerm_subnet.subnets : k => v.id }

}

# ── main.tf ──────────────────────────────────────────
provider "azurerm" {
  features {}

}

ephemeral "azurerm_key_vault_secret" "k8s" {
  for_each = toset(["client-certificate", "client-key", "cluster-ca-certificate"])

  name         = each.key
  key_vault_id = var.key_vault_id
}

provider "kubernetes" {
  host = "https://${var.aks_cluster_host}"

  client_certificate     = base64decode(ephemeral.azurerm_key_vault_secret.k8s["client-certificate"].value)
  client_key             = base64decode(ephemeral.azurerm_key_vault_secret.k8s["client-key"].value)
  cluster_ca_certificate = base64decode(ephemeral.azurerm_key_vault_secret.k8s["cluster-ca-certificate"].value)
}

resource "kubernetes_namespace" "example" {
  metadata {
    annotations = {
      name = "example-annotation"
    }

    labels = {
      mylabel = "label-value"
    }

    name = "terraform-example-namespace"
  }
}

# ── variables.tf ──────────────────────────────────────────
variable "aks_cluster_host" {
  description = "The Kubernetes cluster host."
  type        = string
}

variable "key_vault_id" {
  description = "The ID of the Azure Key Vault."
  type        = string

}

# ── terraform.tf ──────────────────────────────────────────
terraform {
  required_version = ">= 1.10"

  required_providers {
    azurerm = {
      source  = "hashicorp/azurerm"
      version = "~>4.11"
    }

    kubernetes = {
      source  = "hashicorp/kubernetes"
      version = "~>2.0"
    }
  }
}

# ── main.tf ──────────────────────────────────────────
provider "azurerm" {
  features {}
}

resource "random_integer" "naming" {
  min = 10000
  max = 99999
}

locals {
  name = "ephemeral-aks-${random_integer.naming.result}"
}

resource "azurerm_resource_group" "aks" {
  name     = local.name
  location = "East US"
}

data "azurerm_client_config" "example" {

}

resource "azurerm_key_vault" "example" {
  name                = local.name
  location            = azurerm_resource_group.aks.location
  resource_group_name = azurerm_resource_group.aks.name
  sku_name            = "standard"
  tenant_id           = data.azurerm_client_config.example.tenant_id

  access_policy {
    tenant_id = data.azurerm_client_config.example.tenant_id
    object_id = data.azurerm_client_config.example.object_id

    secret_permissions = [
      "Backup",
      "Delete",
      "Get",
      "List",
      "Purge",
      "Recover",
      "Restore",
      "Set",
    ]

    certificate_permissions = [
      "Create",
      "Delete",
      "DeleteIssuers",
      "Get",
      "GetIssuers",
      "Import",
      "List",
      "ListIssuers",
      "ManageContacts",
      "ManageIssuers",
      "SetIssuers",
      "Update",
    ]
  }
}

module "aks" {
  source                            = "Azure/aks/azurerm"
  resource_group_name               = azurerm_resource_group.aks.name
  location                          = azurerm_resource_group.aks.location
  prefix                            = "ephaks"
  agents_count                      = 1
  role_based_access_control_enabled = true
  rbac_aad                          = false
  rbac_aad_azure_rbac_enabled       = false
}

resource "azurerm_key_vault_secret" "kube_config" {
  name         = "kubeconfig"
  value        = module.aks.kube_config_raw
  key_vault_id = azurerm_key_vault.example.id
}

resource "azurerm_key_vault_secret" "client_certificate" {
  name         = "client-certificate"
  value        = module.aks.client_certificate
  key_vault_id = azurerm_key_vault.example.id
}

resource "azurerm_key_vault_secret" "client_key" {
  name         = "client-key"
  value        = module.aks.client_key
  key_vault_id = azurerm_key_vault.example.id
}

resource "azurerm_key_vault_secret" "cluster_ca_certificate" {
  name         = "cluster-ca-certificate"
  value        = module.aks.cluster_ca_certificate
  key_vault_id = azurerm_key_vault.example.id
}

output "key_vault_id" {
  value       = azurerm_key_vault.example.id
  description = "The ID of the Azure Key Vault."
}

output "aks_cluster_host" {
  value       = module.aks.cluster_fqdn
  description = "The Kubernetes cluster host."
}

