# ── main.tf ──────────────────────────────────────────
provider "vault" {
  address = "http://localhost:8200"
  token   = "root"
}

resource "vault_mount" "kvv2" {
  path        = var.secret_mount_path
  type        = "kv"
  options     = { version = "2" }
  description = "KV Version 2 secret engine mount"

  depends_on = [ docker_container.vault ]
}

# Create a KV v2 secret backend
resource "vault_kv_secret_backend_v2" "main" {
  mount        = vault_mount.kvv2.path
  cas_required = false
  max_versions = 10
}

# Create a secret with burrito recipe
resource "vault_kv_secret_v2" "burrito_recipe" {
  mount                = vault_kv_secret_backend_v2.main.mount
  name                 = "burrito-recipe"
  data_json_wo         = jsonencode(var.burrito_recipe)
  data_json_wo_version = var.burrito_recipe_version
}

# ── variables.tf ──────────────────────────────────────────
variable "burrito_recipe" {
  description = "Secret information for the burrito recipe"
  type = object({
    ingredients  = string
    instructions = string
    chef_notes   = optional(string, "")
  })

  sensitive = true
  ephemeral = true
}

variable "burrito_recipe_version" {
  description = "Version of the burrito recipe secret"
  type        = number

  validation {
    condition     = var.burrito_recipe_version > 0 && var.burrito_recipe_version == floor(var.burrito_recipe_version)
    error_message = "The burrito_recipe_version must be a non-negative integer."
  }

}

variable "secret_mount_path" {
  description = "Mount path for the Vault KV v2 secret engine"
  type        = string
  default     = "secret"
}

# ── outputs.tf ──────────────────────────────────────────

# ── main.vault.tf ──────────────────────────────────────────
provider "docker" {}

resource "docker_image" "vault" {
  name         = "hashicorp/vault:1.20"
  keep_locally = true
}

resource "docker_container" "vault" {
  name  = "vault"
  image = docker_image.vault.name
  wait  = true

  ports {
    internal = 8200
    external = 8200
  }

  env = [
    "VAULT_DEV_ROOT_TOKEN_ID=root",
    "VAULT_DEV_LISTEN_ADDRESS=0.0.0.0:8200"
  ]

  command = ["server", "-dev"]

  healthcheck {
    test     = ["CMD", "vault", "status", "-address=http://localhost:8200"]
    interval = "10s"
    timeout  = "5s"
    retries  = 3
  }
}

# ── terraform.tf ──────────────────────────────────────────
terraform {
  required_version = ">= 1.11.0"
  required_providers {
    vault = {
      source  = "hashicorp/vault"
      version = "~> 5.0"
    }

    docker = {
      source  = "kreuzwerker/docker"
      version = "~> 3.0"
    }
  }
}

# ── main.tf ──────────────────────────────────────────
provider "vault" {
  address = var.vault_address
  token   = var.vault_token
}

provider "azurerm" {
  features {}
}

resource "random_integer" "example" {
  min = 10000
  max = 99999

}

locals {
  name = "vault-ephemeral-${random_integer.example.result}"
}

resource "azurerm_resource_group" "example" {
  name     = local.name
  location = "East US"
}

data "azurerm_client_config" "example" {

}

resource "azurerm_key_vault" "example" {
  name                = local.name
  location            = azurerm_resource_group.example.location
  resource_group_name = azurerm_resource_group.example.name
  tenant_id           = data.azurerm_client_config.example.tenant_id
  sku_name            = "standard"

  access_policy {
    tenant_id = data.azurerm_client_config.example.tenant_id
    object_id = data.azurerm_client_config.example.object_id

    key_permissions = [
      "Get", "List", "Create", "Delete", "Update", "Import", "Backup", "Restore", "Recover", "Purge"
    ]

    secret_permissions = [
      "Get", "List", "Set", "Delete", "Backup", "Restore", "Recover", "Purge"
    ]

    certificate_permissions = [
      "Get", "List", "Create", "Delete", "Update", "Import", "Backup", "Restore", "Recover", "Purge"
    ]
  }

}

ephemeral "vault_kv_secret_v2" "burrito_recipe" {
  mount = var.secret_mount_path
  name  = var.secret_name
  version = var.secret_version
}

# Write the secret to Azure Key Vault
resource "azurerm_key_vault_secret" "write_only" {
  name             = "burrito-recipe"
  value_wo         = jsonencode(ephemeral.vault_kv_secret_v2.burrito_recipe.data)
  #value_wo = ephemeral.vault_kv_secret_v2.burrito_recipe.data_json
  value_wo_version = var.secret_version
  key_vault_id     = azurerm_key_vault.example.id
}

# ── variables.tf ──────────────────────────────────────────
variable "secret_mount_path" {
  description = "Mount path for the Vault KV v2 secret engine"
  type        = string
}

variable "secret_name" {
  description = "Name of the secret to be created in Vault"
  type        = string
}

variable "secret_version" {
  description = "Version of the secret to be created in Vault"
  type        = number

    validation {
        condition     = var.secret_version > 0 && var.secret_version == floor(var.secret_version)
        error_message = "The secret_version must be a non-negative integer."
    }

}

variable "vault_address" {
  description = "Address of the Vault server"
  type        = string
  default     = "http://localhost:8200"
}

variable "vault_token" {
  description = "Token for authenticating with Vault"
  type        = string
  default     = "root"
  sensitive = true

}

# ── outputs.tf ──────────────────────────────────────────

# ── terraform.tf ──────────────────────────────────────────
terraform {
  required_version = ">= 1.11.0"
  required_providers {
    vault = {
      source  = "hashicorp/vault"
      version = "~> 5.0"
    }
    azurerm = {
      source  = "hashicorp/azurerm"
      version = "~> 4.0"
    }
  }
}

# ── main.tf ──────────────────────────────────────────
provider "azurerm" {
  features {}

}

resource "random_integer" "example" {
  min = 10000
  max = 99999

}

locals {
  name = "${var.prefix}-ephemeral-${random_integer.example.result}"
}

resource "azurerm_resource_group" "example" {
  name     = local.name
  location = "East US"
}

data "azurerm_client_config" "example" {

}

resource "azurerm_key_vault" "example" {
  name                = local.name
  location            = azurerm_resource_group.example.location
  resource_group_name = azurerm_resource_group.example.name
  tenant_id           = data.azurerm_client_config.example.tenant_id
