  for_each = {
    one = 1
    two = 2
    three = 3
    four = 4
  }
  length = each.value + 10
}

variable "super_weird_variable" {
  type        = any
  description = "I don't know what to expect!"
}

locals {
  my_string = "I'm a string!"
  my_long_string = <<EOF
This is a long
string that spans ${length(var.super_weird_variable)} lines.
multiple lines.
EOF

  my_number = 42
  my_boolean = true

  my_list_variable  = ["I'm", "a", "list", "variable!"] # local.my_list_variable[1]

  my_map_variable = { # local.my_map_variable["key1"]
    key1 = "I'm a map variable!"
    key2 = "I'm another map variable!"
    key3 = ["I'm a list inside a map!"]
  }
}

variable "ip_address_prefix" {
  type        = string
  description = "The IP address prefix to use for the network"

  validation {
    condition     = can(regex("^(\\d{1,3}\\.){3}\\d{1,3}/\\d{1,2}$", var.ip_address_prefix))
    error_message = "The IP address prefix must be a valid CIDR block"
  }

}

variable "create_nat_gw" {
  type = bool
  description = "Whether to create a NAT gateway for the network"
}

# ── main.tf ──────────────────────────────────────────
provider "aws" {
  region = "us-west-2"
}

locals {
  layers = flatten([ for l in var.lambdas :
    [ for layer in l.layers : merge({"function_name" = l.function_name},layer) ]
  ])
}
resource "aws_lambda_layer_version" "lambda_layer" {
    for_each = { for layer in local.layers : "${layer.function_name}-${layer.layer_name}" => layer}

    layer_name              = each.value.layer_name
    description             = each.value.description
    compatible_architectures = lookup(each.value, "architectures", null)
    compatible_runtimes     = lookup(each.value, "compatible_runtimes", null)
    #filename                = each.value.filename
    #license_info            = each.value.license_info
    #s3_bucket               = each.value.s3_bucket
    #s3_key                  = each.value.s3_key
    #s3_object_version       = each.value.s3_object_version
    #skip_destroy            = each.value.skip_destroy
    #source_code_hash        = each.value.source_code_hash
  }

resource "aws_lambda_function" "name" {
  for_each = { for lambdas in var.lambdas : lambdas.function_name => lambdas }

  function_name = each.key
  description   = each.value.description
  architectures = each.value.architectures

  ephemeral_storage {
    size  = each.value.ephemeral_storage
  }

  layers = [ for layer in each.value.layers : aws_lambda_layer_version.lambda_layer["${each.key}-${layer.layer_name}"].arn]
  memory_size = each.value.memory_size
  runtime = each.value.runtime
  timeout = each.value.timeout

  role          = var.lambda_role
  filename      = "lambda.zip"
  handler       = "lambda.handler"
  source_code_hash = "0"

}

# ── variables.tf ──────────────────────────────────────────
variable "lambdas" {
  description = "Lambdas"
  type = list(object({
    function_name     = string
    description       = optional(string)
    architectures     = optional(list(string), ["x86_64"]) # Valid values are ["x86_64"] and ["arm64"]. Default is ["x86_64"].
    ephemeral_storage = optional(number, 512)      # The amount of Ephemeral storage(/tmp) to allocate for the Lambda Function in MB. Default is 512 MB.
    layers = optional(list(object({
      layer_name               = string
      description              = optional(string)
      compatible_architectures = optional(list(string))
      compatible_runtimes      = optional(list(string))
      filename                 = optional(string, "lambda.zip")
      license_info             = optional(string)
      s3_bucket                = optional(string)
      s3_key                   = optional(string)
      s3_object_version        = optional(string)
      skip_destroy             = optional(bool, false)
      source_code_hash         = optional(string)
    })))
    memory_size = optional(number, 128)         # The amount of memory, in MB, that is allocated to your Lambda Function. Default is 128 MB.
    runtime     = optional(string, "python3.8") # The runtime environment for the Lambda function you are uploading. Default is "python3.8".
    timeout     = optional(number, 3)           # The amount of time that Lambda allows a function to run before stopping it. The default is 3 seconds. The maximum allowed value is 900 seconds.
  }))
}

variable "lambda_role" {

}

